import { Injectable, inject } from '@angular/core';
import { AuthService } from '../../core/services/auth.service';

@Injectable({
  providedIn: 'root'
})
export class AppConfigurationService {
  private authService = inject(AuthService);
  private dataServicesConfigured = false;

  async initialize(): Promise<void> {
    try {
      // Verificar el usuario actual
      await this.authService.refreshAuth();

      // Si hay usuario autenticado, configurar los servicios de datos
      if (this.authService.currentUser()) {
        await this.configureDataServices();
      }
    } catch (error) {
      console.error('❌ Error configurando la aplicación:', error);
      throw error;
    }
  }

  /**
   * Configura los servicios de datos después de la autenticación
   * En la arquitectura simplificada, esto asegura que el estado inicial se cargue
   */
  async configureDataServices(): Promise<void> {
    if (this.dataServicesConfigured) return;

    try {
      // Los servicios ahora manejan su propia inicialización lazy o directa
      this.dataServicesConfigured = true;
    } catch (error) {
      console.error('❌ Error configurando servicios de datos:', error);
      throw error;
    }
  }

  /**
   * Verifica si los servicios de datos ya están configurados
   */
  areDataServicesConfigured(): boolean {
    return this.dataServicesConfigured;
  }
}

import { Injectable, signal, Signal, inject, Injector, runInInjectionContext, isDevMode } from '@angular/core';
import {
  Auth,
  GoogleAuthProvider,
  signInWithEmailAndPassword,
  signInWithPopup,
  signOut,
  onAuthStateChanged,
  User as FirebaseUser,
  createUserWithEmailAndPassword
} from 'firebase/auth';
import { Firestore, doc, getDoc, onSnapshot as onFirestoreSnapshot, Unsubscribe, setDoc } from 'firebase/firestore';
import { User, Rol } from 'gym-library';
import { AUTH, FIRESTORE } from '../firebase.tokens';

@Injectable({
  providedIn: 'root'
})
export class AuthService {
  private readonly auth = inject(AUTH);
  private readonly firestore = inject(FIRESTORE);

  private readonly _currentUser = signal<User | null>(null);
  private readonly _isAuthenticated = signal<boolean>(false);
  private readonly _isLoading = signal<boolean>(true);
  private readonly _error = signal<string | null>(null);
  private userSnapshotUnsubscribe?: Unsubscribe;

  constructor() {
    this.loadInitialSession();
    this.initializeAuthListener();
  }

  private loadInitialSession() {
    try {
      const savedUser = localStorage.getItem('gym_auth_user');
      if (savedUser) {
        const user = JSON.parse(savedUser) as User;
        this._currentUser.set(user);
        this._isAuthenticated.set(true);
        // Dejamos _isLoading como true para que Firebase termine su proceso real
      }
    } catch (e) {
      console.warn('🛡️ Auth: Error cargando sesión inicial:', e);
    }
  }

  private initializeAuthListener() {
    // Escuchamos cambios de auth de forma directa y sincronizada
    onAuthStateChanged(this.auth, async (firebaseUser) => {
      // Limpiar listener previo si existe
      if (this.userSnapshotUnsubscribe) {
        this.userSnapshotUnsubscribe();
      }

      if (firebaseUser) {
        try {
          // Primero una carga inicial rápida
          const userData = await this.getUserData(firebaseUser);
          this._currentUser.set(userData);
          this._isAuthenticated.set(true);
          this._isLoading.set(false);

          // Suscribirse a cambios en tiempo real del documento del usuario
          const userDocRef = doc(this.firestore, `usuarios/${firebaseUser.uid}`);
          this.userSnapshotUnsubscribe = onFirestoreSnapshot(userDocRef, (snapshot) => {
            if (snapshot.exists()) {
              const data = snapshot.data() as User;
              const updatedUser = { ...data, uid: firebaseUser.uid };
              this._currentUser.set(updatedUser);
              localStorage.setItem('gym_auth_user', JSON.stringify(updatedUser));
            }
          });

        } catch (error) {
          console.error('🛡️ Auth: Error procesando sesión:', error);
          this._isLoading.set(false);
        }
      } else {
        this._currentUser.set(null);
        this._isAuthenticated.set(false);
        this._isLoading.set(false);
        localStorage.removeItem('gym_auth_user');
      }
    });
  }

  /**
   * Signal del usuario actual
   */
  get currentUser(): Signal<User | null> {
    return this._currentUser.asReadonly();
  }

  /**
   * Signal del estado de autenticación
   */
  get isAuthenticated(): Signal<boolean> {
    return this._isAuthenticated.asReadonly();
  }

  /**
   * Signal del estado de carga (fundamental para los guards)
   */
  get isLoading(): Signal<boolean> {
    return this._isLoading.asReadonly();
  }

  get error(): Signal<string | null> {
    return this._error.asReadonly();
  }

  async loginWithEmail(email: string, password: string): Promise<boolean> {
    this._isLoading.set(true);
    this._error.set(null);
    try {
      const cred = await signInWithEmailAndPassword(this.auth, email, password);
      if (cred.user) {
        // Forzamos carga inmediata para que el router.navigate siguiente funcione
        const user = await this.getUserData(cred.user);
        this._currentUser.set(user);
        this._isAuthenticated.set(true);
        this._isLoading.set(false);
        return true;
      }
      this._isLoading.set(false);
      return false;
    } catch (error: any) {
      if (isDevMode()) console.error('Error en login con email:', error);
      this._error.set(this.getErrorMessage(error));
      this._isLoading.set(false);
      return false;
    }
  }

  async loginWithGoogle(): Promise<boolean> {
    this._isLoading.set(true);
    this._error.set(null);
    try {
      const provider = new GoogleAuthProvider();
      const cred = await signInWithPopup(this.auth, provider);
      if (cred.user) {
        // Obtenemos o creamos los datos en Firestore
        const user = await this.getUserData(cred.user, true);
        this._currentUser.set(user);
        this._isAuthenticated.set(true);
        this._isLoading.set(false);
        return true;
      }
      this._isLoading.set(false);
      return false;
    } catch (error: any) {
      if (isDevMode()) console.error('🛡️ Auth: Error en login con Google:', error);
      this._error.set(this.getErrorMessage(error));
      this._isLoading.set(false);
      return false;
    }
  }

  async registerWithEmail(email: string, password: string): Promise<boolean> {
    this._isLoading.set(true);
    this._error.set(null);
    try {
      const userCredential = await createUserWithEmailAndPassword(this.auth, email, password);
      if (userCredential.user) {
        // Forzamos la creación del documento en Firestore inmediatamente
        const newUser = await this.getUserData(userCredential.user, true);
        this._currentUser.set(newUser);
        this._isAuthenticated.set(true);
        this._isLoading.set(false);
        return true;
      }
      this._isLoading.set(false);
      return false;
    } catch (error: any) {
      if (isDevMode()) console.error('🛡️ Auth: Error en registro:', error);
      this._error.set(this.getRegistrationErrorMessage(error));
      this._isLoading.set(false);
      return false;
    }
  }

  async logout(): Promise<void> {

    await signOut(this.auth);
  }

  private async getUserData(firebaseUser: FirebaseUser, createIfMissing = false): Promise<User> {
    const userDocRef = doc(this.firestore, `usuarios/${firebaseUser.uid}`);
    const userSnap = await getDoc(userDocRef);

    let userData: User;
    if (userSnap.exists()) {
      userData = userSnap.data() as User;
      // Si Firestore no tiene foto pero Firebase sí, la usamos
      if (!userData.photoURL && firebaseUser.photoURL) {
        userData.photoURL = firebaseUser.photoURL;
      }
    } else {
      // Si no existe, preparamos un objeto básico
      userData = {
        uid: firebaseUser.uid,
        nombre: firebaseUser.displayName || firebaseUser.email || 'Nuevo Usuario',
        email: firebaseUser.email || '',
        photoURL: firebaseUser.photoURL || null,
        role: Rol.ENTRENADO,
        onboarded: false
      };

      // Si se nos pide crear el documento (en registro o primer login con Google)
      if (createIfMissing) {
        try {
          // Guardamos en Firestore
          await setDoc(userDocRef, userData);
          if (isDevMode()) console.log('🛡️ Auth: Nuevo perfil de usuario creado en Firestore');
        } catch (e) {
          console.error('🛡️ Auth: Error al crear perfil inicial en Firestore:', e);
        }
      }
    }

    return { ...userData, uid: firebaseUser.uid };
  }

  private getErrorMessage(error: any): string {
    const errorCode = error.code || '';
    switch (errorCode) {
      case 'auth/invalid-credential':
      case 'auth/user-not-found':
      case 'auth/wrong-password': return 'Email o contraseña incorrectos';
      case 'auth/too-many-requests': return 'Demasiados intentos. Intenta más tarde';
      case 'auth/popup-closed-by-user': return 'La ventana de Google se cerró antes de completar';
      case 'auth/operation-not-allowed': return 'El inicio de sesión con Google no está habilitado en Firebase';
      case 'auth/unauthorized-domain': return 'Este dominio (localhost) no está autorizado en Firebase';
      default: return `Error al iniciar sesión: ${errorCode || error.message || 'Error desconocido'}`;
    }
  }

  private getRegistrationErrorMessage(error: any): string {
    const errorCode = error.code || '';
    switch (errorCode) {
      case 'auth/email-already-in-use': return 'Este email ya está registrado';
      case 'auth/weak-password': return 'La contraseña debe tener al menos 6 caracteres';
      case 'auth/invalid-email': return 'El email no tiene un formato válido';
      default: return 'Error al crear la cuenta';
    }
  }


  async refreshAuth(): Promise<void> {
    if (this.auth.currentUser) {
      const user = await this.getUserData(this.auth.currentUser);
      this._currentUser.set(user);
      this._isAuthenticated.set(true);
    }
    this._isLoading.set(false);
  }
}

import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
    Firestore,
    collection,
    addDoc,
    doc,
    deleteDoc,
    setDoc,
    onSnapshot,
    query,
    where,
    Timestamp,
    QuerySnapshot,
    DocumentSnapshot,
    updateDoc,
    arrayUnion,
    arrayRemove
} from 'firebase/firestore';
import { Convocatoria, Rol } from 'gym-library';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

@Injectable({ providedIn: 'root' })
export class ConvocatoriaService {
    private readonly firestore = inject(FIRESTORE);
    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'convocatorias';

    private readonly _convocatorias: WritableSignal<Convocatoria[]> = signal<Convocatoria[]>([]);
    private isListenerInitialized = false;

    constructor() { }

    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    /**
     * Inicializa listener.
     * Si se pasa gymId, filtra por gimnasio (recomendado para la sección de entrenados).
     * Mantiene compatibilidad con carga global (social amplio, admin, etc.).
     */
    private initializeListener(gymId?: string): void {
        if (this.isListenerInitialized) return;

        try {
            const col = collection(this.firestore, this.COLLECTION);
            let q = query(col, where('activo', '==', true));

            if (gymId) {
                q = query(col, where('activo', '==', true), where('gimnasioId', '==', gymId));
            }

            onSnapshot(q, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
                    this._convocatorias.set(list);
                });
            });
            this.isListenerInitialized = true;
        } catch (e) {
            console.warn('Error inicializando listener de convocatorias:', e);
        }
    }

    get convocatorias(): Signal<Convocatoria[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return this._convocatorias.asReadonly();
    }

    /**
     * Obtiene convocatorias filtradas por gimnasio (inicializa listener gym-scoped si es necesario).
     * Recomendado para la sección de entrenados.
     */
    getConvocatoriasForGym(gymId: string): Signal<Convocatoria[]> {
        // For now we still share the same backing signal (full or first init wins).
        // In a more advanced version we could have per-gym signals.
        if (!this.isListenerInitialized) {
            this.initializeListener(gymId);
        }
        return this._convocatorias.asReadonly();
    }

    async save(convocatoria: Convocatoria): Promise<void> {
        return this.runInZone(async () => {
            const dataToSave = this.mapToFirestore(convocatoria);
            if (convocatoria.id) {
                const docRef = doc(this.firestore, this.COLLECTION, convocatoria.id);
                await setDoc(docRef, dataToSave, { merge: true });
            } else {
                const col = collection(this.firestore, this.COLLECTION);
                const docRef = await addDoc(col, dataToSave);
                convocatoria.id = docRef.id;
            }
        });
    }

    async delete(id: string): Promise<void> {
        return this.runInZone(async () => {
            const docRef = doc(this.firestore, this.COLLECTION, id);
            await deleteDoc(docRef);
        });
    }

    async toggleInteres(convocatoriaId: string, userId: string, unirse: boolean): Promise<void> {
        return this.runInZone(async () => {
            const docRef = doc(this.firestore, this.COLLECTION, convocatoriaId);
            if (unirse) {
                await updateDoc(docRef, {
                    interesados: arrayUnion(userId)
                });
            } else {
                await updateDoc(docRef, {
                    interesados: arrayRemove(userId)
                });
            }
        });
    }

    private mapFromFirestore(data: any): Convocatoria {
        return {
            id: data.id,
            creadorId: data.creadorId || '',
            creadorNombre: data.creadorNombre || 'Atleta',
            creadorFoto: data.creadorFoto || null,
            gimnasioId: data.gimnasioId || '',
            fechaCreacion: data.fechaCreacion instanceof Timestamp ? data.fechaCreacion.toDate() : (data.fechaCreacion ? new Date(data.fechaCreacion) : new Date()),
            fechaEntrenamiento: data.fechaEntrenamiento instanceof Timestamp ? data.fechaEntrenamiento.toDate() : (data.fechaEntrenamiento ? new Date(data.fechaEntrenamiento) : new Date()),
            horaInicio: data.horaInicio || '00:00',
            horaFin: data.horaFin || '00:00',
            mensaje: data.mensaje || '',
            interesados: data.interesados || [],
            activo: data.activo ?? true,
            creadorRol: data.creadorRol || Rol.ENTRENADO,
            titulo: data.titulo || '',
            esOficial: data.esOficial ?? false,
            esSemanal: data.esSemanal ?? false
        };
    }

    private mapToFirestore(convocatoria: Convocatoria): any {
        const data: any = {
            creadorId: convocatoria.creadorId,
            creadorNombre: convocatoria.creadorNombre,
            gimnasioId: convocatoria.gimnasioId,
            horaInicio: convocatoria.horaInicio,
            horaFin: convocatoria.horaFin,
            interesados: convocatoria.interesados || [],
            activo: convocatoria.activo ?? true
        };

        if (convocatoria.creadorFoto !== undefined) data.creadorFoto = convocatoria.creadorFoto;
        if (convocatoria.mensaje !== undefined) data.mensaje = convocatoria.mensaje;
        if (convocatoria.creadorRol !== undefined) data.creadorRol = convocatoria.creadorRol;
        if (convocatoria.titulo !== undefined) data.titulo = convocatoria.titulo;
        if (convocatoria.esOficial !== undefined) data.esOficial = convocatoria.esOficial;
        if (convocatoria.esSemanal !== undefined) data.esSemanal = convocatoria.esSemanal;
        
        if (convocatoria.fechaCreacion) {
            data.fechaCreacion = convocatoria.fechaCreacion instanceof Date ? Timestamp.fromDate(convocatoria.fechaCreacion) : convocatoria.fechaCreacion;
        }
        if (convocatoria.fechaEntrenamiento) {
            data.fechaEntrenamiento = convocatoria.fechaEntrenamiento instanceof Date ? Timestamp.fromDate(convocatoria.fechaEntrenamiento) : convocatoria.fechaEntrenamiento;
        }

        return data;
    }
}

import { Injectable, signal, WritableSignal, Signal, inject, Injector, runInInjectionContext } from '@angular/core';
import {
    Firestore,
    collection,
    addDoc,
    doc,
    updateDoc,
    onSnapshot,
    query,
    where,
    Timestamp,
    QuerySnapshot
} from 'firebase/firestore';
import { DesafioParticipacion, DesafioEstado } from 'gym-library';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

@Injectable({ providedIn: 'root' })
export class DesafioParticipacionService {
    private readonly firestore = inject(FIRESTORE);
    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'desafio_participaciones';

    // Cache por desafioId → Signal<DesafioParticipacion[]>
    private readonly participacionesCache = new Map<string, WritableSignal<DesafioParticipacion[]>>();
    // Cache por userId → Signal<DesafioParticipacion[]>  (las mías)
    private readonly misParticipaciones: WritableSignal<DesafioParticipacion[]> = signal([]);
    private misParticipacionesUserId: string | null = null;

    constructor() { }

    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    /** Retorna todas las participaciones de un desafío (para mostrar el conteo en la card) */
    getParticipacionesByDesafio(desafioId: string): Signal<DesafioParticipacion[]> {
        if (!this.participacionesCache.has(desafioId)) {
            const s = signal<DesafioParticipacion[]>([]);
            this.participacionesCache.set(desafioId, s);

            const col = collection(this.firestore, this.COLLECTION);
            const q = query(col, where('desafioId', '==', desafioId));
            onSnapshot(q, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    s.set(snap.docs.map(d => this.mapFromFirestore({ ...d.data(), id: d.id })));
                });
            });
        }
        return this.participacionesCache.get(desafioId)!.asReadonly();
    }

    /** Retorna las participaciones del usuario actual (para saber su estado en cada desafío) */
    getMisParticipaciones(userId: string): Signal<DesafioParticipacion[]> {
        if (this.misParticipacionesUserId !== userId) {
            this.misParticipacionesUserId = userId;
            const col = collection(this.firestore, this.COLLECTION);
            const q = query(col, where('participanteId', '==', userId));
            onSnapshot(q, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    this.misParticipaciones.set(
                        snap.docs.map(d => this.mapFromFirestore({ ...d.data(), id: d.id }))
                    );
                });
            });
        }
        return this.misParticipaciones.asReadonly();
    }

    /** Acepta el desafío — crea participación con estado 'aceptado' */
    async aceptarDesafio(
        desafioId: string,
        userId: string,
        userNombre: string,
        userFoto?: string | null
    ): Promise<void> {
        return this.runInZone(async () => {
            const col = collection(this.firestore, this.COLLECTION);
            const data = {
                desafioId,
                participanteId: userId,
                participanteNombre: userNombre,
                participanteFoto: userFoto || null,
                estado: 'aceptado' as DesafioEstado,
                fechaAceptacion: Timestamp.now()
            };
            await addDoc(col, data);
        });
    }

    /** Declara si el usuario superó o no el desafío */
    async declararResultado(participacionId: string, superado: boolean): Promise<void> {
        return this.runInZone(async () => {
            const docRef = doc(this.firestore, this.COLLECTION, participacionId);
            await updateDoc(docRef, {
                estado: (superado ? 'superado' : 'no_superado') as DesafioEstado,
                fechaRespuesta: Timestamp.now()
            });
        });
    }

    private mapFromFirestore(data: any): DesafioParticipacion {
        return {
            id: data.id,
            desafioId: data.desafioId || '',
            participanteId: data.participanteId || '',
            participanteNombre: data.participanteNombre || 'Atleta',
            participanteFoto: data.participanteFoto || null,
            estado: data.estado || 'aceptado',
            fechaAceptacion: data.fechaAceptacion instanceof Timestamp
                ? data.fechaAceptacion.toDate()
                : new Date(data.fechaAceptacion),
            fechaRespuesta: data.fechaRespuesta instanceof Timestamp
                ? data.fechaRespuesta.toDate()
                : (data.fechaRespuesta ? new Date(data.fechaRespuesta) : undefined)
        };
    }
}

import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
    Firestore,
    collection,
    addDoc,
    doc,
    deleteDoc,
    setDoc,
    onSnapshot,
    query,
    where,
    Timestamp,
    QuerySnapshot,
    DocumentSnapshot
} from 'firebase/firestore';
import { Desafio } from 'gym-library';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

@Injectable({ providedIn: 'root' })
export class DesafioService {
    private readonly firestore = inject(FIRESTORE);
    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'desafios';

    private readonly _desafios: WritableSignal<Desafio[]> = signal<Desafio[]>([]);
    private readonly desafioSignals = new Map<string, WritableSignal<Desafio | null>>();
    private isListenerInitialized = false;

    constructor() { }

    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    /**
     * Inicializa listener.
     * Si se pasa gymId, filtra por gimnasio (recomendado para entrenados/social).
     */
    private initializeListener(gymId?: string): void {
        if (this.isListenerInitialized) return;

        try {
            const col = collection(this.firestore, this.COLLECTION);
            let q = query(col, where('activo', '==', true));

            if (gymId) {
                q = query(col, where('activo', '==', true), where('gimnasioId', '==', gymId));
            }

            onSnapshot(q, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
                    this._desafios.set(list);
                });
            });
            this.isListenerInitialized = true;
        } catch (e) {
            console.warn('Error inicializando listener de desafios:', e);
        }
    }

    get desafios(): Signal<Desafio[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return this._desafios.asReadonly();
    }

    /** Versión gym-scoped (mejor para sección de entrenados) */
    getDesafiosForGym(gymId: string): Signal<Desafio[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener(gymId);
        }
        return this._desafios.asReadonly();
    }

    getDesafio(id: string): Signal<Desafio | null> {
        if (!this.desafioSignals.has(id)) {
            const desafioSignal = signal<Desafio | null>(null);
            this.desafioSignals.set(id, desafioSignal);

            const desafioRef = doc(this.firestore, this.COLLECTION, id);
            onSnapshot(desafioRef, (docSnap: DocumentSnapshot) => {
                this.runInZone(() => {
                    if (docSnap.exists()) {
                        desafioSignal.set(this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
                    } else {
                        desafioSignal.set(null);
                    }
                });
            });
        }
        return this.desafioSignals.get(id)!.asReadonly();
    }

    async save(desafio: Desafio): Promise<void> {
        return this.runInZone(async () => {
            const dataToSave = this.mapToFirestore(desafio);
            if (desafio.id) {
                const desafioRef = doc(this.firestore, this.COLLECTION, desafio.id);
                await setDoc(desafioRef, dataToSave, { merge: true });
            } else {
                const col = collection(this.firestore, this.COLLECTION);
                const docRef = await addDoc(col, dataToSave);
                desafio.id = docRef.id;
            }
        });
    }

    async delete(id: string): Promise<void> {
        return this.runInZone(async () => {
            const desafioRef = doc(this.firestore, this.COLLECTION, id);
            await deleteDoc(desafioRef);
        });
    }

    getDesafiosByGimnasio(gimnasioId: string): Signal<Desafio[]> {
        return computed(() => {
            const now = new Date();
            return this.desafios().filter(d =>
                d.gimnasioId === gimnasioId &&
                d.activo &&
                new Date(d.fechaVencimiento) > now
            );
        });
    }

    getDesafiosByCreador(creadorId: string): Signal<Desafio[]> {
        return computed(() =>
            this.desafios().filter(d => d.creadorId === creadorId)
        );
    }

    private mapFromFirestore(data: any): Desafio {
        return {
            id: data.id,
            creadorId: data.creadorId || '',
            creadorNombre: data.creadorNombre || '',
            creadorFoto: data.creadorFoto || null,
            gimnasioId: data.gimnasioId || '',
            titulo: data.titulo || '',
            logroRelacionado: data.logroRelacionado || null,
            disciplina: data.disciplina || null,
            fechaCreacion: data.fechaCreacion instanceof Timestamp
                ? data.fechaCreacion.toDate()
                : (data.fechaCreacion ? new Date(data.fechaCreacion) : new Date()),
            fechaVencimiento: data.fechaVencimiento instanceof Timestamp
                ? data.fechaVencimiento.toDate()
                : (data.fechaVencimiento ? new Date(data.fechaVencimiento) : new Date()),
            activo: data.activo ?? true
        };
    }

    private mapToFirestore(desafio: Desafio): any {
        const data: any = {
            creadorId: desafio.creadorId,
            creadorNombre: desafio.creadorNombre,
            gimnasioId: desafio.gimnasioId,
            titulo: desafio.titulo,
            activo: desafio.activo ?? true
        };

        if (desafio.creadorFoto) data.creadorFoto = desafio.creadorFoto;
        if (desafio.logroRelacionado) data.logroRelacionado = desafio.logroRelacionado;
        if (desafio.disciplina) data.disciplina = desafio.disciplina;
        if (desafio.fechaCreacion) {
            data.fechaCreacion = desafio.fechaCreacion instanceof Date
                ? Timestamp.fromDate(desafio.fechaCreacion)
                : desafio.fechaCreacion;
        }
        if (desafio.fechaVencimiento) {
            data.fechaVencimiento = desafio.fechaVencimiento instanceof Date
                ? Timestamp.fromDate(desafio.fechaVencimiento)
                : desafio.fechaVencimiento;
        }

        return data;
    }
}

import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
