/**
 * Errores de validación personalizados
 */
export class EjercicioValidationError extends Error {
	constructor(message: string) {
		super(message);
		this.name = 'EjercicioValidationError';
	}
}

@Injectable({ providedIn: 'root' })
export class EjercicioService {
	private readonly firestore = inject(FIRESTORE);

	private readonly injector = inject(Injector);
	private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
	private readonly COLLECTION = 'ejercicios';

	private readonly _ejercicios: WritableSignal<Ejercicio[]> = signal<Ejercicio[]>([]);
	private readonly ejercicioSignals = new Map<string, WritableSignal<Ejercicio | null>>();
	private readonly isSubscribed = new Map<string, boolean>();
	private readonly computedFilters = new Map<string, Signal<Ejercicio[]>>();
	private isListenerInitialized = false;

	/**
	 * Devuelve los ejercicios "creados por el usuario", combinando:
	 * - Los que tienen `creadorId` (nuevo modelo)
	 * - Los que están en la lista legacy `ejerciciosCreadosIds` del perfil de entrenado
	 */
	getCreatedByUser(userId: string, legacyCreatedIds: string[] = []): Signal<Ejercicio[]> {
		return computed(() => {
			const all = this.ejercicios();
			const byCreator = all.filter(e => e.creadorId === userId);
			const legacySet = new Set(legacyCreatedIds);
			const byLegacy = all.filter(e => legacySet.has(e.id));

			const map = new Map<string, Ejercicio>();
			[...byCreator, ...byLegacy].forEach(e => map.set(e.id, e));
			return Array.from(map.values());
		});
	}

	private filterByRange<T>(items: T[], getValue: (item: T) => number, min: number, max?: number): T[] {
		return items.filter(item => {
			const value = getValue(item);
			if (max !== undefined) {
				return value >= min && value <= max;
			}
			return value >= min;
		});
	}

	constructor() { }

	/**
	 * Ejecuta el callback en el contexto correcto (zona o inyección)
	 */
	private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
		if (this.zoneRunner) {
			return this.zoneRunner.run(callback);
		}
		return runInInjectionContext(this.injector, callback as any);
	}

	/**
	 * Inicializa el listener de Firestore de forma segura.
	 * Si se pasa gymId, filtra por gimnasio (recomendado para entrenados/creaciones).
	 */
	private initializeListener(gymId?: string): void {
		if (this.isListenerInitialized) return;

		try {
			const col = collection(this.firestore, this.COLLECTION);
			let q: any = col;

			if (gymId) {
				q = query(col, where('gimnasioId', '==', gymId));
			}

			onSnapshot(q, (snap: QuerySnapshot) => {
				this.runInZone(() => {
					const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
					this._ejercicios.set(list);
				});
			});
			this.isListenerInitialized = true;
		} catch (e) {
			console.warn('Error inicializando listener de ejercicios:', e);
		}
	}

	/**
	 * Signal readonly con todos los ejercicios
	 */
	get ejercicios(): Signal<Ejercicio[]> {
		if (!this.isListenerInitialized) {
			this.initializeListener();
		}
		return this._ejercicios.asReadonly();
	}

	/**
	 * Versión gym-scoped para la sección de entrenados.
	 */
	getEjerciciosForGym(gymId: string): Signal<Ejercicio[]> {
		if (!this.isListenerInitialized) {
			this.initializeListener(gymId);
		}
		return this._ejercicios.asReadonly();
	}

	/**
	 * Obtiene un ejercicio específico por ID
	 */
	getEjercicio(id: string): Signal<Ejercicio | null> {
		if (!this.ejercicioSignals.has(id)) {
			const ejercicioSignal = signal<Ejercicio | null>(null);
			this.ejercicioSignals.set(id, ejercicioSignal);
			this.isSubscribed.set(id, false);

			const ejercicioRef = doc(this.firestore, this.COLLECTION, id);
			onSnapshot(ejercicioRef, (docSnap: DocumentSnapshot) => {
				this.runInZone(() => {
					if (docSnap.exists()) {
						ejercicioSignal.set(this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
					} else {
						ejercicioSignal.set(null);
					}
					this.isSubscribed.set(id, true);
				});
			});
		}
		return this.ejercicioSignals.get(id)!.asReadonly();
	}

	/**
	 * Valida las reglas de negocio del ejercicio
	 * @throws {EjercicioValidationError} Si la validación falla
	 */
	validateEjercicio(ejercicio: Ejercicio): void {
		if (ejercicio.series < 0) {
			throw new EjercicioValidationError('Las series deben ser un valor positivo');
		}

		if (ejercicio.repeticiones < 0) {
			throw new EjercicioValidationError('Las repeticiones deben ser un valor positivo');
		}

		if (ejercicio.peso !== undefined && ejercicio.peso < 0) {
			throw new EjercicioValidationError('El peso debe ser un valor positivo');
		}
	}

	/**
	 * Normaliza y limpia el ejercicio antes de guardar
	 */
	private normalizeEjercicio(ejercicio: Ejercicio): Ejercicio {
		const normalized: any = { ...ejercicio };

		if (!normalized.nombre || normalized.nombre.trim() === '') {
			throw new EjercicioValidationError('El nombre del ejercicio es obligatorio');
		}
		normalized.nombre = normalized.nombre.trim();
		if (normalized.descripcion) {
			normalized.descripcion = normalized.descripcion.trim();
			if (normalized.descripcion === '') {
				delete normalized.descripcion;
			}
		}

		// Eliminar cualquier campo undefined para evitar errores en Firestore
		Object.keys(normalized).forEach(key => {
			if (normalized[key] === undefined) {
				delete normalized[key];
			}
		});

		const now = new Date();
		if (!normalized.id || normalized.id === '') {
			normalized.fechaCreacion = now;
		}
		normalized.fechaModificacion = now;

		return normalized;
	}

	/**
	 * Guarda o actualiza un ejercicio (upsert si tiene id). Aplica validaciones y normalización automáticamente.
	 * @throws {EjercicioValidationError} Si la validación falla
	 */
	async save(ejercicio: Ejercicio): Promise<void> {
		const normalizedEjercicio = this.normalizeEjercicio(ejercicio);
		this.validateEjercicio(normalizedEjercicio);

		return this.runInZone(async () => {
			const dataToSave = this.mapToFirestore(normalizedEjercicio);
			if (normalizedEjercicio.id) {
				const ejercicioRef = doc(this.firestore, this.COLLECTION, normalizedEjercicio.id);
				await setDoc(ejercicioRef, dataToSave, { merge: true });
			} else {
				const col = collection(this.firestore, this.COLLECTION);
				await addDoc(col, dataToSave);
			}
		});
	}

	/**
	 * Elimina un ejercicio por ID
	 */
	async delete(id: string): Promise<void> {
		return this.runInZone(async () => {
			const ejercicioRef = doc(this.firestore, this.COLLECTION, id);
			await deleteDoc(ejercicioRef);
		});
	}

	/**
	 * Busca ejercicios por nombre
	 */
	getEjerciciosByNombre(nombre: string): Signal<Ejercicio[]> {
		const key = `nombre-${nombre}`;
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this._ejercicios().filter(ejercicio =>
					ejercicio.nombre.toLowerCase().includes(nombre.toLowerCase())
				)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Busca ejercicios por descripción
	 */
	getEjerciciosByDescripcion(descripcion: string): Signal<Ejercicio[]> {
		const key = `descripcion-${descripcion}`;
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this._ejercicios().filter(ejercicio =>
					ejercicio.descripcion?.toLowerCase().includes(descripcion.toLowerCase())
				)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Busca ejercicios por rango de series
	 */
	getEjerciciosBySeries(minSeries: number, maxSeries?: number): Signal<Ejercicio[]> {
		const key = `series-${minSeries}-${maxSeries || 'max'}`;
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this.filterByRange(this._ejercicios(), e => e.series, minSeries, maxSeries)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Obtiene el conteo total de ejercicios
	 */
	get ejercicioCount(): Signal<number> {
		return computed(() => this._ejercicios().length);
	}

	/**
	 * Busca ejercicios por rango de repeticiones
	 */
	getEjerciciosByRepeticiones(minReps: number, maxReps?: number): Signal<Ejercicio[]> {
		const key = `repeticiones-${minReps}-${maxReps || 'max'}`;
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this.filterByRange(this._ejercicios(), e => e.repeticiones, minReps, maxReps)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Obtiene ejercicios con peso específico
	 */
	getEjerciciosConPeso(): Signal<Ejercicio[]> {
		const key = 'con-peso';
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this._ejercicios().filter(ejercicio => ejercicio.peso && ejercicio.peso > 0)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Obtiene ejercicios sin peso (peso corporal)
	 */
	getEjerciciosSinPeso(): Signal<Ejercicio[]> {
		const key = 'sin-peso';
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this._ejercicios().filter(ejercicio => !ejercicio.peso || ejercicio.peso === 0)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Verifica si un rol puede crear ejercicios
	 */
	static canCreateEjercicio(rol: Rol): boolean {
		return rol === Rol.ENTRENADO || rol === Rol.ENTRENADOR;
	}

	/**
	 * Obtiene los roles que pueden crear ejercicios
	 */
	static getRolesCreadores(): Rol[] {
		return [Rol.ENTRENADO, Rol.ENTRENADOR];
	}

	private mapFromFirestore(data: any): Ejercicio {
		return {
			id: data.id,
			nombre: data.nombre || '',
			descripcion: data.descripcion,
			series: data.series || 0,
			repeticiones: data.repeticiones || 0,
			peso: data.peso,
			descansoSegundos: data.descansoSegundos,
			serieSegundos: data.serieSegundos,
			fechaCreacion: data.fechaCreacion instanceof Timestamp ? data.fechaCreacion.toDate() : data.fechaCreacion,
			fechaModificacion: data.fechaModificacion instanceof Timestamp ? data.fechaModificacion.toDate() : data.fechaModificacion,
			creadorId: data.creadorId
		};
	}

	private mapToFirestore(ejercicio: Ejercicio): any {
		const data: any = {
			nombre: ejercicio.nombre,
			descripcion: ejercicio.descripcion || null,
			series: ejercicio.series,
			repeticiones: ejercicio.repeticiones
		};

		if (ejercicio.peso !== undefined) data.peso = ejercicio.peso;
		if (ejercicio.descansoSegundos !== undefined) data.descansoSegundos = ejercicio.descansoSegundos;
		if (ejercicio.serieSegundos !== undefined) data.serieSegundos = ejercicio.serieSegundos;
		if (ejercicio.fechaCreacion) data.fechaCreacion = ejercicio.fechaCreacion instanceof Date ? Timestamp.fromDate(ejercicio.fechaCreacion) : ejercicio.fechaCreacion;
		if (ejercicio.fechaModificacion) data.fechaModificacion = ejercicio.fechaModificacion instanceof Date ? Timestamp.fromDate(ejercicio.fechaModificacion) : ejercicio.fechaModificacion;
		if (ejercicio.creadorId) data.creadorId = ejercicio.creadorId;

		return data;
	}
}

import { Injectable, signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
  Firestore,
  collection,
  addDoc,
  doc,
  deleteDoc,
  setDoc,
  onSnapshot,
  QuerySnapshot,
  DocumentSnapshot,
  Timestamp,
  query,
  where,
  updateDoc
} from 'firebase/firestore';
import { Entrenador, Ejercicio, Plan, Rol, PlanLimits, ROL_PLAN_LIMITS } from 'gym-library';
import { RutinaService } from './rutina.service';
import { EjercicioService } from './ejercicio.service';
import { EntrenadoService } from './entrenado.service';
import { UserService } from './user.service';
import { NotificacionService } from './notificacion.service';
import { MensajeService } from './mensaje.service';
import { InvitacionService } from './invitacion.service';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

// Clase de error personalizada para límites
export class PlanLimitError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'PlanLimitError';
  }
}

/**
 * 🏋️‍♂️ Servicio de gestión de Entrenadores
 */
@Injectable({
  providedIn: 'root'
})
export class EntrenadorService {
  private readonly firestore = inject(FIRESTORE);
  private readonly injector = inject(Injector);
  private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
  private readonly COLLECTION = 'entrenadores';

  private rutinaService = inject(RutinaService);
  private ejercicioService = inject(EjercicioService);
  private entrenadoService = inject(EntrenadoService);
  private userService = inject(UserService);
  private notificacionService = inject(NotificacionService);
  private mensajeService = inject(MensajeService);
  private invitacionService = inject(InvitacionService);

  // 📊 Signals para el estado de los entrenadores
  private readonly _entrenadores = signal<Entrenador[]>([]);
  private readonly _loading = signal<boolean>(false);
  private readonly _error = signal<string | null>(null);

  // 🔍 Signals públicos de solo lectura
  readonly entrenadores = this._entrenadores.asReadonly();
  readonly loading = this._loading.asReadonly();
  readonly error = this._error.asReadonly();

  private isListenerInitialized = false;

  // Cache para límites por entrenador (evita búsquedas repetidas)
  private limitsCache = new Map<string, PlanLimits>();

  constructor() { }

  /**
   * Ejecuta el callback en el contexto correcto (zona o inyección)
   */
  private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
    if (this.zoneRunner) {
      return this.zoneRunner.run(callback);
    }
    return runInInjectionContext(this.injector, callback as any);
  }

  // Métodos para límites de plan
  getLimits(entrenadorId: string): PlanLimits {
    if (this.limitsCache.has(entrenadorId)) {
      return this.limitsCache.get(entrenadorId)!;
    }
    const user = this.userService.users().find(u => u.uid === entrenadorId);
    const plan = user?.plan || Plan.FREE;
    const limits = ROL_PLAN_LIMITS[Rol.ENTRENADOR][plan];
    this.limitsCache.set(entrenadorId, limits);
    return limits;
  }

  private validateLimit(entrenadorId: string, currentCount: number, max: number, item: string): void {
    if (currentCount >= max) {
      throw new PlanLimitError(`Límite alcanzado: ${currentCount}/${max} ${item} en plan free.`);
    }
  }

  private async addItemWithLimit(
    entrenadorId: string,
    itemId: string,
    arrayKey: keyof Entrenador,
    maxKey: keyof ReturnType<typeof this.getLimits>,
    itemName: string
  ): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (!entrenador) return;

    const limits = this.getLimits(entrenadorId);
    const currentArray = (entrenador[arrayKey] as string[]) || [];
    this.validateLimit(entrenadorId, currentArray.length, limits[maxKey] as number, itemName);

    if (!currentArray.includes(itemId)) {
      const updatedArray = [...currentArray, itemId];
      await this.update(entrenadorId, { [arrayKey]: updatedArray });
    }
  }

  invalidateLimitsCache(entrenadorId: string): void {
    this.limitsCache.delete(entrenadorId);
  }

  /**
   * Inicializa el listener de entrenadores
   */
  initializeListener(): void {
    if (this.isListenerInitialized) return;

    this._loading.set(true);
    this._error.set(null);
    try {
      const col = collection(this.firestore, this.COLLECTION);
      onSnapshot(col, (snap: QuerySnapshot) => {
        this.runInZone(() => {
          const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
          this._entrenadores.set(list);
          this._loading.set(false);
          this._error.set(null);
        });
      }, (error) => {
        this.runInZone(() => {
          console.error('❌ Error en listener de entrenadores:', error);
          this._error.set('Error al cargar entrenadores');
          this._loading.set(false);
        });
      });
      this.isListenerInitialized = true;
    } catch (error) {
      console.error('❌ Error al inicializar listener de entrenadores:', error);
      this._error.set('Error al inicializar entrenadores');
      this._loading.set(false);
    }
  }

  /**
   * Crea un nuevo entrenador
   */
  async create(entrenadorData: Omit<Entrenador, 'id'>): Promise<string> {
    this._loading.set(true);
    this._error.set(null);
    try {
      return await this.runInZone(async () => {
        const docRef = await addDoc(collection(this.firestore, this.COLLECTION), this.mapToFirestore(entrenadorData));
        return docRef.id;
      });
    } catch (error) {
      console.error('❌ Error al crear entrenador:', error);
      this._error.set('Error al crear entrenador');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Crea un nuevo entrenador con ID específico
   */
  async createWithId(id: string, entrenadorData: Omit<Entrenador, 'id'>): Promise<void> {
    this._loading.set(true);
    this._error.set(null);
    try {
      await this.runInZone(async () => {
        await setDoc(doc(this.firestore, this.COLLECTION, id), this.mapToFirestore(entrenadorData));
      });
    } catch (error) {
      this._error.set('Error al crear entrenador');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Actualiza un entrenador existente
   */
  async update(id: string, entrenadorData: Partial<Entrenador>): Promise<void> {
    this._loading.set(true);
    this._error.set(null);
    try {
      await this.runInZone(async () => {
        const dataToUpdate = this.mapPartialToFirestore(entrenadorData);
        await updateDoc(doc(this.firestore, this.COLLECTION, id), dataToUpdate);
      });
    } catch (error) {
      console.error('❌ Error al actualizar entrenador:', error);
      this._error.set('Error al actualizar entrenador');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Elimina un entrenador
   */
  async delete(id: string): Promise<void> {
    this._loading.set(true);
    this._error.set(null);
    try {
      await this.runInZone(async () => {
        await deleteDoc(doc(this.firestore, this.COLLECTION, id));
      });
    } catch (error) {
      console.error('❌ Error al eliminar entrenador:', error);
      this._error.set('Error al eliminar entrenador');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Busca un entrenador por ID
   */
  getEntrenadorById(id: string) {
    return computed(() =>
      this._entrenadores().find(entrenador => entrenador.id === id)
    );
  }

  /**
   * Obtiene las rutinas de un entrenador específico
   */
  getRutinasByEntrenador(entrenadorId: string) {
    return computed(() => {
      const entrenador = this._entrenadores().find(e => e.id === entrenadorId);
      if (!entrenador || !entrenador.rutinasCreadasIds) return [];
      return this.rutinaService.rutinas().filter(rutina =>
        entrenador.rutinasCreadasIds.includes(rutina.id)
      );
    });
  }

  /**
   * Obtiene los ejercicios de un entrenador específico
   */
  getEjerciciosByEntrenador(entrenadorId: string) {
    return computed(() => {
      return this.ejercicioService.ejercicios().filter(ejercicio =>
        ejercicio.creadorId === entrenadorId
      );
    });
  }

  /**
   * Obtiene las invitaciones de un entrenador específico
   */
  getInvitacionesByEntrenador(entrenadorId: string) {
    return this.invitacionService.getInvitacionesPorEntrenador(entrenadorId);
  }

  /**
   * Obtiene los mensajes de un entrenador específico
   */
  getMensajesByEntrenador(entrenadorId: string) {
    return this.mensajeService.getMensajesByEntrenador(entrenadorId);
  }

  /**
   * Obtiene el conteo de entrenados asignados a un entrenador
   */
  getEntrenadosCount(entrenadorId: string) {
    return computed(() => {
      const entrenador = this.getEntrenadorById(entrenadorId)();
      return entrenador?.entrenadosAsignadosIds?.length || 0;
    });
  }

  /**
   * Desvincula un entrenado de un entrenador
   */
  async desvincularEntrenado(entrenadorId: string, entrenadoId: string): Promise<void> {
    const entrenado = this.entrenadoService.getEntrenadoById(entrenadoId)();
    if (entrenado) {
      const entrenadoresId = (entrenado.entrenadoresId || []).filter((id: string) => id !== entrenadorId);
      await this.entrenadoService.save({ ...entrenado, entrenadoresId });
    }

    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (entrenador) {
      const entrenadosAsignadosIds = (entrenador.entrenadosAsignadosIds || []).filter((id: string) => id !== entrenadoId);
      await this.update(entrenadorId, { entrenadosAsignadosIds });
    }
  }

  /**
   * Obtiene los entrenadores con información de usuario combinada
   */
  getEntrenadoresWithUserInfo() {
    return computed(() => {
      return this._entrenadores().map(entrenador => {
        const usuario = this.userService.users().find(u => u.uid === entrenador.id);
        return {
          ...entrenador,
          displayName: usuario?.nombre || usuario?.email || `Usuario ${entrenador.id}`,
          email: usuario?.email || '',
          plan: usuario?.plan || 'free'
        };
      });
    });
  }

  /**
   * ➕ Agrega un ejercicio a la lista de ejercicios creados de un entrenador
   */
  async addEjercicioCreado(entrenadorId: string, ejercicioId: string): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (!entrenador) return;

    const limits = this.getLimits(entrenadorId);
    if (!limits.allowCustomTimers) { // Plan free
      const ejercicio = this.ejercicioService.getEjercicio(ejercicioId)();
      if (ejercicio && (ejercicio.descansoSegundos !== undefined || ejercicio.serieSegundos !== undefined)) {
        throw new PlanLimitError('En el plan free no se pueden configurar tiempos de descanso o serie. Actualiza a premium.');
      }
    }

    const currentCount = entrenador.ejerciciosCreadasIds?.length || 0;
    this.validateLimit(entrenadorId, currentCount, limits.maxExercises, 'ejercicios');

    const ejerciciosCreadasIds = [...(entrenador.ejerciciosCreadasIds || [])];
    if (!ejerciciosCreadasIds.includes(ejercicioId)) {
      ejerciciosCreadasIds.push(ejercicioId);
      await this.update(entrenadorId, { ejerciciosCreadasIds });
    }
  }

  /**
   * ➖ Quita un ejercicio de la lista de ejercicios creados de un entrenador
   */
  async removeEjercicioCreado(entrenadorId: string, ejercicioId: string): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (entrenador) {
      const ejerciciosCreadasIds = (entrenador.ejerciciosCreadasIds || []).filter((id: string) => id !== ejercicioId);
      await this.update(entrenadorId, { ejerciciosCreadasIds });
    }
  }

  async deleteEjercicioCreado(entrenadorId: string, ejercicioId: string): Promise<void> {
    await this.ejercicioService.delete(ejercicioId);
    await this.removeEjercicioCreado(entrenadorId, ejercicioId);
  }

  async addRutinaCreada(entrenadorId: string, rutinaId: string): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (!entrenador) return;

    const limits = this.getLimits(entrenadorId);
    if (!limits.allowCustomDuration) { // Plan free
      const rutina = this.rutinaService.getRutina(rutinaId)();
      if (rutina && rutina.duracion !== undefined) {
        throw new PlanLimitError('En el plan free no se pueden configurar duración. Actualiza a premium.');
      }
    }

    await this.addItemWithLimit(entrenadorId, rutinaId, 'rutinasCreadasIds', 'maxRoutines', 'rutinas');
  }

  async removeRutinaCreada(entrenadorId: string, rutinaId: string): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (entrenador) {
      const rutinasCreadasIds = (entrenador.rutinasCreadasIds || []).filter((id: string) => id !== rutinaId);
      await this.update(entrenadorId, { rutinasCreadasIds });
    }
  }

  async asignarEntrenado(entrenadorId: string, entrenadoId: string): Promise<void> {
    await this.addItemWithLimit(entrenadorId, entrenadoId, 'entrenadosAsignadosIds', 'maxClients', 'clientes activos');
    const entrenado = this.entrenadoService.getEntrenadoById(entrenadoId)();
    if (entrenado) {
      const entrenadoresId = [...(entrenado.entrenadoresId || []), entrenadorId];
      await this.entrenadoService.save({ ...entrenado, entrenadoresId });
    }
  }

  private mapToFirestore(entrenador: Omit<Entrenador, 'id'> | Entrenador): any {
    const data = { ...entrenador } as any;
    if (entrenador.fechaRegistro) {
      data.fechaRegistro = Timestamp.fromDate(entrenador.fechaRegistro);
    }
    return data;
  }

  private mapFromFirestore(data: any): Entrenador {
    const entrenador = { ...data };
    if (data.fechaRegistro && data.fechaRegistro instanceof Timestamp) {
      entrenador.fechaRegistro = data.fechaRegistro.toDate();
    }
    return entrenador as Entrenador;
  }

  private mapPartialToFirestore(entrenador: Partial<Entrenador>): any {
    const data: any = {};
    if (entrenador.fechaRegistro !== undefined) {
      data.fechaRegistro = entrenador.fechaRegistro ? Timestamp.fromDate(entrenador.fechaRegistro) : null;
    }
    if (entrenador.ejerciciosCreadasIds !== undefined) data.ejerciciosCreadasIds = entrenador.ejerciciosCreadasIds;
    if (entrenador.entrenadosAsignadosIds !== undefined) data.entrenadosAsignadosIds = entrenador.entrenadosAsignadosIds;
    if (entrenador.rutinasCreadasIds !== undefined) data.rutinasCreadasIds = entrenador.rutinasCreadasIds;
    return data;
  }
}

import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
    Firestore,
    collection,
    addDoc,
    doc,
    deleteDoc,
    setDoc,
    onSnapshot,
    QuerySnapshot,
    DocumentSnapshot,
    Timestamp,
    query,
    where,
    updateDoc,
    arrayUnion,
    arrayRemove
} from 'firebase/firestore';
import { Entrenado } from 'gym-library';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

@Injectable({ providedIn: 'root' })
export class EntrenadoService {
    private readonly firestore = inject(FIRESTORE);
    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'entrenados';

    // Señal que contiene la lista de entrenados (reactiva)
    private readonly _entrenados: WritableSignal<Entrenado[]> = signal<Entrenado[]>([]);
    private readonly entrenadoSignals = new Map<string, WritableSignal<Entrenado | null>>();
    private isListenerInitialized = false;

    constructor() { }

    /**
     * Ejecuta el callback en el contexto correcto (zona o inyección)
     */
    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    /**
     * 🔄 Inicializa el listener de Firestore de forma segura (carga TODOS los entrenados).
     *
     * Medium priority improvement: para apps con muchos gimnasios, idealmente
     * deberíamos tener listeners por `gimnasioId` (especialmente para "Descubrir" y sugerencias).
     * Actualmente el filtro por gym se hace en cliente en los componentes.
     */
    initializeListener(gymId?: string): void {
        if (this.isListenerInitialized) return;

        try {
            const col = collection(this.firestore, this.COLLECTION);
            let q: any = col;

            if (gymId) {
                q = query(col, where('gimnasioId', '==', gymId));
            }

            onSnapshot(q, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
                    this._entrenados.set(list);
                });
            });
            this.isListenerInitialized = true;
        } catch (e) {
            console.warn('Error inicializando listener de entrenados:', e);
        }
    }

    /**
     * 📊 Signal readonly con la lista de entrenados
     */
    get entrenados(): Signal<Entrenado[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return this._entrenados.asReadonly();
    }

    /**
     * Versión gym-scoped (para Descubrir / MatchService en entrenados).
     */
    getEntrenadosForGym(gymId: string): Signal<Entrenado[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener(gymId);
        }
        return this._entrenados.asReadonly();
    }

    /**
     * 📊 Obtiene un entrenado específico por ID
     */
    getEntrenado(id: string): Signal<Entrenado | null> {
        if (!this.entrenadoSignals.has(id)) {
            const entrenadoSignal = signal<Entrenado | null>(null);
            this.entrenadoSignals.set(id, entrenadoSignal);

            const entrenadoRef = doc(this.firestore, this.COLLECTION, id);
            onSnapshot(entrenadoRef, (docSnap: DocumentSnapshot) => {
                this.runInZone(() => {
                    if (docSnap.exists()) {
                        entrenadoSignal.set(this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
                    } else {
                        entrenadoSignal.set(null);
                    }
                });
            });
        }
        return this.entrenadoSignals.get(id)!.asReadonly();
    }

    /**
     * 💾 Guarda o actualiza un entrenado (upsert si tiene id)
     */
    async save(entrenado: Entrenado): Promise<void> {
        return this.runInZone(async () => {
            const dataToSave = this.mapToFirestore(entrenado);
            if (entrenado.id) {
                const entrenadoRef = doc(this.firestore, this.COLLECTION, entrenado.id);
                await setDoc(entrenadoRef, dataToSave, { merge: true });
            } else {
                const col = collection(this.firestore, this.COLLECTION);
                const docRef = await addDoc(col, dataToSave);
                entrenado.id = docRef.id;
            }
        });
    }

    /**
     * 🗑️ Elimina un entrenado por ID
     */
    async delete(id: string): Promise<void> {
        return this.runInZone(async () => {
            const entrenadoRef = doc(this.firestore, this.COLLECTION, id);
            await deleteDoc(entrenadoRef);
        });
    }

    /**
     * 👥 Sigue a un usuario
     */
    async followUser(currentUserId: string, targetUserId: string): Promise<void> {
        return this.runInZone(async () => {
            const currentUserRef = doc(this.firestore, this.COLLECTION, currentUserId);
            const targetUserRef = doc(this.firestore, this.COLLECTION, targetUserId);

            // Añadir al target a mis seguidos
            await updateDoc(currentUserRef, {
                seguidos: arrayUnion(targetUserId)
            });

            // Añadirme a los seguidores del target
            await updateDoc(targetUserRef, {
                seguidores: arrayUnion(currentUserId)
            });
        });
    }

    /**
     * 👥 Deja de seguir a un usuario
     */
    async unfollowUser(currentUserId: string, targetUserId: string): Promise<void> {
        return this.runInZone(async () => {
            const currentUserRef = doc(this.firestore, this.COLLECTION, currentUserId);
            const targetUserRef = doc(this.firestore, this.COLLECTION, targetUserId);

            // Quitar al target de mis seguidos
            await updateDoc(currentUserRef, {
                seguidos: arrayRemove(targetUserId)
            });

            // Quitarme de los seguidores del target
            await updateDoc(targetUserRef, {
                seguidores: arrayRemove(currentUserId)
            });
        });
    }

    /**
     * 🔍 Busca entrenados por ID
     */
    getEntrenadoById(id: string): Signal<Entrenado | null> {
        return computed(() =>
            this._entrenados().find(entrenado => entrenado.id === id) || null
        );
    }

    /**
     * 🔍 Busca entrenados por objetivo
     */
    getEntrenadosByObjetivo(objetivo: string): Signal<Entrenado[]> {
        return computed(() =>
            this._entrenados().filter(entrenado =>
                entrenado.objetivo === objetivo
            )
        );
    }

    /**
     * 🔍 Busca entrenados por entrenador
     */
    getEntrenadosByEntrenador(entrenadorId: string): Signal<Entrenado[]> {
        return computed(() =>
            this._entrenados().filter(entrenado =>
                entrenado.entrenadoresId?.includes(entrenadorId)
            )
        );
    }

    /**
     * 🔍 Busca entrenados que tienen una rutina asignada específica
     * NOTA: Este método ahora usa RutinaAsignadaService. Implementar cuando esté disponible.
     */
    getEntrenadosByRutinaAsignada(rutinaId: string): Signal<Entrenado[]> {
        // TODO: Implementar usando RutinaAsignadaService
        return computed(() => []);
    }    /**
     * 🔍 Busca entrenados que han creado una rutina específica
     */
    getEntrenadosByRutinaCreada(rutinaId: string): Signal<Entrenado[]> {
        return computed(() =>
            this._entrenados().filter(entrenado =>
                entrenado.rutinasCreadas?.includes(rutinaId)
            )
        );
    }

    /**
     * 📊 Obtiene entrenados activos
     */
    getEntrenadosActivos(): Signal<Entrenado[]> {
        return computed(() =>
            this._entrenados()
        );
    }

    /**
     * 📊 Obtiene el conteo total de entrenados
     */
    get entrenadoCount(): Signal<number> {
        return computed(() => this._entrenados().length);
    }

    /**
     * 📊 Obtiene el conteo de entrenados activos
     */
    get entrenadoActivoCount(): Signal<number> {
        return computed(() => this._entrenados().length);
    }

    private mapFromFirestore(data: any): Entrenado {
        return {
            id: data.id,
            fechaRegistro: data.fechaRegistro instanceof Timestamp ? data.fechaRegistro.toDate() : (data.fechaRegistro instanceof Date ? data.fechaRegistro : new Date()),
            objetivo: data.objetivo || null,
            entrenadoresId: data.entrenadoresId || [],
            rutinasAsignadasIds: data.rutinasAsignadasIds || [],
            rutinasCreadas: data.rutinasCreadas || [],
            ejerciciosCreadosIds: data.ejerciciosCreadosIds || [],
            nivel: data.nivel || null,
            seguidores: data.seguidores || [],
            seguidos: data.seguidos || [],
            bio: data.bio || '',
            franjaHoraria: data.franjaHoraria || null,
            visibleDescubrir: data.visibleDescubrir ?? true
        };
    }
 
    private mapToFirestore(entrenado: Entrenado): any {
        const data: any = {};
        if (entrenado.objetivo !== undefined) data.objetivo = entrenado.objetivo;
        if (entrenado.fechaRegistro) {
            data.fechaRegistro = entrenado.fechaRegistro instanceof Date ? Timestamp.fromDate(entrenado.fechaRegistro) : entrenado.fechaRegistro;
        }
        if (entrenado.entrenadoresId) data.entrenadoresId = entrenado.entrenadoresId;
        if (entrenado.rutinasAsignadasIds) data.rutinasAsignadasIds = entrenado.rutinasAsignadasIds;
        if (entrenado.rutinasCreadas) data.rutinasCreadas = entrenado.rutinasCreadas;
        if (entrenado.ejerciciosCreadosIds) data.ejerciciosCreadosIds = entrenado.ejerciciosCreadosIds;
        if (entrenado.nivel !== undefined) data.nivel = entrenado.nivel;
        if (entrenado.seguidores) data.seguidores = entrenado.seguidores;
        if (entrenado.seguidos) data.seguidos = entrenado.seguidos;
        if (entrenado.bio !== undefined) data.bio = entrenado.bio;
        if (entrenado.franjaHoraria !== undefined) data.franjaHoraria = entrenado.franjaHoraria;
        if (entrenado.visibleDescubrir !== undefined) data.visibleDescubrir = entrenado.visibleDescubrir;
        return data;
    }

    /**
     * ➕ Agrega un ejercicio a la lista de ejercicios creados de un entrenado
     */
    async addEjercicioCreado(entrenadoId: string, ejercicioId: string): Promise<void> {
        const entrenado = this.getEntrenado(entrenadoId)();
        if (!entrenado) return;

        const ejerciciosCreadosIds = [...(entrenado.ejerciciosCreadosIds || [])];
        if (!ejerciciosCreadosIds.includes(ejercicioId)) {
            ejerciciosCreadosIds.push(ejercicioId);
            await this.save({ ...entrenado, ejerciciosCreadosIds });
        }
    }

    /**
     * ➖ Quita un ejercicio de la lista de ejercicios creados de un entrenado
     */
    async removeEjercicioCreado(entrenadoId: string, ejercicioId: string): Promise<void> {
        const entrenado = this.getEntrenado(entrenadoId)();
        if (entrenado) {
            const ejerciciosCreadosIds = (entrenado.ejerciciosCreadosIds || []).filter((id: string) => id !== ejercicioId);
            await this.save({ ...entrenado, ejerciciosCreadosIds });
        }
    }

    /**
     * ➕ Agrega una rutina a la lista de rutinas creadas de un entrenado
     */
    async addRutinaCreada(entrenadoId: string, rutinaId: string): Promise<void> {
        const entrenadoRef = doc(this.firestore, this.COLLECTION, entrenadoId);
        await updateDoc(entrenadoRef, {
            rutinasCreadas: arrayUnion(rutinaId)
        });
    }

    /**
     * ➖ Quita una rutina de la lista de rutinas creadas de un entrenado
     */
    async removeRutinaCreada(entrenadoId: string, rutinaId: string): Promise<void> {
        const entrenado = this.getEntrenado(entrenadoId)();
        if (entrenado) {
            const rutinasCreadas = (entrenado.rutinasCreadas || []).filter((id: string) => id !== rutinaId);
            await this.save({ ...entrenado, rutinasCreadas });
        }
    }
}

import { Injectable, signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {

  Firestore,
  collection,
  addDoc,
  doc,
  deleteDoc,
  setDoc,
  onSnapshot,
  QuerySnapshot,
  DocumentSnapshot,
  Timestamp,
  query,
  where,
  updateDoc
} from 'firebase/firestore';
import { EstadisticasEntrenado } from 'gym-library';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

/**
 * 📊 Servicio de gestión de Estadísticas de Entrenados
 * Maneja la lógica de negocio y el estado de las estadísticas directamente con Firestore
 */
@Injectable({
  providedIn: 'root'
})
export class EstadisticasEntrenadoService {
  private readonly firestore = inject(FIRESTORE);
  private readonly injector = inject(Injector);
  private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
  private readonly COLLECTION = 'estadisticas-entrenado';

  // 📊 Signals para el estado de las estadísticas
  private readonly _estadisticas = signal<Map<string, EstadisticasEntrenado>>(new Map());
  private readonly _loading = signal<boolean>(false);
  private readonly _error = signal<string | null>(null);

  // 🔍 Signals públicos de solo lectura
  readonly loading = this._loading.asReadonly();
  readonly error = this._error.asReadonly();

  private unsubscribes = new Map<string, () => void>();

  constructor() { }

  /**
   * Ejecuta el callback en el contexto correcto (zona o inyección)
   */
  private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
    if (this.zoneRunner) {
      return this.zoneRunner.run(callback);
    }
    return runInInjectionContext(this.injector, callback as any);
  }

  /**
   * Obtiene las estadísticas de un entrenado específico
   * @param entrenadoId - ID del entrenado
   * @returns Signal con las estadísticas del entrenado
   */
  getEstadisticas(entrenadoId: string) {
    return computed(() => this._estadisticas().get(entrenadoId) || null);
  }

  /**
   * Inicializa el listener para las estadísticas de un entrenado
   * @param entrenadoId - ID del entrenado
   */
  initializeListener(entrenadoId: string): void {
    if (this.unsubscribes.has(entrenadoId)) {
      return; // Ya está inicializado
    }

    this._loading.set(true);
    this._error.set(null);

    try {
      const estadisticasRef = doc(this.firestore, this.COLLECTION, entrenadoId);
      const unsubscribe = onSnapshot(estadisticasRef, (docSnap: DocumentSnapshot) => {
        this.runInZone(() => {
          const current = this._estadisticas();
          const updated = new Map(current);
          if (docSnap.exists()) {
            updated.set(entrenadoId, this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
          } else {
            updated.delete(entrenadoId);
          }
          this._estadisticas.set(updated);
          this._loading.set(false);
          this._error.set(null);
        });
      }, (error) => {
        console.error('❌ Error en listener de estadísticas:', error);
        this._error.set('Error al cargar estadísticas');
        this._loading.set(false);
      });

      this.unsubscribes.set(entrenadoId, unsubscribe);
    } catch (error) {
      console.error('❌ Error al inicializar listener de estadísticas:', error);
      this._error.set('Error al inicializar estadísticas');
      this._loading.set(false);
    }
  }

  /**
   * Detiene el listener para las estadísticas de un entrenado
   * @param entrenadoId - ID del entrenado
   */
  stopListener(entrenadoId: string): void {
    const unsubscribe = this.unsubscribes.get(entrenadoId);
    if (unsubscribe) {
      unsubscribe();
      this.unsubscribes.delete(entrenadoId);
    }
  }

  /**
   * Crea estadísticas iniciales para un entrenado
   * @param entrenadoId - ID del entrenado
   * @param estadisticas - Datos de las estadísticas
   */
  async createEstadisticas(entrenadoId: string, estadisticas: EstadisticasEntrenado): Promise<void> {
    this._loading.set(true);
    this._error.set(null);

    try {
      await this.runInZone(async () => {
        const dataToSave = this.mapToFirestore(estadisticas);
        const estadisticasRef = doc(this.firestore, this.COLLECTION, entrenadoId);
        await setDoc(estadisticasRef, dataToSave);
      });
    } catch (error) {
      console.error('❌ Error al crear estadísticas:', error);
      this._error.set('Error al crear estadísticas');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Actualiza las estadísticas de un entrenado
   * @param entrenadoId - ID del entrenado
   * @param estadisticas - Datos actualizados de las estadísticas
   */
  async updateEstadisticas(entrenadoId: string, estadisticas: Partial<EstadisticasEntrenado>): Promise<void> {
    this._loading.set(true);
    this._error.set(null);

    try {
      await this.runInZone(async () => {
        const dataToSave = this.mapToFirestore(estadisticas);
        const estadisticasRef = doc(this.firestore, this.COLLECTION, entrenadoId);
        await updateDoc(estadisticasRef, dataToSave);
      });
    } catch (error) {
      console.error('❌ Error al actualizar estadísticas:', error);
      this._error.set('Error al actualizar estadísticas');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Elimina las estadísticas de un entrenado
   * @param entrenadoId - ID del entrenado
   */
  async deleteEstadisticas(entrenadoId: string): Promise<void> {
    this._loading.set(true);
    this._error.set(null);

    try {
      await this.runInZone(async () => {
        const estadisticasRef = doc(this.firestore, this.COLLECTION, entrenadoId);
        await deleteDoc(estadisticasRef);
        // Remover del estado local
        const current = this._estadisticas();
        const updated = new Map(current);
        updated.delete(entrenadoId);
        this._estadisticas.set(updated);
      });
    } catch (error) {
      console.error('❌ Error al eliminar estadísticas:', error);
      this._error.set('Error al eliminar estadísticas');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Crea estadísticas iniciales por defecto
   * @returns Estadísticas iniciales
   */
  crearEstadisticasIniciales(): EstadisticasEntrenado {
    return {
      totalRutinasCompletadas: 0,
      rachaActual: 0,
      mejorRacha: 0,
      nivel: 1,
      experiencia: 0,
      experienciaProximoNivel: 100
    };
  }

  /**
   * Calcula el nivel basado en la experiencia
   * @param experiencia - Experiencia acumulada
   * @returns Nivel calculado
   */
  calcularNivel(experiencia: number): number {
    // Lógica simple: cada 100 XP un nivel
    return Math.floor(experiencia / 100) + 1;
  }

  /**
   * Calcula la experiencia necesaria para el próximo nivel
   * @param nivel - Nivel actual
   * @returns Experiencia necesaria para el próximo nivel
   */
  calcularExperienciaProximoNivel(nivel: number): number {
    return nivel * 100;
  }

  private mapFromFirestore(data: any): EstadisticasEntrenado {
    return {
      totalRutinasCompletadas: data.totalRutinasCompletadas || 0,
      rachaActual: data.rachaActual || 0,
      mejorRacha: data.mejorRacha || 0,
      ultimaFechaEntrenamiento: data.ultimaFechaEntrenamiento instanceof Timestamp
        ? data.ultimaFechaEntrenamiento.toDate()
        : (data.ultimaFechaEntrenamiento ? new Date(data.ultimaFechaEntrenamiento) : undefined),
      nivel: data.nivel || 1,
      experiencia: data.experiencia || 0,
      experienciaProximoNivel: data.experienciaProximoNivel || 100
    };
  }

  private mapToFirestore(estadisticas: Partial<EstadisticasEntrenado>): any {
    const data: any = {};
    if (estadisticas.totalRutinasCompletadas !== undefined) data.totalRutinasCompletadas = estadisticas.totalRutinasCompletadas;
    if (estadisticas.rachaActual !== undefined) data.rachaActual = estadisticas.rachaActual;
    if (estadisticas.mejorRacha !== undefined) data.mejorRacha = estadisticas.mejorRacha;
    if (estadisticas.ultimaFechaEntrenamiento !== undefined) {
      data.ultimaFechaEntrenamiento = estadisticas.ultimaFechaEntrenamiento instanceof Date
        ? Timestamp.fromDate(estadisticas.ultimaFechaEntrenamiento)
        : (estadisticas.ultimaFechaEntrenamiento || null);
    }
    if (estadisticas.nivel !== undefined) data.nivel = estadisticas.nivel;
    if (estadisticas.experiencia !== undefined) data.experiencia = estadisticas.experiencia;
    if (estadisticas.experienciaProximoNivel !== undefined) data.experienciaProximoNivel = estadisticas.experienciaProximoNivel;
    return data;
  }
}

import { Injectable, inject } from '@angular/core';
import {
    ref,
    uploadBytes,
    getDownloadURL,
    deleteObject,
    FirebaseStorage
} from 'firebase/storage';
import { STORAGE } from '../firebase.tokens';

@Injectable({
    providedIn: 'root'
})
export class FirebaseStorageService {
    private readonly storage = inject(STORAGE);

    /**
     * Sube un archivo a Firebase Storage
     * @param path Ruta donde se guardará el archivo (ej: 'profiles/uid/avatar.jpg')
     * @param file El archivo a subir
     * @returns La URL de descarga del archivo
     */
    async uploadFile(path: string, file: File | Blob): Promise<string> {
        const storageRef = ref(this.storage, path);
        const snapshot = await uploadBytes(storageRef, file);
        return await getDownloadURL(snapshot.ref);
    }

    /**
     * Elimina un archivo de Firebase Storage
     * @param path Ruta del archivo a eliminar
     */
    async deleteFile(path: string): Promise<void> {
        const storageRef = ref(this.storage, path);
        await deleteObject(storageRef);
    }

    /**
     * Genera una ruta para la foto de perfil de un usuario
     * @param uid UID del usuario
     * @param extension Extensión del archivo
     */
    getProfilePath(uid: string, extension: string = 'jpg'): string {
        return `profiles/${uid}/profile_${Date.now()}.${extension}`;
    }

    /**
     * Genera una ruta para la foto de progreso de una sesión
     * @param uid UID del usuario
     * @param sesionId ID de la sesión
     * @param extension Extensión del archivo
     */
    getProgressPhotoPath(uid: string, sesionId: string, extension: string = 'jpg'): string {
        return `progreso/${uid}/${sesionId}_${Date.now()}.${extension}`;
    }
}

import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
    Firestore,
    collection,
    addDoc,
    doc,
    deleteDoc,
    setDoc,
    onSnapshot,
    QuerySnapshot,
    DocumentSnapshot,
    Timestamp,
    query,
    where
} from 'firebase/firestore';
import { Gimnasio } from 'gym-library';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

@Injectable({ providedIn: 'root' })
export class GimnasioService {
    private readonly firestore = inject(FIRESTORE);
    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'gimnasios';

    private readonly _gimnasios: WritableSignal<Gimnasio[]> = signal<Gimnasio[]>([]);
    private readonly gimnasioSignals = new Map<string, WritableSignal<Gimnasio | null>>();
    private isListenerInitialized = false;

    constructor() { }

    /**
     * Ejecuta el callback en el contexto correcto (zona o inyección)
     */
    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    /**
     * 🔄 Inicializa el listener de gimnasios
     */
    initializeListener(): void {
        if (this.isListenerInitialized) return;

        try {
            const col = collection(this.firestore, this.COLLECTION);
            onSnapshot(col, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
                    this._gimnasios.set(list);
                });
            });
            this.isListenerInitialized = true;
        } catch (e) {
            console.warn('Error inicializando listener de gimnasios:', e);
        }
    }

    /**
     * 📊 Signal readonly con todos los gimnasios
     */
    get gimnasios(): Signal<Gimnasio[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return this._gimnasios.asReadonly();
    }

    /**
     * 📊 Obtiene un gimnasio específico por ID
     */
    getGimnasio(id: string): Signal<Gimnasio | null> {
        if (!this.gimnasioSignals.has(id)) {
            const gimnasioSignal = signal<Gimnasio | null>(null);
            this.gimnasioSignals.set(id, gimnasioSignal);

            const gimnasioRef = doc(this.firestore, this.COLLECTION, id);
            onSnapshot(gimnasioRef, (docSnap: DocumentSnapshot) => {
                this.runInZone(() => {
                    if (docSnap.exists()) {
                        gimnasioSignal.set(this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
                    } else {
                        gimnasioSignal.set(null);
                    }
                });
            });
        }
        return this.gimnasioSignals.get(id)!.asReadonly();
    }

    /**
     * 💾 Guarda o actualiza un gimnasio (upsert si tiene id)
     */
    async save(gimnasio: Gimnasio): Promise<void> {
        return this.runInZone(async () => {
            const dataToSave = this.mapToFirestore(gimnasio);
            if (gimnasio.id) {
                const gimnasioRef = doc(this.firestore, this.COLLECTION, gimnasio.id);
                await setDoc(gimnasioRef, dataToSave, { merge: true });
            } else {
                const col = collection(this.firestore, this.COLLECTION);
                await addDoc(col, dataToSave);
            }
        });
    }

    /**
     * 🗑️ Elimina un gimnasio por ID
     */
    async delete(id: string): Promise<void> {
        return this.runInZone(async () => {
            const gimnasioRef = doc(this.firestore, this.COLLECTION, id);
            await deleteDoc(gimnasioRef);
        });
    }

    /**
     * 🔍 Obtiene un gimnasio específico por ID
     */
    getGimnasioById(id: string): Signal<Gimnasio | null> {
        return computed(() =>
            this._gimnasios().find(gimnasio => gimnasio.id === id) || null
        );
    }

    /**
     * 🔍 Busca gimnasios activos
     */
    getGimnasiosActivos(): Signal<Gimnasio[]> {
        return computed(() =>
            this._gimnasios().filter(gimnasio => gimnasio.activo)
        );
    }

    /**
     * 🔍 Busca gimnasios por dirección
     */
    getGimnasiosByDireccion(direccion: string): Signal<Gimnasio[]> {
        return computed(() =>
            this._gimnasios().filter(gimnasio =>
                gimnasio.direccion.toLowerCase().includes(direccion.toLowerCase())
            )
        );
    }

    /**
     * 📊 Obtiene el conteo total de gimnasios
     */
    get gimnasioCount(): Signal<number> {
        return computed(() => this._gimnasios().length);
    }

    /**
     * 📊 Obtiene el conteo de gimnasios activos
     */
    get gimnasioActivoCount(): Signal<number> {
        return computed(() =>
            this._gimnasios().filter(gimnasio => gimnasio.activo).length
        );
    }

    private mapToFirestore(gimnasio: Gimnasio): any {
        return { ...gimnasio };
    }

    private mapFromFirestore(data: any): Gimnasio {
        return { ...data } as Gimnasio;
    }
}

import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
    Firestore,
    collection,
    addDoc,
    doc,
    updateDoc,
    deleteDoc,
    onSnapshot,
    setDoc,
    query,
    where,
    orderBy,
    Timestamp,
    QuerySnapshot,
    DocumentSnapshot,
} from 'firebase/firestore';
import { EntrenadoService } from './entrenado.service';
import { EntrenadorService, PlanLimitError } from './entrenador.service';
import { GimnasioService } from './gimnasio.service';
import { Invitacion, Notificacion, TipoNotificacion } from 'gym-library';
import { NotificacionService } from './notificacion.service';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

@Injectable({ providedIn: 'root' })
export class InvitacionService {
    private readonly firestore = inject(FIRESTORE);
    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'invitaciones';

    private readonly _invitaciones: WritableSignal<Invitacion[]> = signal<Invitacion[]>([]);
    private readonly invitacionSignals = new Map<string, WritableSignal<Invitacion | null>>();
    private isListenerInitialized = false;

    constructor() { }

    /**
     * Ejecuta el callback en el contexto correcto (zona o inyección)
     */
    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    /**
     * 🔄 Inicializa el listener de Firestore de forma segura
     */
    private initializeListener(gymId?: string): void {
        if (this.isListenerInitialized) return;

        try {
            const col = collection(this.firestore, this.COLLECTION);
            let q = query(col, orderBy('fechaCreacion', 'desc'));

            if (gymId) {
                q = query(col, where('gimnasioId', '==', gymId), orderBy('fechaCreacion', 'desc'));
            }

            onSnapshot(q, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
                    this._invitaciones.set(list);
                });
            });
            this.isListenerInitialized = true;
        } catch (e) {
            console.warn('Error inicializando listener de invitaciones:', e);
        }
    }

    /**
     * 📊 Signal readonly con la lista de invitaciones
     */
    get invitaciones(): Signal<Invitacion[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return this._invitaciones.asReadonly();
    }

    getInvitacionesForGym(gymId: string): Signal<Invitacion[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener(gymId);
        }
        return this._invitaciones.asReadonly();
    }

    /**
     * 📊 Obtiene una invitación específica por ID
     */
    getInvitacion(id: string): Signal<Invitacion | null> {
        if (!this.invitacionSignals.has(id)) {
            const invitacionSignal = signal<Invitacion | null>(null);
            this.invitacionSignals.set(id, invitacionSignal);

            const invitacionRef = doc(this.firestore, this.COLLECTION, id);
            onSnapshot(invitacionRef, (docSnap: DocumentSnapshot) => {
                this.runInZone(() => {
                    if (docSnap.exists()) {
                        invitacionSignal.set(this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
                    } else {
                        invitacionSignal.set(null);
                    }
                });
            });
        }
        return this.invitacionSignals.get(id)!.asReadonly();
    }

    /**
     * 💾 Guarda o actualiza una invitación
     */
    async save(invitacion: Invitacion): Promise<void> {
        return this.runInZone(async () => {
            const dataToSave = this.mapToFirestore(invitacion);
            if (invitacion.id) {
                const invitacionRef = doc(this.firestore, this.COLLECTION, invitacion.id);
                await setDoc(invitacionRef, dataToSave, { merge: true });
            } else {
                const col = collection(this.firestore, this.COLLECTION);
                await addDoc(col, dataToSave);
            }
        });
    }

    /**
     * 🗑️ Elimina una invitación por ID
     */
    async delete(id: string): Promise<void> {
        return this.runInZone(async () => {
            const invitacionRef = doc(this.firestore, this.COLLECTION, id);
            await deleteDoc(invitacionRef);
        });
    }

    /**
     * 🔄 Actualiza el estado de una invitación
     */
    async updateEstado(id: string, estado: 'pendiente' | 'aceptada' | 'rechazada'): Promise<void> {
        return this.runInZone(async () => {
            const invitacionRef = doc(this.firestore, this.COLLECTION, id);
            await updateDoc(invitacionRef, {
                estado,
                fechaRespuesta: estado !== 'pendiente' ? Timestamp.now() : null
            });
        });
    }

    /**
     * 📨 Crear invitación de entrenador a entrenado
     */
    async crearInvitacion(
        entrenadorId: string,
        entrenadoId: string,
        entrenadorNombre: string,
        entrenadoNombre: string,
        emailEntrenado: string,
        mensajePersonalizado?: string,
        tipo: 'gimnasio_a_entrenador' | 'entrenador_a_entrenado' = 'entrenador_a_entrenado'
    ): Promise<void> {
        const invitacion: Invitacion = {
            id: `inv-${entrenadorId}-${entrenadoId}-${Date.now()}`,
            entrenadorId,
            entrenadoId,
            entrenadorNombre,
            entrenadoNombre,
            emailEntrenado,
            remitenteId: entrenadorId,
            destinatarioId: entrenadoId,
            remitenteNombre: entrenadorNombre,
            destinatarioNombre: entrenadoNombre,
            emailDestinatario: emailEntrenado,
            tipo,
            estado: 'pendiente',
            mensajePersonalizado,
            fechaCreacion: new Date(),
            activa: true
        };

        // 1) Guardar invitación
        await this.save(invitacion);

        // 2) Crear notificación ligada a la invitación para el entrenado
        try {
            const notificacionService = this.injector.get(NotificacionService);
            const notificacion: Notificacion = {
                id: `notif-${invitacion.id}`,
                usuarioId: invitacion.entrenadoId || '', // La ve el entrenado
                tipo: TipoNotificacion.INVITACION_PENDIENTE,
                titulo: tipo === 'gimnasio_a_entrenador' 
                    ? `Invitación de ${entrenadorNombre} (Gimnasio)` 
                    : `Invitación de ${entrenadorNombre}`,
                mensaje: mensajePersonalizado || (tipo === 'gimnasio_a_entrenador'
                    ? `${entrenadorNombre} te ha invitado a unirte a su gimnasio`
                    : `${entrenadorNombre} te ha invitado a vincularse como tu entrenador`),
                leida: false,
                datos: {
                    invitacionId: invitacion.id,
                    entrenadorId,
                    entrenadorNombre,
                    emailInvitado: emailEntrenado,
                    estadoInvitacion: 'pendiente'
                },
                fechaCreacion: new Date()
            };

            await notificacionService.save(notificacion);
        } catch (e) {
            // No bloquear el flujo si falla la notificación, pero dejar rastro
            console.warn('No se pudo crear la notificación de invitación:', e);
        }
    }

    /**
     * ✅ Aceptar invitación y vincular entrenado <-> entrenador
     */
    async aceptarInvitacion(invitacionId: string): Promise<void> {
        try {
            // Intentar obtener de la lista general primero
            let invitacion: Invitacion | null = this._invitaciones().find(inv => inv.id === invitacionId) || null;

            // Si no está en la lista general, usar el signal específico
            if (!invitacion) {
                const invitacionSignal = this.getInvitacion(invitacionId);
                invitacion = invitacionSignal();

                // Si aún no está cargado, esperar un poco
                if (!invitacion) {
                    await new Promise(resolve => setTimeout(resolve, 200));
                    invitacion = invitacionSignal();
                }
            }

            if (!invitacion) {
                throw new Error(`Invitación ${invitacionId} no encontrada`);
            }

            const entrenadoId = invitacion.entrenadoId || '';
            const entrenadorId = invitacion.entrenadorId || '';
            const tipo = invitacion.tipo || 'entrenador_a_entrenado';

            // 1) Marcar invitación como aceptada
            await this.updateEstado(invitacionId, 'aceptada');

            if (tipo === 'gimnasio_a_entrenador') {
                const gimnasioId = invitacion.remitenteId || entrenadorId;
                const entrenadorIdAsociado = invitacion.destinatarioId || entrenadoId;

                // Actualizar perfil Entrenador: agregar gimnasioId
                const entrenadorService = this.injector.get(EntrenadorService);
                const entrenador = entrenadorService.getEntrenadorById(entrenadorIdAsociado)();
                if (entrenador) {
                    await entrenadorService.update(entrenadorIdAsociado, { gimnasioId });
                }

                // Actualizar perfil Gimnasio: agregar entrenador a entrenadoresIds
                const gimnasioService = this.injector.get(GimnasioService);
                const gimnasio = gimnasioService.getGimnasioById(gimnasioId)();
                if (gimnasio) {
                    const entrenadoresIds = [...(gimnasio.entrenadoresIds || [])];
                    if (!entrenadoresIds.includes(entrenadorIdAsociado)) {
                        entrenadoresIds.push(entrenadorIdAsociado);
                        await gimnasioService.save({ ...gimnasio, entrenadoresIds });
                    }
                }
            } else {
                // 2) Actualizar entrenado: agregar entrenadorId a entrenadoresId
                const entrenadoService = this.injector.get(EntrenadoService);
                const entrenadoSignal = entrenadoService.getEntrenadoById(entrenadoId)();
                const entrenado = entrenadoSignal || entrenadoService.entrenados().find((e: any) => e.id === entrenadoId) || null;
                if (entrenado) {
                    const entrenadoresId = [...(entrenado.entrenadoresId || [])];
                    if (!entrenadoresId.includes(entrenadorId)) {
                        entrenadoresId.push(entrenadorId);
                        const entrenadoActualizado = { ...entrenado, entrenadoresId } as any;
                        await entrenadoService.save(entrenadoActualizado);
                    }
                }

                // 3) Actualizar entrenador: agregar entrenadoId a entrenadosAsignadosIds
                const entrenadorService = this.injector.get(EntrenadorService);
                const entrenador = entrenadorService.getEntrenadorById(entrenadorId)();
                if (entrenador) {
                    const entrenadosAsignadosIds = [...(entrenador.entrenadosAsignadosIds || [])];
                    if (!entrenadosAsignadosIds.includes(entrenadoId)) {
                        // Check limit before adding
                        const limits = entrenadorService.getLimits(entrenadorId);
                        if (entrenadosAsignadosIds.length >= limits.maxClients) {
                            throw new PlanLimitError('Has alcanzado el límite de clientes para tu plan. Actualiza para conectar más.');
                        }
                        entrenadosAsignadosIds.push(entrenadoId);
                        await entrenadorService.update(entrenadorId, { entrenadosAsignadosIds });
                    }
                }
            }

            // 4) Actualizar la notificación asociada a la invitación
            try {
                const notificacionService = this.injector.get(NotificacionService);
                await notificacionService.save({
                    id: `notif-${invitacionId}`,
                    usuarioId: entrenadoId,
                    tipo: TipoNotificacion.INVITACION_ACEPTADA,
                    titulo: 'Invitación aceptada',
                    mensaje: 'Has aceptado la invitación del entrenador',
                    leida: true, // Marcar como leída porque el usuario ejecutó la acción
                    fechaLeida: new Date(),
                    datos: {
                        invitacionId: invitacionId,
                        entrenadorId,
                        estadoInvitacion: 'aceptada',
                        fechaRespuesta: new Date()
                    },
                    fechaCreacion: new Date()
                } as Notificacion);

                // 5) Crear notificación para el entrenador informando aceptación
                await notificacionService.save({
                    id: `notif-${invitacionId}-entrenador`,
                    usuarioId: entrenadorId,
                    tipo: TipoNotificacion.INVITACION_ACEPTADA,
                    titulo: 'Tu invitación fue aceptada',
                    mensaje: `${invitacion.entrenadoNombre} aceptó tu invitación`,
                    leida: false,
                    datos: {
                        invitacionId: invitacionId,
                        entrenadorId,
                        remitenteId: entrenadoId,
                        remitenteNombre: invitacion.entrenadoNombre,
                        estadoInvitacion: 'aceptada',
                        fechaRespuesta: new Date()
                    },
                    fechaCreacion: new Date()
                } as Notificacion);
            } catch (e) {
                console.warn('No se pudo actualizar la notificación de invitación (aceptada):', e);
            }
        } catch (error) {
            console.error('Error al aceptar invitación:', error);
            throw error;
        }
    }

    /**
     * ❌ Rechazar invitación
     */
    async rechazarInvitacion(invitacionId: string): Promise<void> {
        try {
            await this.updateEstado(invitacionId, 'rechazada');

            // Actualizar notificación asociada a la invitación
            try {
                // Intentar obtener la invitación para conocer ids
                let invitacion: Invitacion | null = this._invitaciones().find(inv => inv.id === invitacionId) || null;
                if (!invitacion) {
                    const invSignal = this.getInvitacion(invitacionId);
                    invitacion = invSignal();
                }
                if (!invitacion) {
                    // Si no pudimos determinar los datos, no bloqueamos
                    return;
                }

                const notificacionService = this.injector.get(NotificacionService);
                await notificacionService.save({
                    id: `notif-${invitacionId}`,
                    usuarioId: invitacion.entrenadoId || '',
                    tipo: TipoNotificacion.INVITACION_RECHAZADA,
                    titulo: 'Invitación rechazada',
                    mensaje: 'Has rechazado la invitación del entrenador',
                    leida: true, // Marcar como leída porque el usuario ejecutó la acción
                    fechaLeida: new Date(),
                    datos: {
                        invitacionId: invitacionId,
                        entrenadorId: invitacion.entrenadorId,
                        estadoInvitacion: 'rechazada',
                        fechaRespuesta: new Date()
                    },
                    fechaCreacion: new Date()
                } as Notificacion);

                // Crear notificación para el entrenador informando rechazo
                await notificacionService.save({
                    id: `notif-${invitacionId}-entrenador`,
                    usuarioId: invitacion.entrenadorId || '',
                    tipo: TipoNotificacion.INVITACION_RECHAZADA,
                    titulo: 'Tu invitación fue rechazada',
                    mensaje: `${invitacion.entrenadoNombre} rechazó tu invitación`,
                    leida: false,
                    datos: {
                        invitacionId: invitacionId,
                        entrenadorId: invitacion.entrenadorId,
                        remitenteId: invitacion.entrenadoId,
                        remitenteNombre: invitacion.entrenadoNombre,
                        estadoInvitacion: 'rechazada',
                        fechaRespuesta: new Date()
                    },
                    fechaCreacion: new Date()
                } as Notificacion);
            } catch (e) {
                console.warn('No se pudo actualizar la notificación de invitación (rechazada):', e);
            }
        } catch (error) {
            console.error('Error al rechazar invitación:', error);
            throw error;
        }
    }

    /**
     * 📋 Obtener invitaciones por entrenador
     */
    getInvitacionesPorEntrenador(entrenadorId: string): Signal<Invitacion[]> {
        return computed(() =>
            this.invitaciones().filter(inv =>
                inv.entrenadorId === entrenadorId
            )
        );
    }

    /**
     * 📋 Obtener invitaciones por entrenado
     */
    getInvitacionesPorEntrenado(entrenadoId: string): Signal<Invitacion[]> {
        return computed(() =>
            this.invitaciones().filter(inv =>
                inv.entrenadoId === entrenadoId
            )
        );
    }

    /**
     * 📋 Obtener invitaciones pendientes por entrenador
     */
    getInvitacionesPendientesPorEntrenador(entrenadorId: string): Signal<Invitacion[]> {
        return computed(() =>
            this.invitaciones().filter(inv =>
                inv.entrenadorId === entrenadorId &&
                inv.estado === 'pendiente' &&
                inv.activa
            )
        );
    }

    /**
     * 📋 Obtener invitaciones pendientes por entrenado
     */
    getInvitacionesPendientesPorEntrenado(entrenadoId: string): Signal<Invitacion[]> {
        return computed(() =>
            this.invitaciones().filter(inv =>
                inv.entrenadoId === entrenadoId &&
                inv.estado === 'pendiente' &&
                inv.activa
            )
        );
    }

    private mapFromFirestore(data: any): Invitacion {
        return {
            ...data,
            id: data.id,
            fechaCreacion: data.fechaCreacion instanceof Timestamp ? data.fechaCreacion.toDate() : (data.fechaCreacion ? new Date(data.fechaCreacion) : new Date()),
            fechaRespuesta: data.fechaRespuesta instanceof Timestamp ? data.fechaRespuesta.toDate() : (data.fechaRespuesta ? new Date(data.fechaRespuesta) : undefined)
        } as Invitacion;
    }

    private mapToFirestore(invitacion: Invitacion): any {
        return {
            ...invitacion,
            fechaCreacion: invitacion.fechaCreacion instanceof Date ? Timestamp.fromDate(invitacion.fechaCreacion) : (invitacion.fechaCreacion || Timestamp.now()),
            fechaRespuesta: invitacion.fechaRespuesta instanceof Date ? Timestamp.fromDate(invitacion.fechaRespuesta) : (invitacion.fechaRespuesta || null)
        };
    }
}

import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
    Firestore,
    collection,
    addDoc,
    doc,
    deleteDoc,
    setDoc,
    onSnapshot,
    query,
    where,
    Timestamp,
    QuerySnapshot,
    DocumentSnapshot,
    updateDoc,
    getDocs
} from 'firebase/firestore';
import { MatchInteraction, Entrenado, Rol, TipoMensaje, TipoNotificacion } from 'gym-library';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';
import { EntrenadoService } from './entrenado.service';
import { MensajeService } from './mensaje.service';
import { NotificacionService } from './notificacion.service';
import { UserService } from './user.service';
import { DesafioService } from './desafio.service';
import { TarjetaDescubrir } from '../types/descubrir.types';

@Injectable({ providedIn: 'root' })
export class MatchService {
    private readonly firestore = inject(FIRESTORE);
    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'matches';

    private readonly entrenadoService = inject(EntrenadoService);
    private readonly mensajeService = inject(MensajeService);
    private readonly notificacionService = inject(NotificacionService);
    private readonly userService = inject(UserService);
    private readonly desafioService = inject(DesafioService);

    private readonly _interactions: WritableSignal<MatchInteraction[]> = signal<MatchInteraction[]>([]);
    private isListenerInitialized = false;

    constructor() { }

    /**
     * Retorna una señal reactiva con todas las interacciones de match que involucran al usuario.
     * Si se pasa gymId, el listener se inicializa con filtro adicional por gimnasio (para scoping).
     */
    getInteractions(userId: string, gymId?: string): Signal<MatchInteraction[]> {
        this.initializeListener(userId, gymId);
        return this._interactions.asReadonly();
    }

    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    private initializeListener(userId: string, gymId?: string): void {
        if (this.isListenerInitialized) return;

        try {
            const col = collection(this.firestore, this.COLLECTION);

            // Construir queries con filtro por gimnasio si se provee (para scoping en entrenados)
            let qOrigen = query(col, where('usuarioOrigenId', '==', userId));
            let qDestino = query(col, where('usuarioDestinoId', '==', userId));

            if (gymId) {
                qOrigen = query(col, where('usuarioOrigenId', '==', userId), where('gimnasioId', '==', gymId));
                qDestino = query(col, where('usuarioDestinoId', '==', userId), where('gimnasioId', '==', gymId));
            }

            // Escuchar interacciones donde el usuario es origen O destino
            onSnapshot(qOrigen, (snap) => {
                this.mergeInteractions(snap, userId);
            });

            onSnapshot(qDestino, (snap) => {
                this.mergeInteractions(snap, userId);
            });

            this.isListenerInitialized = true;
        } catch (e) {
            console.warn('Error inicializando listener de matches:', e);
        }
    }

    private mergeInteractions(snap: QuerySnapshot, userId: string) {
        this.runInZone(() => {
            const current = this._interactions();
            const newOnes = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
            const merged = new Map<string, MatchInteraction>();
            [...current, ...newOnes].forEach(i => merged.set(i.id, i));
            this._interactions.set(Array.from(merged.values()));
        });
    }

    /**
     * Registra el interés de un usuario sobre otro o sobre un desafío.
     * Si el otro usuario ya había registrado interés previamente, se genera un MATCH MUTUO.
     */
    async registrarInteres(
        usuarioOrigenId: string,
        usuarioDestinoId: string,
        tipo: 'horario' | 'afinidad' | 'general',
        esInteres: boolean = true,
        referenciaId?: string
    ): Promise<boolean> {
        this.initializeListener(usuarioOrigenId);

        return this.runInZone(async () => {
            const matchesCol = collection(this.firestore, this.COLLECTION);

            // Obtener gimnasioId del usuario origen para denormalizarlo en el match
            const originUserProfile = this.userService.getUserByUid(usuarioOrigenId)();
            const gimnasioId = originUserProfile?.gimnasioId;

            // 1. Buscar si existe interés inverso previo (one-time read, sin listener)
            const qInverse = query(
                matchesCol,
                where('usuarioOrigenId', '==', usuarioDestinoId),
                where('usuarioDestinoId', '==', usuarioOrigenId),
                where('tipo', '==', tipo)
            );

            const inverseSnap = await getDocs(qInverse);
            let inverseMatchDoc: any = null;
            if (!inverseSnap.empty) {
                const docData = inverseSnap.docs[0];
                inverseMatchDoc = { ...docData.data(), id: docData.id };
            }

            if (esInteres && inverseMatchDoc && inverseMatchDoc.interesOrigen === true) {
                // ¡HAY MATCH MUTUO!
                // A. Actualizar la interacción inversa
                const inverseRef = doc(this.firestore, this.COLLECTION, inverseMatchDoc.id);
                await updateDoc(inverseRef, {
                    interesDestino: true,
                    mutuo: true,
                    fechaMatch: Timestamp.now(),
                    ...(gimnasioId && { gimnasioId })   // asegurar denormalización
                });

                // B. Crear la interacción de origen ya marcada como mutua
                const interactionId = `match-${usuarioOrigenId}-${usuarioDestinoId}-${Date.now()}`;
                const newInteraction: MatchInteraction = {
                    id: interactionId,
                    tipo,
                    usuarioOrigenId,
                    usuarioDestinoId,
                    referenciaId,
                    interesOrigen: true,
                    interesDestino: true,
                    mutuo: true,
                    fechaCreacion: new Date(),
                    fechaMatch: new Date(),
                    gimnasioId
                };
                await setDoc(doc(this.firestore, this.COLLECTION, interactionId), this.mapToFirestore(newInteraction));

                // C. Crear un mensaje de bienvenida automático en el chat para habilitar la conversación
                const msgId = `msg-welcome-${usuarioOrigenId}-${usuarioDestinoId}-${Date.now()}`;
                const originUser = this.userService.getUserByUid(usuarioOrigenId)();
                const originName = originUser?.nombre || 'Un atleta';
                
                let contenido = `¡Conexión establecida! ¡Empecemos a coordinar para entrenar en equipo!`;
                if (tipo === 'horario') {
                    contenido = `¡Conexión establecida! Nos interesa entrenar en un horario similar. ¡Empecemos a coordinar!`;
                } else if (tipo === 'afinidad') {
                    contenido = `¡Hay equipo! Encontramos a tu partner ideal para esta semana. ¡Vamos a entrenar!`;
                }

                await this.mensajeService.save({
                    id: msgId,
                    remitenteId: usuarioOrigenId,
                    remitenteTipo: Rol.ENTRENADO,
                    destinatarioId: usuarioDestinoId,
                    destinatarioTipo: Rol.ENTRENADO,
                    contenido: contenido,
                    tipo: TipoMensaje.TEXTO,
                    leido: false,
                    entregado: true,
                    fechaEnvio: new Date()
                });

                // D. Notificar a AMBOS usuarios con contexto claro del "por qué" del match
                const targetUserForNotif = this.userService.getUserByUid(usuarioDestinoId)();
                const targetName = targetUserForNotif?.nombre || 'Un atleta';

                const matchReason = this.buildMatchReasonMessage(tipo, originName, targetName);

                // Notificación para el que inició el último "chocar los 5"
                await this.notificacionService.save({
                    id: `notif-match-${interactionId}-for-origin`,
                    usuarioId: usuarioOrigenId,
                    tipo: TipoNotificacion.NUEVO_MATCH,
                    titulo: '¡Chocaste los 5! Nuevo match',
                    mensaje: matchReason.forOrigin,
                    leida: false,
                    fechaCreacion: new Date(),
                    datos: {
                        matchId: interactionId,
                        tipoMatch: tipo,
                        partnerId: usuarioDestinoId,
                        partnerName: targetName
                    }
                });

                // Notificación para el otro usuario
                await this.notificacionService.save({
                    id: `notif-match-${interactionId}-for-target`,
                    usuarioId: usuarioDestinoId,
                    tipo: TipoNotificacion.NUEVO_MATCH,
                    titulo: '¡Chocaste los 5! Nuevo match',
                    mensaje: matchReason.forTarget,
                    leida: false,
                    fechaCreacion: new Date(),
                    datos: {
                        matchId: interactionId,
                        tipoMatch: tipo,
                        partnerId: usuarioOrigenId,
                        partnerName: originName
                    }
                });

                return true; // Match concretado
            } else {
                // No hay interés inverso previo, registrar interés inicial
                const interactionId = `match-${usuarioOrigenId}-${usuarioDestinoId}-${Date.now()}`;
                const newInteraction: MatchInteraction = {
                    id: interactionId,
                    tipo,
                    usuarioOrigenId,
                    usuarioDestinoId,
                    referenciaId,
                    interesOrigen: esInteres,
                    mutuo: false,
                    fechaCreacion: new Date(),
                    gimnasioId
                };
                await setDoc(doc(this.firestore, this.COLLECTION, interactionId), this.mapToFirestore(newInteraction));
                return false; // Esperando interés mutuo
            }
        });
    }

    /**
     * Obtener sugerencias para la Tarjeta de Utilidad (Coincidencia horaria)
     */
    getSugerenciasHorario(currentUser: Entrenado): Signal<Entrenado[]> {
        return computed(() => {
            const all = this.entrenadoService.entrenados();
            if (!currentUser || !currentUser.franjaHoraria) return [];

            const currentUserProfile = this.userService.getUserByUid(currentUser.id)();
            const currentUserGymId = currentUserProfile?.gimnasioId;

            return all.filter(e => {
                if (e.id === currentUser.id) return false;
                if (e.visibleDescubrir === false) return false;

                const targetUserProfile = this.userService.getUserByUid(e.id)();
                if (targetUserProfile?.gimnasioId !== currentUserGymId) return false;

                if (!e.franjaHoraria) return false;

                // Comprobar solapamiento de rango de horas
                const currentStart = this.parseTimeToMinutes(currentUser.franjaHoraria!.inicio);
                const currentEnd = this.parseTimeToMinutes(currentUser.franjaHoraria!.fin);
                const targetStart = this.parseTimeToMinutes(e.franjaHoraria.inicio);
                const targetEnd = this.parseTimeToMinutes(e.franjaHoraria.fin);

                return (currentStart < targetEnd && currentEnd > targetStart);
            });
        });
    }

    /**
     * Obtener sugerencias para la Tarjeta Social Pura (Afinidad por estilo de vida / Objetivo)
     */
    getSugerenciasAfinidad(currentUser: Entrenado): Signal<Entrenado[]> {
        return computed(() => {
            const all = this.entrenadoService.entrenados();
            if (!currentUser || !currentUser.objetivo) return [];

            const currentUserProfile = this.userService.getUserByUid(currentUser.id)();
            const currentUserGymId = currentUserProfile?.gimnasioId;

            return all.filter(e => {
                if (e.id === currentUser.id) return false;
                if (e.visibleDescubrir === false) return false;

                const targetUserProfile = this.userService.getUserByUid(e.id)();
                if (targetUserProfile?.gimnasioId !== currentUserGymId) return false;

                // Comprobar si comparten el mismo objetivo de entrenamiento
                return e.objetivo === currentUser.objetivo;
            });
        });
    }

    private parseTimeToMinutes(timeStr: string): number {
        if (!timeStr) return 0;
        const parts = timeStr.split(':');
        if (parts.length < 2) return 0;
        return parseInt(parts[0]) * 60 + parseInt(parts[1]);
    }

    /**
     * Construye el mazo completo de tarjetas para el tab Descubrir:
     * sugerencias por horario, por afinidad y desafíos activos del gimnasio,
     * filtrando las tarjetas con las que el usuario ya interactuó.
     *
     * Centralizado aquí para mantener toda la lógica de matching en el servicio.
     */
    getTarjetasDescubrir(entrenado: Entrenado, gymId: string): Signal<TarjetaDescubrir[]> {
        return computed(() => {
            const all = this.entrenadoService.entrenados();
            const interactions = this.getInteractions(entrenado.id, gymId)();
            const _ = this.userService.users(); // dependencia reactiva: re-computa cuando llegan los usuarios

            const interactedIds = new Set(
                interactions.map(i => i.referenciaId || i.usuarioDestinoId)
            );

            const currentUserProfile = this.userService.getUserByUid(entrenado.id)();
            const currentUserGymId = currentUserProfile?.gimnasioId;

            const list: TarjetaDescubrir[] = [];

            for (const u of all) {
                if (u.id === entrenado.id || u.visibleDescubrir === false) continue;
                if (interactedIds.has(u.id)) continue;

                const targetProfile = this.userService.getUserByUid(u.id)();
                if (targetProfile?.gimnasioId !== currentUserGymId) continue;

                let tipoMatch: 'horario' | 'afinidad' | 'general' = 'general';

                // 1. Sugerencias por coincidencia horaria
                if (entrenado.franjaHoraria && u.franjaHoraria) {
                    const currentStart = this.parseTimeToMinutes(entrenado.franjaHoraria.inicio);
                    const currentEnd   = this.parseTimeToMinutes(entrenado.franjaHoraria.fin);
                    const targetStart = this.parseTimeToMinutes(u.franjaHoraria.inicio);
                    const targetEnd   = this.parseTimeToMinutes(u.franjaHoraria.fin);

                    if (currentStart < targetEnd && currentEnd > targetStart) {
                        tipoMatch = 'horario';
                    }
                }

                // 2. Sugerencias por afinidad de objetivo (si no hay match de horario)
                if (tipoMatch === 'general' && entrenado.objetivo && u.objetivo === entrenado.objetivo) {
                    tipoMatch = 'afinidad';
                }

                list.push({
                    id: `${tipoMatch}-${u.id}`,
                    tipo: tipoMatch,
                    data: u,
                    photoURL: targetProfile?.photoURL ?? null
                });
            }

            return list;
        });
    }

    /**
     * Construye el mensaje contextual que se muestra en el popup de match mutuo.
     * Centralizado en el servicio para mantener la lógica de negocio fuera de los componentes.
     */
    buildMatchPopupMessage(
        tipo: 'horario' | 'afinidad' | 'general',
        active: TarjetaDescubrir,
        partnerName: string
    ): string {
        if (tipo === 'horario') {
            return `¡Hay equipo para el turno tarde! A ambos les queda bien entrenar en el rango de ${active.data.franjaHoraria?.inicio} a ${active.data.franjaHoraria?.fin}.`;
        }
        if (tipo === 'afinidad') {
            return `¡Hay equipo! Encontramos a tu partner ideal para esta semana. ¿Vamos a entrenar?`;
        }
        return '';
    }

    /**
     * Genera mensajes contextuales para notificaciones de match mutuo.
     * Explica claramente "el por qué" del match a ambos usuarios.
     */
    private buildMatchReasonMessage(
        tipo: 'horario' | 'afinidad' | 'general',
        originName: string,
        targetName: string
    ): { forOrigin: string; forTarget: string } {
        if (tipo === 'afinidad') {
            return {
                forOrigin: `¡Match con ${targetName}! Comparten el mismo objetivo. ¡A entrenar juntos!`,
                forTarget: `¡Match con ${originName}! Comparten el mismo objetivo. ¡A entrenar juntos!`
            };
        }
        if (tipo === 'horario') {
            return {
                forOrigin: `¡Match con ${targetName}! Sus horarios de entrenamiento coinciden. ¡Buen momento para entrenar en equipo!`,
                forTarget: `¡Match con ${originName}! Sus horarios de entrenamiento coinciden. ¡Buen momento para entrenar en equipo!`
            };
        }
        return {
            forOrigin: `¡Match con ${targetName}! Es un buen momento para entrenar en equipo.`,
            forTarget: `¡Match con ${originName}! Es un buen momento para entrenar en equipo.`
        };
    }

    private mapFromFirestore(data: any): MatchInteraction {
        return {
            id: data.id,
            tipo: data.tipo,
            usuarioOrigenId: data.usuarioOrigenId,
            usuarioDestinoId: data.usuarioDestinoId,
            referenciaId: data.referenciaId || null,
            interesOrigen: data.interesOrigen ?? false,
            interesDestino: data.interesDestino ?? false,
            mutuo: data.mutuo ?? false,
            fechaCreacion: data.fechaCreacion instanceof Timestamp ? data.fechaCreacion.toDate() : (data.fechaCreacion ? new Date(data.fechaCreacion) : new Date()),
            fechaMatch: data.fechaMatch instanceof Timestamp ? data.fechaMatch.toDate() : (data.fechaMatch ? new Date(data.fechaMatch) : undefined),
            gimnasioId: data.gimnasioId || undefined
        };
    }

    private mapToFirestore(interaction: MatchInteraction): any {
        const data: any = {
            tipo: interaction.tipo,
            usuarioOrigenId: interaction.usuarioOrigenId,
            usuarioDestinoId: interaction.usuarioDestinoId,
            interesOrigen: interaction.interesOrigen,
            mutuo: interaction.mutuo ?? false,
            fechaCreacion: interaction.fechaCreacion instanceof Date ? Timestamp.fromDate(interaction.fechaCreacion) : interaction.fechaCreacion
        };

        if (interaction.referenciaId) data.referenciaId = interaction.referenciaId;
        if (interaction.interesDestino !== undefined) data.interesDestino = interaction.interesDestino;
        if (interaction.fechaMatch) {
            data.fechaMatch = interaction.fechaMatch instanceof Date ? Timestamp.fromDate(interaction.fechaMatch) : interaction.fechaMatch;
        }
        if (interaction.gimnasioId) {
            data.gimnasioId = interaction.gimnasioId;
        }

        return data;
    }
}

import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
    Firestore,
    collection,
    doc,
    addDoc,
    updateDoc,
    deleteDoc,
    onSnapshot,
    setDoc,
    query,
    orderBy,
    Timestamp,
    QuerySnapshot,
    DocumentSnapshot,
    where,
    limit
} from 'firebase/firestore';
import { Mensaje } from 'gym-library';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

@Injectable({ providedIn: 'root' })
export class MensajeService {
    private readonly firestore = inject(FIRESTORE);
    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'mensajes';

    private readonly _mensajes: WritableSignal<Mensaje[]> = signal<Mensaje[]>([]);
    private readonly mensajeSignals = new Map<string, WritableSignal<Mensaje | null>>();
    private isListenerInitialized = false;

    constructor() { }

    /**
     * Ejecuta el callback en el contexto correcto (zona o inyección)
     */
    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    /**
     * 🔄 Inicializa el listener de Firestore de forma segura
     */
    private initializeListener(): void {
        if (this.isListenerInitialized) return;

        try {
            const col = collection(this.firestore, this.COLLECTION);
            const q = query(col, orderBy('fechaEnvio', 'desc'));
            onSnapshot(q, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
                    this._mensajes.set(list);
                });
            });
            this.isListenerInitialized = true;
        } catch (e) {
            console.warn('Error inicializando listener de mensajes:', e);
        }
    }

    /**
     * 📊 Signal readonly con la lista de mensajes
     */
    get mensajes(): Signal<Mensaje[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return this._mensajes.asReadonly();
    }

    /**
     * 📊 Obtiene un mensaje específico por ID
     */
    getMensaje(id: string): Signal<Mensaje | null> {
        if (!this.mensajeSignals.has(id)) {
            const mensajeSignal = signal<Mensaje | null>(null);
            this.mensajeSignals.set(id, mensajeSignal);

            const mensajeRef = doc(this.firestore, this.COLLECTION, id);
            onSnapshot(mensajeRef, (docSnap: DocumentSnapshot) => {
                this.runInZone(() => {
                    if (docSnap.exists()) {
                        mensajeSignal.set(this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
                    } else {
                        mensajeSignal.set(null);
                    }
                });
            });
        }
        return this.mensajeSignals.get(id)!.asReadonly();
    }

    /**
     * 💾 Guarda o actualiza un mensaje
     */
    async save(mensaje: Mensaje): Promise<void> {
        return this.runInZone(async () => {
            const dataToSave = this.mapToFirestore(mensaje);
            if (mensaje.id) {
                const mensajeRef = doc(this.firestore, this.COLLECTION, mensaje.id);
                await setDoc(mensajeRef, dataToSave, { merge: true });
            } else {
                const col = collection(this.firestore, this.COLLECTION);
                await addDoc(col, dataToSave);
            }
        });
    }

    /**
     * 🗑️ Elimina un mensaje por ID
     */
    async delete(id: string): Promise<void> {
        return this.runInZone(async () => {
            const mensajeRef = doc(this.firestore, this.COLLECTION, id);
            await deleteDoc(mensajeRef);
        });
    }

    /**
     * ✅ Marca un mensaje como leído
     */
    async marcarComoLeido(id: string): Promise<void> {
        return this.runInZone(async () => {
            const mensajeRef = doc(this.firestore, this.COLLECTION, id);
            await updateDoc(mensajeRef, {
                leido: true,
                fechaLeido: Timestamp.now()
            });
        });
    }

    /**
     * 📩 Marca un mensaje como entregado
     */
    async marcarComoEntregado(id: string): Promise<void> {
        return this.runInZone(async () => {
            const mensajeRef = doc(this.firestore, this.COLLECTION, id);
            await updateDoc(mensajeRef, {
                entregado: true
            });
        });
    }

    /**
     * 🔍 Obtiene mensajes enviados por un usuario
     */
    getMensajesByRemitente(remitenteId: string): Signal<Mensaje[]> {
        return computed(() =>
            this.mensajes().filter(msg => msg.remitenteId === remitenteId)
        );
    }

    /**
     * 🔍 Obtiene mensajes recibidos por un usuario
     */
    getMensajesByDestinatario(destinatarioId: string): Signal<Mensaje[]> {
        return computed(() =>
            this.mensajes().filter(msg => msg.destinatarioId === destinatarioId)
        );
    }

    /**
     * 📊 Obtiene mensajes no leídos para un usuario
     */
    getMensajesNoLeidos(destinatarioId: string): Signal<Mensaje[]> {
        return computed(() =>
            this.mensajes().filter(msg =>
                msg.destinatarioId === destinatarioId && !msg.leido
            )
        );
    }

    /**
     * 📊 Contador de mensajes no leídos
     */
    getContadorNoLeidos(destinatarioId: string): Signal<number> {
        return computed(() =>
            this.mensajes().filter(msg =>
                msg.destinatarioId === destinatarioId && !msg.leido
            ).length
        );
    }

    /**
     * 📋 Obtiene mensajes por entrenador (enviados o recibidos)
     */
    getMensajesByEntrenador(entrenadorId: string): Signal<Mensaje[]> {
        return computed(() =>
            this.mensajes().filter(msg =>
                msg.remitenteId === entrenadorId || msg.destinatarioId === entrenadorId
            )
        );
    }

    private mapFromFirestore(data: any): Mensaje {
        return {
            ...data,
            id: data.id,
            fechaEnvio: data.fechaEnvio instanceof Timestamp ? data.fechaEnvio.toDate() : (data.fechaEnvio ? new Date(data.fechaEnvio) : new Date()),
            fechaLeido: data.fechaLeido instanceof Timestamp ? data.fechaLeido.toDate() : (data.fechaLeido ? new Date(data.fechaLeido) : undefined),
            fechaEditado: data.fechaEditado instanceof Timestamp ? data.fechaEditado.toDate() : (data.fechaEditado ? new Date(data.fechaEditado) : undefined)
        } as Mensaje;
    }

    private mapToFirestore(mensaje: Mensaje): any {
        return {
            ...mensaje,
            fechaEnvio: mensaje.fechaEnvio instanceof Date ? Timestamp.fromDate(mensaje.fechaEnvio) : (mensaje.fechaEnvio || Timestamp.now()),
            fechaLeido: mensaje.fechaLeido instanceof Date ? Timestamp.fromDate(mensaje.fechaLeido) : (mensaje.fechaLeido || null),
            fechaEditado: mensaje.fechaEditado instanceof Date ? Timestamp.fromDate(mensaje.fechaEditado) : (mensaje.fechaEditado || null)
        };
    }
}

