     */
    async solicitarPremium(user: User): Promise<string> {
        const solicitud: Omit<SolicitudPlan, 'id'> = {
            userId: user.uid,
            userName: user.nombre || 'Usuario',
            userEmail: user.email || '',
            planActual: user.plan || Plan.FREE,
            planSolicitado: Plan.PREMIUM,
