     */
    async getUltimaSolicitud(userId: string): Promise<SolicitudPlan | null> {
        const colRef = collection(this.firestore, this.COLLECTION);
        const q = query(
            colRef,
            where('userId', '==', userId),
            orderBy('fechaCreacion', 'desc'),
            limit(1)
        );

        const snapshot = await getDocs(q);
        if (snapshot.empty) return null;

        const data = snapshot.docs[0].data();
        return {
            ...data,
            id: snapshot.docs[0].id
        } as SolicitudPlan;
    }

    /**
     * Escucha cambios en las solicitudes del usuario
     */
    getSolicitudesUsuarioListener(userId: string, callback: (solicitudes: SolicitudPlan[]) => void) {
        const colRef = collection(this.firestore, this.COLLECTION);
        const q = query(
            colRef,
            where('userId', '==', userId),
            orderBy('fechaCreacion', 'desc')
        );

        return onSnapshot(q, {
            next: (snapshot) => {
                const solicitudes = snapshot.docs.map(doc => ({
                    ...doc.data(),
                    id: doc.id
                })) as SolicitudPlan[];
                callback(solicitudes);
            },
            error: (err) => {
                console.warn('⚠️ PlanService: Error en el listener de solicitudes:', err);
                callback([]);
            }
        });
    }
}

