    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'rutinas-asignadas';

    private readonly _rutinasAsignadas: WritableSignal<RutinaAsignada[]> = signal<RutinaAsignada[]>([]);
    private readonly rutinaAsignadaSignals = new Map<string, WritableSignal<RutinaAsignada | null>>();
    private isListenerInitialized = false;

    // Servicios auxiliares
    private readonly notificacionService: NotificacionService = inject(NotificacionService);
    private readonly rutinaService: RutinaService = inject(RutinaService);

    constructor() { }

    /**
     * Ejecuta el callback en el contexto correcto (zona o inyección)
     */
    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    /**
     * 🔄 Inicializa el listener de Firestore de forma segura.
     * Por defecto carga todo (usado por admin / vistas globales).
     * Para la experiencia de entrenado se recomienda usar los getters por usuario/gym
     * que filtran en cliente, o evolucionar hacia listeners gym-scoped.
     */
    private initializeListener(gymId?: string): void {
        if (this.isListenerInitialized) return;

        try {
            const col = collection(this.firestore, this.COLLECTION);
            let q = query(col); // full collection by default

            // TODO (medium): cuando la mayoría de documentos tengan gimnasioId,
            // podemos hacer where('gimnasioId', '==', gymId) para reducir payload.
            // Por ahora mantenemos full + filtro en memoria para compatibilidad legacy.
            if (gymId) {
                // Ejemplo futuro:
                // q = query(col, where('gimnasioId', '==', gymId));
            }

            onSnapshot(q, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
                    this._rutinasAsignadas.set(list);
                });
            });
            this.isListenerInitialized = true;
        } catch (e) {
            console.warn('Error inicializando listener de rutinas asignadas:', e);
        }
    }

    /**
     * 📡 Suscribe a cambios en una rutina asignada específica
     */
    subscribeToRutinaAsignada(id: string): Signal<RutinaAsignada | null> {
        if (!this.rutinaAsignadaSignals.has(id)) {
            const rutinaSignal = signal<RutinaAsignada | null>(null);
            this.rutinaAsignadaSignals.set(id, rutinaSignal);

            const rutinaAsignadaRef = doc(this.firestore, this.COLLECTION, id);
            onSnapshot(rutinaAsignadaRef, (docSnap: DocumentSnapshot) => {
                this.runInZone(() => {
                    if (docSnap.exists()) {
                        rutinaSignal.set(this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
                    } else {
                        rutinaSignal.set(null);
                    }
                });
            });
        }
        return this.rutinaAsignadaSignals.get(id)!.asReadonly();
    }

    /**
     * 🔍 Obtiene todas las rutinas asignadas
     */
    getRutinasAsignadas(): Signal<RutinaAsignada[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return this._rutinasAsignadas.asReadonly();
    }

    /**
     * 🔍 Obtiene rutinas asignadas por entrenado
     */
    getRutinasAsignadasByEntrenado(entrenadoId: string): Signal<RutinaAsignada[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return computed(() =>
            this._rutinasAsignadas().filter(ra => ra.entrenadoId === entrenadoId)
        );
    }

    /**
     * 🔍 Obtiene rutinas asignadas por entrenador
     */
    getRutinasAsignadasByEntrenador(entrenadorId: string): Signal<RutinaAsignada[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return computed(() =>
            this._rutinasAsignadas().filter(ra => ra.entrenadorId === entrenadorId)
        );
    }

    /**
     * 🔍 Obtiene rutinas asignadas por rutina
     */
    getRutinasAsignadasByRutina(rutinaId: string): Signal<RutinaAsignada[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return computed(() =>
            this._rutinasAsignadas().filter(ra => ra.rutinaId === rutinaId)
        );
    }

    /**
     * 🔍 Obtiene rutinas asignadas activas por entrenado
     */
    getRutinasAsignadasActivasByEntrenado(entrenadoId: string): Signal<RutinaAsignada[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return computed(() =>
            this._rutinasAsignadas().filter(ra =>
                ra.entrenadoId === entrenadoId && ra.activa
            )
        );
    }

    /**
     * 🕒 Organiza las rutinas por días de la semana (próximos 7 días)
     * (los objetos de rutina llevan propiedades extra como diaCorto, esHoy, esFuturo, encuentros)
     */
    organizarRutinasSemanales(rutinasAsignadas: Rutina[], asignaciones: RutinaAsignada[]): any[] {
        const hoy = new Date();
        const fechas = [];
        for (let i = 0; i < 7; i++) {
            const fecha = new Date(hoy);
            fecha.setDate(hoy.getDate() + i);
            fechas.push(fecha);
        }

        const rutinasOrganizadas: { [key: string]: { fecha: Date; rutinas: any[]; diaCorto: string; esHoy: boolean; esFuturo: boolean; } } = {};

        const diasSemanaSinTilde = ['domingo', 'lunes', 'martes', 'miercoles', 'jueves', 'viernes', 'sabado'];
        const diasSemanaCorto = ['Dom', 'Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb'];

        fechas.forEach(fecha => {
            const diaSemanaIndex = fecha.getDay();
            const diaSemanaNormalizado = diasSemanaSinTilde[diaSemanaIndex];
            const diaCorto = diasSemanaCorto[diaSemanaIndex];
            const fechaKey = fecha.toISOString().split('T')[0];

            if (!rutinasOrganizadas[fechaKey]) {
                const esHoyCheck = fecha.toDateString() === hoy.toDateString();
                rutinasOrganizadas[fechaKey] = {
                    fecha: new Date(fecha),
                    rutinas: [],
                    diaCorto,
                    esHoy: esHoyCheck,
                    esFuturo: !esHoyCheck && fecha.getTime() > hoy.getTime()
                };
            }

            const asignacionesDelDia = asignaciones.filter((asig: RutinaAsignada) => {
                if (!asig.diaSemana) return false;
                const asigDiaNormalizado = asig.diaSemana.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
                return asigDiaNormalizado === diaSemanaNormalizado;
            });

            asignacionesDelDia.forEach((asig: RutinaAsignada) => {
                const rutinaCompleta = rutinasAsignadas.find(r => r.id === asig.rutinaId);
                if (rutinaCompleta) {
                    rutinasOrganizadas[fechaKey].rutinas.push(rutinaCompleta);
                }
            });

            // Soporte para rutinas creadas por el propio usuario que guardan sus días directamente
            // en el documento Rutina (vía el modal de Creaciones). Esto hace que aparezcan
            // en la vista semanal aunque no tengan un documento RutinaAsignada explícito.
            rutinasAsignadas.forEach((rutina: any) => {
                const diasDirectos: string[] = rutina?.diasSemana || [];
                if (!diasDirectos.length) return;

                diasDirectos.forEach((diaStr: string) => {
                    const diaNorm = diaStr.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();
                    if (diaNorm === diaSemanaNormalizado) {
                        // Evitar duplicados si ya vino por asignación
                        const yaExiste = rutinasOrganizadas[fechaKey].rutinas.some((r: any) => r.id === rutina.id);
                        if (!yaExiste) {
                            rutinasOrganizadas[fechaKey].rutinas.push(rutina);
                        }
                    }
                });
            });
        });

        // Rutinas sin día asignado: mostrarlas hoy para que el usuario pueda ejecutarlas
        const idsEnSemana = new Set<string>();
        Object.values(rutinasOrganizadas).forEach(dia => {
            dia.rutinas.forEach((r: Rutina) => idsEnSemana.add(r.id));
        });

        const sinProgramar = rutinasAsignadas.filter(r => !idsEnSemana.has(r.id));
        if (sinProgramar.length > 0) {
            const hoyKey = fechas[0].toISOString().split('T')[0];
            const diaHoy = rutinasOrganizadas[hoyKey];
            if (diaHoy) {
                sinProgramar.forEach(rutina => {
                    if (!diaHoy.rutinas.some((r: Rutina) => r.id === rutina.id)) {
                        diaHoy.rutinas.push(rutina);
                    }
                });
            }
        }

        return Object.values(rutinasOrganizadas).sort((a, b) => a.fecha.getTime() - b.fecha.getTime());
    }

    /**
     * 🕒 Obtiene las próximas 3 rutinas para el dashboard de un entrenado
     * (con propiedades extra: esEjecutable, diaCorto, asignadoPor)
     */
    getProximasRutinasDashboard(userId: string, rutinasEntrenado: Rutina[]): Signal<DashboardRutina[]> {
        return computed(() => {
            const rutinas = this.rutinaService.rutinas();
            const asignaciones = this.getRutinasAsignadasByEntrenado(userId)();
            const rutinasDelEntrenado = rutinasEntrenado;

            if (!rutinas.length) return [];

            const hoy = new Date();
            const proximas: DashboardRutina[] = [];
            const idsAgregados = new Set<string>();
            const nombresAgregados = new Set<string>();

            const diasSemanaSinTilde = ['domingo', 'lunes', 'martes', 'miercoles', 'jueves', 'viernes', 'sabado'];
            const diaCortoArr = ['Dom', 'Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb'];
            const diasSemanaMapa: Record<string, string> = {
                'domingo': 'domingo', 'lunes': 'lunes', 'martes': 'martes',
                'miercoles': 'miercoles', 'jueves': 'jueves', 'viernes': 'viernes',
                'sabado': 'sabado', 'dom': 'domingo', 'lun': 'lunes', 'mar': 'martes',
                'mie': 'miercoles', 'jue': 'jueves', 'vie': 'viernes', 'sab': 'sabado'
            };

            for (let i = 0; i < 7 && proximas.length < 3; i++) {
                const fechaBucle = new Date(hoy);
                fechaBucle.setDate(hoy.getDate() + i);

                const diaSemanaIndex = fechaBucle.getDay();
                const diaSemanaNombre = diasSemanaSinTilde[diaSemanaIndex];
                const esHoy = i === 0;

                const asignacionesDelDia = asignaciones.filter(asig => {
                    if (!asig.diaSemana) return false;
                    const diaAsigNorm = asig.diaSemana.toLowerCase()
                        .normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();
                    return (diasSemanaMapa[diaAsigNorm] || diaAsigNorm) === diaSemanaNombre;
                });

                for (const asig of asignacionesDelDia) {
                    if (proximas.length >= 3) break;
                    const rId = asig.rutinaId;
                    if (!rId || idsAgregados.has(rId)) continue;

                    const rutinaOriginal = rutinas.find(r => r.id === rId);
                    if (rutinaOriginal) {
                        if (nombresAgregados.has(rutinaOriginal.nombre)) continue;
                        idsAgregados.add(rId);
                        nombresAgregados.add(rutinaOriginal.nombre);

                        proximas.push({
                            ...rutinaOriginal,
                            asignadoPor: 'Entrenador',
                            diaCorto: esHoy ? 'Hoy' : diaCortoArr[diaSemanaIndex],
                            esEjecutable: esHoy,
                            fecha: fechaBucle
                        } as DashboardRutina);
                    }
                }
            }

            if (proximas.length < 3 && rutinasDelEntrenado.length > 0) {
                for (const rutina of rutinasDelEntrenado) {
                    if (proximas.length >= 3) break;
                    if (!idsAgregados.has(rutina.id) && !nombresAgregados.has(rutina.nombre)) {
                        idsAgregados.add(rutina.id);
                        nombresAgregados.add(rutina.nombre);
                        proximas.push({
                            ...rutina,
                            asignadoPor: 'Entrenador',
                            diaCorto: '',
                            esEjecutable: false
                        } as DashboardRutina);
                    }
                }
            }

            return proximas;
        });
    }

    /**
     * 💾 Guarda una rutina asignada
     */
    async save(rutinaAsignada: RutinaAsignada): Promise<void> {
        return this.runInZone(async () => {
            const dataToSave = this.mapToFirestore(rutinaAsignada);
            if (rutinaAsignada.id) {
                const rutinaAsignadaRef = doc(this.firestore, this.COLLECTION, rutinaAsignada.id);
                await setDoc(rutinaAsignadaRef, dataToSave, { merge: true });
            } else {
                const col = collection(this.firestore, this.COLLECTION);
                const docRef = await addDoc(col, dataToSave);
                rutinaAsignada.id = docRef.id;
            }
        });
    }

    /**
     * 🗑️ Elimina una rutina asignada
     */
    async delete(id: string): Promise<void> {
        return this.runInZone(async () => {
            const rutinaAsignadaRef = doc(this.firestore, this.COLLECTION, id);
            await deleteDoc(rutinaAsignadaRef);
        });
    }

    /**
     * 🔄 Actualiza el estado de una rutina asignada
     */
    async toggleActiva(id: string): Promise<void> {
        const rutinas = this.getRutinasAsignadas()();
        const rutinaAsignada = rutinas.find(ra => ra.id === id);
        if (rutinaAsignada) {
            const updated = { ...rutinaAsignada, activa: !rutinaAsignada.activa };
            await this.save(updated);
        }
    }

    /**
     * Crea notificaciones de recordatorio para rutinas próximas de un entrenado en una ventana dada (por defecto 24h).
     */
    async checkAndNotifyRutinasProximas(entrenadoId: string, windowHours: number = 24): Promise<void> {
        const ahora = new Date();
        const ventanaMs = windowHours * 60 * 60 * 1000;
        const limite = new Date(ahora.getTime() + ventanaMs);

        const asignadas = this.getRutinasAsignadasActivasByEntrenado(entrenadoId)();
        if (!asignadas || asignadas.length === 0) return;

        for (const ra of asignadas) {
            const fechaObjetivo = this.calcularProximaFechaObjetivo(ra, ahora);
            if (!fechaObjetivo) continue;

            if (fechaObjetivo.getTime() >= ahora.getTime() && fechaObjetivo.getTime() <= limite.getTime()) {
                const yyyyMMdd = this.formatearYYYYMMDD(fechaObjetivo);
                const notifId = `notif-rutina-proxima-${ra.id}-${yyyyMMdd}`;

                const rutina = this.rutinaService.rutinas().find(r => r.id === ra.rutinaId);
                const nombreRutina = rutina?.nombre || 'tu rutina asignada';

                const notificacion: Notificacion = {
                    id: notifId,
                    usuarioId: entrenadoId,
                    tipo: TipoNotificacion.RECORDATORIO,
                    titulo: 'Rutina próxima',
                    mensaje: `Tienes ${nombreRutina} próximamente (${fechaObjetivo.toLocaleDateString('es-ES')}).`,
                    leida: false,
                    datos: {
                        rutinaAsignadaId: ra.id,
                        rutinaId: ra.rutinaId,
                        fechaObjetivo: fechaObjetivo,
                    },
                    fechaCreacion: new Date()
                };

                try {
                    await this.notificacionService.save(notificacion);
                } catch (e) {
                    console.warn('No se pudo guardar notificación de rutina próxima:', e);
                }
            }
        }
    }

    private calcularProximaFechaObjetivo(ra: RutinaAsignada, referencia: Date): Date | null {
        if (ra.fechaEspecifica) {
            return new Date(ra.fechaEspecifica);
        }

        if (ra.diaSemana) {
            const targetDow = this.mapDiaSemana(ra.diaSemana);
            if (targetDow === null) return null;
            const ref = new Date(referencia);
            const diff = (targetDow - ref.getDay() + 7) % 7;
            const proxima = new Date(ref);
            proxima.setHours(23, 59, 59, 999);
            proxima.setDate(ref.getDate() + diff);
            return proxima;
        }

        return null;
    }

    private formatearYYYYMMDD(d: Date): string {
        const y = d.getFullYear();
        const m = `${d.getMonth() + 1}`.padStart(2, '0');
        const day = `${d.getDate()}`.padStart(2, '0');
        return `${y}${m}${day}`;
    }

    private mapDiaSemana(dia: string): number | null {
        const v = dia.trim().toLowerCase();
        const map: Record<string, number> = {
            'domingo': 0, 'dom': 0, 'sun': 0, 'sunday': 0,
            'lunes': 1, 'lun': 1, 'mon': 1, 'monday': 1,
            'martes': 2, 'mar': 2, 'tue': 2, 'tuesday': 2,
            'miercoles': 3, 'miércoles': 3, 'mie': 3, 'mié': 3, 'wed': 3, 'wednesday': 3,
            'jueves': 4, 'jue': 4, 'thu': 4, 'thursday': 4,
            'viernes': 5, 'vie': 5, 'fri': 5, 'friday': 5,
            'sabado': 6, 'sábado': 6, 'sab': 6, 'sáb': 6, 'sat': 6, 'saturday': 6,
        };
        return map[v] ?? null;
    }

    private mapToFirestore(rutinaAsignada: RutinaAsignada): any {
        return {
            rutinaId: rutinaAsignada.rutinaId,
            entrenadoId: rutinaAsignada.entrenadoId,
            entrenadorId: rutinaAsignada.entrenadorId,
            diaSemana: rutinaAsignada.diaSemana || null,
            fechaEspecifica: rutinaAsignada.fechaEspecifica ? Timestamp.fromDate(rutinaAsignada.fechaEspecifica) : null,
            fechaAsignacion: rutinaAsignada.fechaAsignacion ? Timestamp.fromDate(rutinaAsignada.fechaAsignacion) : Timestamp.now(),
            activa: rutinaAsignada.activa
        };
    }

    private mapFromFirestore(data: any): RutinaAsignada {
        return {
            id: data.id,
            rutinaId: data.rutinaId,
            entrenadoId: data.entrenadoId,
            entrenadorId: data.entrenadorId,
            diaSemana: data.diaSemana || undefined,
            fechaEspecifica: data.fechaEspecifica instanceof Timestamp ? data.fechaEspecifica.toDate() : (data.fechaEspecifica ? new Date(data.fechaEspecifica) : undefined),
            fechaAsignacion: data.fechaAsignacion instanceof Timestamp ? data.fechaAsignacion.toDate() : (data.fechaAsignacion ? new Date(data.fechaAsignacion) : new Date()),
            activa: data.activa
        } as RutinaAsignada;
    }
}

import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
    Firestore,
    collection,
    addDoc,
    doc,
    deleteDoc,
    setDoc,
    onSnapshot,
    query,
    where,
    QuerySnapshot,
    DocumentSnapshot,
    Timestamp
} from 'firebase/firestore';
import { Rutina } from 'gym-library';
import { EjercicioService } from './ejercicio.service';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

export interface RutinaConEjercicios extends Rutina {
    ejercicios: any[]; // Ejercicios ya resueltos
}

@Injectable({ providedIn: 'root' })
export class RutinaService {
    private readonly firestore = inject(FIRESTORE);
    private readonly injector = inject(Injector);
    private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
    private readonly COLLECTION = 'rutinas';

    // Señal interna con todas las rutinas
    private readonly _rutinas: WritableSignal<Rutina[]> = signal<Rutina[]>([]);
    private readonly rutinaSignals = new Map<string, WritableSignal<Rutina | null>>();
    private isListenerInitialized = false;

    // Inyectar EjercicioService para combinar datos
    private readonly ejercicioService = inject(EjercicioService);

    /**
     * Devuelve las rutinas "creadas por el usuario", combinando:
     * - Las que tienen `creadorId` (nuevo modelo)
     * - Las que están en la lista legacy `rutinasCreadas` del perfil de entrenado
     */
    getCreatedByUser(userId: string, legacyCreatedIds: string[] = []): Signal<Rutina[]> {
        return computed(() => {
            const all = this.rutinas();
            const byCreator = all.filter(r => r.creadorId === userId);
            const legacySet = new Set(legacyCreatedIds);
            const byLegacy = all.filter(r => legacySet.has(r.id));

            const map = new Map<string, Rutina>();
            [...byCreator, ...byLegacy].forEach(r => map.set(r.id, r));
            return Array.from(map.values());
        });
    }

    constructor() { }

    /**
     * Ejecuta el callback en el contexto correcto (zona o inyección)
     */
    private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
        if (this.zoneRunner) {
            return this.zoneRunner.run(callback);
        }
        return runInInjectionContext(this.injector, callback as any);
    }

    /**
     * 🔄 Inicializa el listener de Firestore de forma segura.
     * Si se pasa gymId, filtra por gimnasio (recomendado para entrenados).
     */
    private initializeListener(gymId?: string): void {
        if (this.isListenerInitialized) return;

        try {
            const col = collection(this.firestore, this.COLLECTION);
            let q: any = col;

            if (gymId) {
                q = query(col, where('gimnasioId', '==', gymId));
            }

            onSnapshot(q, (snap: QuerySnapshot) => {
                this.runInZone(() => {
                    const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
                    this._rutinas.set(list);
                });
            });
            this.isListenerInitialized = true;
        } catch (e) {
            console.warn('Error inicializando listener de rutinas:', e);
        }
    }

    /**
     * 📊 Signal readonly con todas las rutinas (o filtradas por gym si se inicializó así)
     */
    get rutinas(): Signal<Rutina[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener();
        }
        return this._rutinas.asReadonly();
    }

    /**
     * Versión gym-scoped para la sección de entrenados.
     */
    getRutinasForGym(gymId: string): Signal<Rutina[]> {
        if (!this.isListenerInitialized) {
            this.initializeListener(gymId);
        }
        return this._rutinas.asReadonly();
    }

    /**
     * 📊 Obtiene una rutina específica por ID
     */
    getRutina(id: string): Signal<Rutina | null> {
        if (!this.rutinaSignals.has(id)) {
            const rutinaSignal = signal<Rutina | null>(null);
            this.rutinaSignals.set(id, rutinaSignal);

            const rutinaRef = doc(this.firestore, this.COLLECTION, id);
            onSnapshot(rutinaRef, (docSnap: DocumentSnapshot) => {
                this.runInZone(() => {
                    if (docSnap.exists()) {
                        rutinaSignal.set(this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
                    } else {
                        rutinaSignal.set(null);
                    }
                });
            });
        }
        return this.rutinaSignals.get(id)!.asReadonly();
    }

    /**
     * 🛰️ Actualiza el estado de compartir de una rutina
     */
    async setCompartida(id: string, compartida: boolean, userId: string, userName?: string): Promise<void> {
        const rutinaRef = doc(this.firestore, this.COLLECTION, id);
        const data: Partial<Rutina> = {
            compartida,
            usuarioId: userId,
            nombreUsuario: userName,
            fechaCompartida: compartida ? Timestamp.now() : null
        };
        await setDoc(rutinaRef, data, { merge: true });
    }

    /**
     * 💾 Guarda o actualiza una rutina (upsert si tiene id)
     */
    async save(rutina: Rutina): Promise<void> {
        return this.runInZone(async () => {
            const dataToSave = this.mapToFirestore(rutina);
            if (rutina.id) {
                const rutinaRef = doc(this.firestore, this.COLLECTION, rutina.id);
                await setDoc(rutinaRef, dataToSave, { merge: true });
            } else {
                const col = collection(this.firestore, this.COLLECTION);
                const docRef = await addDoc(col, dataToSave);
                rutina.id = docRef.id;
            }
        });
    }

    /**
     * 🗑️ Elimina una rutina por ID
     */
    async delete(id: string): Promise<void> {
        return this.runInZone(async () => {
            const rutinaRef = doc(this.firestore, this.COLLECTION, id);
            await deleteDoc(rutinaRef);
        });
    }

    /**
     * 🔍 Busca rutinas por nombre
     */
    getRutinasByNombre(nombre: string): Signal<Rutina[]> {
        return computed(() =>
            this._rutinas().filter(rutina =>
                rutina.nombre.toLowerCase().includes(nombre.toLowerCase())
            )
        );
    }

    /**
     * 🔍 Busca rutinas activas
     */
    getRutinasActivas(): Signal<Rutina[]> {
        return computed(() =>
            this._rutinas().filter(rutina => rutina.activa)
        );
    }

    /**
     * 📊 Obtiene el conteo total de rutinas
     */
    get rutinaCount(): Signal<number> {
        return computed(() => this._rutinas().length);
    }

    /**
     * 📊 Obtiene el conteo de rutinas activas
     */
    get rutinaActivaCount(): Signal<number> {
        return computed(() => this._rutinas().filter(r => r.activa).length);
    }

    /**
     * 🔍 Busca rutinas por duración
     */
    getRutinasByDuracion(duracion: number): Signal<Rutina[]> {
        return computed(() =>
            this._rutinas().filter(rutina =>
                rutina.duracion === duracion
            )
        );
    }

    /**
     * 🔍 Busca rutinas completadas (DEPRECATED - usar ProgresoService)
     * @deprecated El progreso ahora está en el modelo del entrenado
     */
    getRutinasCompletadas(): Signal<Rutina[]> {
        return computed(() => []);
    }

    /**
     * 🎯 Obtiene una rutina con sus ejercicios ya resueltos (más eficiente que hacer llamadas separadas)
     */
    getRutinaConEjercicios(id: string): Signal<RutinaConEjercicios | null> {
        return computed(() => {
            // Obtener la rutina base
            const rutinaSignal = this.getRutina(id);
            const rutina = rutinaSignal();

            if (!rutina || !rutina.ejerciciosIds || !Array.isArray(rutina.ejerciciosIds)) {
                return null;
            }

            // Obtener todos los ejercicios disponibles
            const todosEjercicios = this.ejercicioService.ejercicios();

            // Resolver ejercicios por IDs
            const ejerciciosResueltos = rutina.ejerciciosIds
                .map(id => todosEjercicios.find(e => e && e.id === id))
                .filter(e => e !== undefined); // Filtrar ejercicios no encontrados

            // Retornar rutina con ejercicios incluidos
            return {
                ...rutina,
                ejercicios: ejerciciosResueltos
            } as RutinaConEjercicios;
        });
    }

    private mapFromFirestore(data: any): Rutina {
        return {
            id: data.id,
            nombre: data.nombre || '',
            activa: data.activa ?? true,
            descripcion: data.descripcion,
            ejerciciosIds: data.ejerciciosIds || data.ejercicios || [], // Compatibilidad
            fechaCreacion: data.fechaCreacion instanceof Timestamp ? data.fechaCreacion.toDate() : data.fechaCreacion,
            fechaModificacion: data.fechaModificacion instanceof Timestamp ? data.fechaModificacion.toDate() : data.fechaModificacion,
            duracion: data.duracion,
            creadorId: data.creadorId,
            diasSemana: data.diasSemana || []
        };
    }

    private mapToFirestore(rutina: Rutina): any {
        const data: any = {
            nombre: rutina.nombre,
            activa: rutina.activa ?? true
        };

        data.descripcion = rutina.descripcion || '';
        if (rutina.ejerciciosIds && rutina.ejerciciosIds.length > 0) data.ejerciciosIds = rutina.ejerciciosIds;
        if (rutina.fechaCreacion) data.fechaCreacion = rutina.fechaCreacion instanceof Date ? Timestamp.fromDate(rutina.fechaCreacion) : rutina.fechaCreacion;
        if (rutina.fechaModificacion) data.fechaModificacion = rutina.fechaModificacion instanceof Date ? Timestamp.fromDate(rutina.fechaModificacion) : rutina.fechaModificacion;
        if (rutina.duracion && rutina.duracion > 0) data.duracion = rutina.duracion;
        if (rutina.creadorId) data.creadorId = rutina.creadorId;
        if (rutina.diasSemana && Array.isArray(rutina.diasSemana) && rutina.diasSemana.length > 0) data.diasSemana = rutina.diasSemana;

        return data;
    }
}

import { Injectable, signal, WritableSignal, Signal, inject, Injector, runInInjectionContext } from '@angular/core';
import {
  Firestore,
  collection,
  doc,
  setDoc,
  updateDoc,
  deleteDoc,
  onSnapshot,
  query,
  where,
  Timestamp,
  arrayUnion,
  arrayRemove,
  QuerySnapshot,
  DocumentSnapshot
} from 'firebase/firestore';
import { SesionRutina, SesionRutinaStatus, Rutina, Ejercicio } from 'gym-library';
import { RutinaService } from './rutina.service';
import { EjercicioService } from './ejercicio.service';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

/**
 * Servicio para gestionar sesiones de rutina como documentos independientes en Firestore
 */
@Injectable({ providedIn: 'root' })
export class SesionRutinaService {
  private readonly firestore = inject(FIRESTORE);
  private readonly injector = inject(Injector);
  private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
  private readonly COLLECTION = 'sesiones-rutina';

  private readonly _sesionesPorEntrenado = new Map<string, WritableSignal<SesionRutina[]>>();
  private _sesionesCompartidasSignal?: Signal<SesionRutina[]>;

  // inyección de servicios
  private readonly rutinaService: RutinaService = inject(RutinaService);
  private readonly ejercicioService: EjercicioService = inject(EjercicioService);

  constructor() { }

  /**
   * Ejecuta el callback en el contexto correcto (zona o inyección)
   */
  private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
    if (this.zoneRunner) {
      return this.zoneRunner.run(callback);
    }
    return runInInjectionContext(this.injector, callback as any);
  }

  /**
   * Normaliza y limpia la sesión antes de guardar
   */
  private normalizeSesionRutina(sesion: SesionRutina): any {
    const normalized: any = { ...sesion };

    // Eliminar cualquier campo undefined para evitar errores en Firestore
    Object.keys(normalized).forEach(key => {
      if (normalized[key] === undefined) {
        delete normalized[key];
      }
    });

    // Normalizar rutinaResumen si existe
    if (normalized.rutinaResumen) {
      normalized.rutinaResumen = { ...normalized.rutinaResumen };
      Object.keys(normalized.rutinaResumen).forEach(key => {
        if (normalized.rutinaResumen[key] === undefined) {
          delete normalized.rutinaResumen[key];
        }
      });

      // Normalizar ejercicios
      if (normalized.rutinaResumen.ejercicios) {
        normalized.rutinaResumen.ejercicios = normalized.rutinaResumen.ejercicios.map((ejercicio: any) => {
          const ej: any = { ...ejercicio };
          Object.keys(ej).forEach(key => {
            if (ej[key] === undefined) {
              delete ej[key];
            }
          });
          return ej;
        });
      }
    }

    return normalized;
  }

  /**
   * Obtiene sesiones por entrenado
   */
  getSesionesPorEntrenado(entrenadoId: string): Signal<SesionRutina[]> {
    if (!this._sesionesPorEntrenado.has(entrenadoId)) {
      const sesionesSignal = signal<SesionRutina[]>([]);
      this._sesionesPorEntrenado.set(entrenadoId, sesionesSignal);

      const q = query(collection(this.firestore, this.COLLECTION), where('entrenadoId', '==', entrenadoId));
      onSnapshot(q, (snapshot: QuerySnapshot) => {
        this.runInZone(() => {
          const sesiones = snapshot.docs.map(d => this.mapFromFirestore({ ...d.data(), id: d.id }));
          sesionesSignal.set(sesiones);
        });
      });
    }
    return this._sesionesPorEntrenado.get(entrenadoId)!.asReadonly();
  }

  /**
   * Inicializa sesión de rutina en base a un usuario y a una rutina asignada
   */
  async inicializarSesionRutina(entrenadoId: string, rutinaId: string): Promise<SesionRutina> {
    const rutinaSesion = await this.getRutinaById(rutinaId);

    if (!rutinaSesion) {
      throw new Error('Rutina no encontrada');
    }

    const nuevaSesion: SesionRutina = {
      id: this.generarIdUnico(),
      entrenadoId: entrenadoId,
      fechaInicio: new Date(),
      rutinaResumen: {
        id: rutinaSesion.id,
        nombre: rutinaSesion.nombre,
        ejercicios: await this.getEjerciciosByRutinaId(rutinaId)
      },
      status: SesionRutinaStatus.EN_PROGRESO,
      porcentajeCompletado: 0,
      completada: false
    };
    return nuevaSesion;
  }

  /**
   * Crea una nueva sesión de rutina
   */
  async crearSesion(sesion: SesionRutina): Promise<void> {
    return this.runInZone(async () => {
      const normalizedSesion = this.normalizeSesionRutina(sesion);
      const dataToSave = this.mapToFirestore(normalizedSesion);
      const ref = doc(this.firestore, this.COLLECTION, sesion.id);
      await setDoc(ref, dataToSave);
    });
  }

  /**
   * Obtiene una rutina por su ID con reintentos limitados (evita polling largo).
   * Prefiere la señal de lista completa; si no está, activa el listener individual.
   */
  async getRutinaById(rutinaId: string): Promise<Rutina> {
    const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));
    const maxAttempts = 6; // ~1.1s total con backoff corto

    // 1. Intentos rápidos contra la lista en memoria (normalmente ya precargada)
    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      const fromList = this.rutinaService.rutinas().find(r => r.id === rutinaId);
      if (fromList) return fromList;

      // En el primer fallo, activamos el listener de documento individual
      if (attempt === 0) {
        this.rutinaService.getRutina(rutinaId); // dispara onSnapshot si no existe
      }

      await wait(80 + attempt * 60); // backoff suave: 80, 140, 200...
    }

    // 2. Último intento contra el signal individual
    const single = this.rutinaService.getRutina(rutinaId)();
    if (single) return single;

    throw new Error(`Rutina no encontrada tras espera: ${rutinaId}`);
  }

  async getEjerciciosByRutinaId(rutinaId: string): Promise<Ejercicio[]> {
    const rutina = await this.getRutinaById(rutinaId);
    if (!rutina.ejerciciosIds?.length) return [];
    const allEjercicios = this.ejercicioService.ejercicios();
    return allEjercicios.filter(e => rutina.ejerciciosIds!.includes(e.id));
  }

  /**
   * Actualiza una sesión existente
   */
  async actualizarSesion(sesion: SesionRutina): Promise<void> {
    return this.runInZone(async () => {
      const normalizedSesion = this.normalizeSesionRutina(sesion);
      const dataToSave = this.mapToFirestore(normalizedSesion);
      const ref = doc(this.firestore, this.COLLECTION, sesion.id);
      await updateDoc(ref, dataToSave);
    });
  }

  /**
   * Marca una sesión como completada
   */
  async completarSesion(sesion: SesionRutina, fechaFin: Date, duracion: number): Promise<void> {
    sesion.fechaFin = fechaFin;
    sesion.duracion = duracion;
    sesion.completada = true;
    sesion.status = SesionRutinaStatus.COMPLETADA;
    await this.actualizarSesion(sesion);
  }

  /**
   * Elimina una sesión
   */
  async eliminarSesion(id: string): Promise<void> {
    return this.runInZone(async () => {
      const ref = doc(this.firestore, this.COLLECTION, id);
      await deleteDoc(ref);
    });
  }

  /**
   * Actualiza el estado de compartir de una sesión consumida
   */
  async setCompartida(id: string, compartida: boolean, userName?: string, userPhoto?: string, fotoProgreso?: string, gimnasioId?: string): Promise<void> {
    return this.runInZone(async () => {
      const ref = doc(this.firestore, this.COLLECTION, id);
      const data: any = {
        compartida,
        nombreUsuario: userName || 'Usuario',
        fotoUsuario: userPhoto || null, // Asegurar null en lugar de undefined
        fotoProgreso: fotoProgreso || null,
        fechaCompartida: compartida ? Timestamp.now() : null
      };
      if (gimnasioId) {
        data.gimnasioId = gimnasioId;
      }
      await updateDoc(ref, data);
    });
  }

  /**
   * Obtiene todas las sesiones compartidas (Feed Social)
   * 
   * IMPORTANTE: Siempre traemos todas las compartidas (sin filtro por gimnasio en la query).
   * El filtrado por gym + "siguiendo" se hace del lado del cliente en feed-tab.component.ts
   * para mantener compatibilidad con sesiones legacy que NO tienen el campo `gimnasioId`.
   * 
   * No cambies esto a where('gimnasioId') sin backfill de datos legacy.
   */
  getSesionesCompartidas(_gimnasioId?: string): Signal<SesionRutina[]> {
    if (this._sesionesCompartidasSignal) {
      return this._sesionesCompartidasSignal;
    }

    const sesionesSignal = signal<SesionRutina[]>([]);
    const col = collection(this.firestore, this.COLLECTION);
    const q = query(col, where('compartida', '==', true));

    onSnapshot(q, (snapshot: QuerySnapshot) => {
      this.runInZone(() => {
        const sesiones = snapshot.docs.map(d => this.mapFromFirestore({ ...d.data(), id: d.id }));

        // Ordenar por fecha de compartida descendente
        sesiones.sort((a, b) => {
          const timeA = this.getSafeTime(a.fechaCompartida) || this.getSafeTime(a.fechaInicio) || 0;
          const timeB = this.getSafeTime(b.fechaCompartida) || this.getSafeTime(b.fechaInicio) || 0;
          return timeB - timeA;
        });

        sesionesSignal.set(sesiones);
      });
    });

    this._sesionesCompartidasSignal = sesionesSignal.asReadonly();
    return this._sesionesCompartidasSignal;
  }

  private getSafeTime(date: any): number {
    if (!date) return 0;
    if (date instanceof Date) return date.getTime();
    if (date.toDate && typeof date.toDate === 'function') return date.toDate().getTime();
    if (typeof date === 'string' || typeof date === 'number') {
      const d = new Date(date);
      return isNaN(d.getTime()) ? 0 : d.getTime();
    }
    return 0;
  }

  /**
   * Agrega un like a una sesión compartida
   */
  async addLike(sesionId: string, userId: string): Promise<void> {
    const ref = doc(this.firestore, this.COLLECTION, sesionId);
    return this.runInZone(async () => {
      await updateDoc(ref, {
        likes: arrayUnion(userId)
      });
    });
  }

  /**
   * Elimina un like de una sesión compartida
   */
  async removeLike(sesionId: string, userId: string): Promise<void> {
    const ref = doc(this.firestore, this.COLLECTION, sesionId);
    return this.runInZone(async () => {
      await updateDoc(ref, {
        likes: arrayRemove(userId)
      });
    });
  }

  generarIdUnico(): string {
    return crypto.randomUUID();
  }

  private mapToFirestore(sesion: SesionRutina): any {
    const data = { ...sesion } as any;
    if (data.fechaInicio instanceof Date) {
      data.fechaInicio = Timestamp.fromDate(data.fechaInicio);
    }
    if (data.fechaFin instanceof Date) {
      data.fechaFin = Timestamp.fromDate(data.fechaFin);
    }
    if (data.fechaCompartida instanceof Date) {
      data.fechaCompartida = Timestamp.fromDate(data.fechaCompartida);
    }
    return data;
  }

  private mapFromFirestore(data: any): SesionRutina {
    return {
      ...data,
      fechaInicio: data.fechaInicio instanceof Timestamp ? data.fechaInicio.toDate() : (data.fechaInicio ? new Date(data.fechaInicio) : new Date()),
      fechaFin: data.fechaFin instanceof Timestamp ? data.fechaFin.toDate() : (data.fechaFin ? new Date(data.fechaFin) : undefined),
      fechaCompartida: data.fechaCompartida instanceof Timestamp ? data.fechaCompartida.toDate() : (data.fechaCompartida ? new Date(data.fechaCompartida) : undefined),
      likes: data.likes || [],
      fotoProgreso: data.fotoProgreso || null
    } as SesionRutina;
  }
}

import { Injectable, inject } from '@angular/core';
import { ProgresoService } from './progreso.service';
import { EstadisticasEntrenadoService } from './estadisticas-entrenado.service';
import { EntrenadoService } from './entrenado.service';
import { UserService } from './user.service';
import { SesionRutinaService } from './sesion-rutina.service';
import { SesionRutina } from 'gym-library';
import { ToastController } from '@ionic/angular/standalone';

export interface ShareProgressOptions {
  includeStats?: boolean;
  includeLevel?: boolean;
  includeStreak?: boolean;
  includeLast7Days?: boolean;
  backgroundColor?: string;
  textColor?: string;
  watermarkText?: string;
}

export interface SocialSharePlatform {
  name: 'instagram' | 'facebook' | 'twitter' | 'whatsapp';
  url: string;
}

/**
 * Servicio para compartir progreso en redes sociales
 * Genera imágenes con watermark para versión gratuita
 */
@Injectable({ providedIn: 'root' })
export class SocialShareService {
  private readonly progresoService = inject(ProgresoService);
  private readonly estadisticasService = inject(EstadisticasEntrenadoService);
  private readonly entrenadoService = inject(EntrenadoService);
  private readonly userService = inject(UserService);
  private readonly sesionRutinaService = inject(SesionRutinaService);
  private readonly toastCtrl = inject(ToastController);

  private readonly defaultWatermarkText = 'Exportá tu progreso completo en PDF — desbloqueá con Premium';

  /**
   * Genera una imagen del progreso con watermark
   * @param entrenadoId ID del entrenado
   * @param options Opciones de personalización
   * @returns Promise con el blob de la imagen generada
   */
  async generateProgressImage(
    entrenadoId: string,
    options: ShareProgressOptions = {}
  ): Promise<Blob> {
    const {
      includeStats = true,
      includeLevel = true,
      includeStreak = true,
      includeLast7Days = true,
      backgroundColor = '#1a1a1a',
      textColor = '#ffffff',
      watermarkText = this.defaultWatermarkText,
    } = options;

    // Obtener datos del entrenado y estadísticas (con fallback completo)
    const entrenado = this.entrenadoService.getEntrenado(entrenadoId)();
    let estadisticas = this.estadisticasService.getEstadisticas(entrenadoId)();

    if (!estadisticas) {
      // Intentar inicializar listener y esperar brevemente
      try {
        this.estadisticasService.initializeListener(entrenadoId);
      } catch (err) {
        // Ignorar si el adapter no está aún disponible
      }

      // Espera corta con polling
      const wait = (ms: number) => new Promise(r => setTimeout(r, ms));
      for (let i = 0; i < 5 && !estadisticas; i++) {
        await wait(200);
        estadisticas = this.estadisticasService.getEstadisticas(entrenadoId)();
      }
    }

    // Si aún no hay estadísticas, usar valores por defecto de manera segura
    if (!estadisticas) {
      estadisticas = {
        totalRutinasCompletadas: 0,
        rachaActual: 0,
        mejorRacha: 0,
        nivel: 1,
        experiencia: 0,
        experienciaProximoNivel: 100
      } as any;
    }

    const stats: any = estadisticas;

    // Nota: No requerimos que el entrenado esté disponible
    // El nombre del usuario se usará como fallback
  
  // Crear canvas
  const canvas = document.createElement('canvas');
  canvas.width = 1080; // Formato Instagram
  canvas.height = 1080;
  const ctx = canvas.getContext('2d');

    if (!ctx) {
      throw new Error('No se pudo obtener el contexto del canvas');
    }

    // Fondo degradado moderno
    const bgGrad = ctx.createLinearGradient(0, 0, 0, canvas.height);
    bgGrad.addColorStop(0, '#111827'); // slate-900
    bgGrad.addColorStop(1, '#0b0f17'); // más oscuro
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Encabezado (alineado a la izquierda, más minimalista)
  const marginX = 96;
  ctx.textAlign = 'left';
  ctx.fillStyle = '#ffffff';
  ctx.shadowColor = 'rgba(0,0,0,0.35)';
  ctx.shadowBlur = 12;
  ctx.font = 'bold 68px Arial';
  ctx.fillText('Mi Progreso', marginX, 110);
  ctx.shadowBlur = 0;

    // Nombre del usuario/entrenado (mejor fallback)
    const usuario = this.userService.user();
    // Intentar obtener el usuario asociado al entrenado (por uid === entrenadoId)
    let displayName: string | undefined = undefined;
    try {
      const list = this.userService.users(); // Signal invocada para obtener array
      const owner = list.find((u: any) => u?.uid === entrenadoId);
      displayName = owner?.nombre || owner?.email || usuario?.nombre || usuario?.email || undefined;
      if (!displayName) {
        // Polling corto por si el listener de usuarios aún no actualizó
        const wait = (ms: number) => new Promise(r => setTimeout(r, ms));
        const byUid = this.userService.getUserByUid(entrenadoId);
        for (let i = 0; i < 5 && !displayName; i++) {
          await wait(200);
          const u = byUid();
          if (u) {
            displayName = u.nombre || u.email || undefined;
            break;
          }
        }
      }
    } catch {}
    // No mostrar ID ni texto genérico: si no hay nombre real, omitimos la línea
    if (displayName) {
      ctx.fillStyle = '#e5e7eb';
      ctx.font = '500 40px Arial';
      ctx.fillText(displayName, marginX, 175);
    }

    // Precalcular métricas de últimos 7 días si se pidió
    let dias7: { label: string; key: string; count: number }[] | null = null;
    let total7 = 0;
    if (includeLast7Days) {
      const sesiones: SesionRutina[] = (this.sesionRutinaService.getSesionesPorEntrenado(entrenadoId)() || []) as any;
      const hoy = new Date(); hoy.setHours(0,0,0,0);
      const dayNames = ['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];
      dias7 = [];
      for (let i = 6; i >= 0; i--) {
        const d = new Date(hoy); d.setDate(hoy.getDate() - i);
        const key = `${d.getFullYear()}-${(d.getMonth()+1).toString().padStart(2,'0')}-${d.getDate().toString().padStart(2,'0')}`;
        dias7.push({ label: dayNames[d.getDay()], key, count: 0 });
      }
      const toDate = (v: any): Date | null => {
        if (!v) return null; if (v instanceof Date) return v; if (typeof v.toDate === 'function') return v.toDate();
        const d = new Date(v); return isNaN(d.getTime()) ? null : d;
      };
      const start = new Date(hoy); start.setDate(hoy.getDate() - 6); start.setHours(0,0,0,0);
      sesiones.filter(s => s && s.completada === true && s.fechaFin)
        .forEach(s => {
          const f = toDate((s as any).fechaFin); if (!f) return;
          const df = new Date(f); df.setHours(0,0,0,0);
          if (df < start || df > hoy) return;
          const key = `${df.getFullYear()}-${(df.getMonth()+1).toString().padStart(2,'0')}-${df.getDate().toString().padStart(2,'0')}`;
          const bucket = dias7!.find(d => d.key === key); if (bucket) bucket.count += 1;
        });
  total7 = dias7.reduce((acc, d) => acc + d.count, 0);
    }

  let yPosition = 240;
  const statsX = marginX;

    // Estadísticas
    if (includeStats) {
      // Subtítulo con pill
  ctx.font = 'bold 34px Arial';
  ctx.fillStyle = '#ffffff';
  ctx.textAlign = 'left';
  ctx.fillText('Estadísticas', marginX, yPosition);
  yPosition += 50;

      // Tarjeta semitransparente
  const cardX = marginX, cardY = yPosition - 42, cardW = canvas.width - marginX * 2, cardH = 110;
      ctx.fillStyle = 'rgba(255,255,255,0.06)';
      ctx.strokeStyle = 'rgba(255,255,255,0.12)';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.roundRect(cardX, cardY, cardW, cardH, 16);
      ctx.fill();
      ctx.stroke();

      ctx.font = '30px Arial';
  ctx.textAlign = 'left';
      ctx.fillStyle = '#f3f4f6';
      const labelTotal = includeLast7Days ? `Rutinas completadas (7 días): ${total7}` : `Rutinas completadas: ${stats.totalRutinasCompletadas}`;
  ctx.fillText(labelTotal, statsX + 14, yPosition);
  yPosition += 70;
    }

    // Nivel
    if (includeLevel) {
      ctx.fillText(
        `Nivel: ${stats.nivel} (${stats.experiencia} XP)`,
        statsX,
        yPosition
      );
      yPosition += 60;
    }

    // Racha
    if (includeStreak) {
      ctx.fillText(
        `Racha actual: ${stats.rachaActual} días`,
        statsX,
        yPosition
      );
      yPosition += 60;
      ctx.fillText(
        `Mejor racha: ${stats.mejorRacha} días`,
        statsX,
        yPosition
      );
      yPosition += 80;
    }

    // Últimos 7 días: gráfico de barras y total
    if (includeLast7Days && dias7) {
      const maxCount = Math.max(1, ...dias7.map(d => d.count));

      // Título sección
    ctx.textAlign = 'left';
    ctx.font = 'bold 32px Arial';
    ctx.fillStyle = '#ffffff';
    ctx.fillText('Últimos 7 días', marginX, yPosition);
      yPosition += 20;
    ctx.font = 'italic 22px Arial';
    ctx.fillStyle = '#d1d5db';
    ctx.fillText(`Rutinas completadas: ${total7}`, marginX, yPosition + 40);

      // Área del gráfico
      const chartTop = yPosition + 70;
      const reservedBottom = 120 + 30; // watermark + margen/labels
      const maxChartBottom = canvas.height - reservedBottom;
      let chartHeight = 220;
      if (chartTop + chartHeight > maxChartBottom) {
        chartHeight = Math.max(100, maxChartBottom - chartTop);
      }
      const chartLeft = marginX;
      const chartRight = canvas.width - marginX;
      const chartWidth = chartRight - chartLeft;

      // Eje base + líneas de guía
      ctx.strokeStyle = 'rgba(255,255,255,0.15)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(chartLeft, chartTop + chartHeight);
      ctx.lineTo(chartRight, chartTop + chartHeight);
      ctx.stroke();

      // Líneas de guía horizontales (4 divisiones)
      ctx.strokeStyle = 'rgba(255,255,255,0.08)';
      for (let i = 1; i <= 4; i++) {
        const y = chartTop + chartHeight - (chartHeight * i) / 4;
        ctx.beginPath();
        ctx.moveTo(chartLeft, y);
        ctx.lineTo(chartRight, y);
        ctx.stroke();
      }

      // Barras
      const barSpacing = 12;
      const barWidth = (chartWidth - barSpacing * (dias7.length - 1)) / dias7.length;
      dias7.forEach((d, idx) => {
        const h = Math.round((d.count / maxCount) * chartHeight);
        const x = chartLeft + idx * (barWidth + barSpacing);
        const y = chartTop + (chartHeight - h);
        const grad = ctx.createLinearGradient(0, y, 0, y + h);
        grad.addColorStop(0, '#60a5fa'); // blue-400
        grad.addColorStop(1, '#8b5cf6'); // violet-500
        ctx.fillStyle = grad;
        // sombra sutil de la barra
        ctx.shadowColor = 'rgba(0,0,0,0.3)';
        ctx.shadowBlur = 8;
        ctx.fillRect(x, y, barWidth, h);
        ctx.shadowBlur = 0;
        // Día
        ctx.fillStyle = textColor;
        ctx.font = '20px Arial';
        ctx.textAlign = 'center';
        ctx.fillText(d.label, x + barWidth / 2, chartTop + chartHeight + 24);
        if (d.count > 0) {
          ctx.font = 'bold 20px Arial';
          ctx.fillText(String(d.count), x + barWidth / 2, y - 8);
        }
      });

      yPosition = chartTop + chartHeight + 60;
    }

    // Watermark con fondo semitransparente
    ctx.textAlign = 'center';
    const watermarkHeight = 120;
    const watermarkY = canvas.height - watermarkHeight;
    
    // Fondo del watermark
    ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
    ctx.fillRect(0, watermarkY, canvas.width, watermarkHeight);

    // Texto del watermark
    ctx.fillStyle = '#ffcc00'; // Color dorado para destacar
    ctx.font = 'bold 24px Arial';
    
    // Dividir el texto en dos líneas si es muy largo
    const maxWidth = canvas.width - 100;
    const words = watermarkText.split(' ');
    let line1 = '';
    let line2 = '';
    let isSecondLine = false;

    for (const word of words) {
      const testLine = (isSecondLine ? line2 : line1) + word + ' ';
      const metrics = ctx.measureText(testLine);
      
      if (metrics.width > maxWidth && !isSecondLine) {
        isSecondLine = true;
        line2 = word + ' ';
      } else if (isSecondLine) {
        line2 += word + ' ';
      } else {
        line1 += word + ' ';
      }
    }

    if (line2) {
      ctx.fillText(line1.trim(), canvas.width / 2, watermarkY + 40);
      ctx.fillText(line2.trim(), canvas.width / 2, watermarkY + 75);
    } else {
      ctx.fillText(line1.trim(), canvas.width / 2, watermarkY + 60);
    }

    // Convertir canvas a blob
    return new Promise((resolve, reject) => {
      canvas.toBlob(
        (blob) => {
          if (blob) {
            resolve(blob);
          } else {
            reject(new Error('Error al generar la imagen'));
          }
        },
        'image/png',
        0.95
      );
    });
  }

  /**
   * Comparte la imagen del progreso en una red social
   * @param blob Imagen generada
   * @param platform Plataforma de red social
   * @param text Texto adicional para compartir
   */
  async shareToSocialMedia(
    blob: Blob,
    platform: 'instagram' | 'facebook' | 'twitter' | 'whatsapp',
    text: string = '¡Mira mi progreso!'
  ): Promise<void> {
    // Verificar si Web Share API está disponible
    if (navigator.share) {
      try {
        const file = new File([blob], 'mi-progreso.png', { type: 'image/png' });
        await navigator.share({
          files: [file],
          title: 'Mi Progreso',
          text: text,
        });
        return;
      } catch (error: any) {
        // Silenciar errores no críticos (cancelación)
        // Si el usuario cancela, el error será AbortError
        if (error.name === 'AbortError') {
          return; // No continuar con fallback si el usuario canceló
        }
        // Continuar con el método alternativo
      }
    } else {
      // Continuar con el fallback silenciosamente
    }

    // Método alternativo: descargar y abrir URLs específicas
    const url = URL.createObjectURL(blob);
    const shareUrls = this.getShareUrls(text);
    const targetUrl = shareUrls.find((u) => u.name === platform)?.url;

    if (targetUrl) {
      // Abrir en nueva ventana
      window.open(targetUrl, '_blank');
    } else {
      // Si no hay URL conocida, solo descargamos la imagen
    }

    // También descargar la imagen para que el usuario pueda subirla manualmente
    this.downloadImage(blob, 'mi-progreso.png');
  }

  /**
   * Descarga la imagen del progreso
   * @param blob Imagen generada
   * @param filename Nombre del archivo
   */
  downloadImage(blob: Blob, filename: string = 'mi-progreso.png'): void {
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }

  /**
   * Obtiene las URLs para compartir en diferentes plataformas
   * @param text Texto para compartir
   * @returns Array de plataformas con sus URLs
   */
  getShareUrls(text: string = '¡Mira mi progreso!'): SocialSharePlatform[] {
    const encodedText = encodeURIComponent(text);
    const encodedUrl = encodeURIComponent(window.location.href);

    return [
      {
        name: 'instagram',
        url: 'https://www.instagram.com/', // Instagram no tiene URL share directa
      },
      {
        name: 'facebook',
        url: `https://www.facebook.com/sharer/sharer.php?u=${encodedUrl}&quote=${encodedText}`,
      },
      {
        name: 'twitter',
        url: `https://twitter.com/intent/tweet?text=${encodedText}&url=${encodedUrl}`,
      },
      {
        name: 'whatsapp',
        url: `https://wa.me/?text=${encodedText}%20${encodedUrl}`,
      },
    ];
  }

  /**
   * Genera una imagen de progreso y la comparte directamente
   * @param entrenadoId ID del entrenado
   * @param platform Plataforma de red social
   * @param options Opciones de personalización
   */
  /**
   * Genera una imagen de progreso y la comparte directamente
   * @param entrenadoId ID del entrenado
   * @param platform Plataforma de red social
   * @param options Opciones de personalización
   */
  async generateAndShare(
    entrenadoId: string,
    platform: 'instagram' | 'facebook' | 'twitter' | 'whatsapp',
    options: ShareProgressOptions = {}
  ): Promise<void> {
    try {
      const blob = await this.generateProgressImage(entrenadoId, options);
      await this.shareToSocialMedia(blob, platform);
    } catch (error) {
      // Propagar sin loguear
      throw error;
    }
  }

  /**
   * Carga una imagen de forma segura con timeout y cache-buster para evitar problemas de CORS
   */
  private cargarImagenUrl(url: string): Promise<HTMLImageElement> {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = 'anonymous';

      const timeout = setTimeout(() => {
        img.src = ''; // Cancelar carga
        reject(new Error('Timeout cargando imagen de progreso'));
      }, 4000);

      img.onload = () => {
        clearTimeout(timeout);
        resolve(img);
      };

      img.onerror = (e) => {
        clearTimeout(timeout);
        reject(new Error('Error cargando imagen de progreso'));
      };

      // Agregar cache-buster para evitar problemas con CORS y caché en navegadores
      const separator = url.includes('?') ? '&' : '?';
      img.src = `${url}${separator}t=${Date.now()}`;
    });
  }

  private dibujarFotoFondo(ctx: CanvasRenderingContext2D, img: HTMLImageElement, size: number): void {
    const imgRatio = img.width / img.height;
    let drawWidth = size;
    let drawHeight = size;
    let offsetX = 0;
    let offsetY = 0;

    if (imgRatio > 1) {
      drawWidth = size * imgRatio;
      offsetX = -(drawWidth - size) / 2;
    } else {
      drawHeight = size / imgRatio;
      offsetY = -(drawHeight - size) / 2;
    }

    ctx.drawImage(img, offsetX, offsetY, drawWidth, drawHeight);
  }

  private dibujarFondoGradiente(ctx: CanvasRenderingContext2D, size: number): void {
    const grad = ctx.createLinearGradient(0, 0, size, size);
    grad.addColorStop(0, '#0f1923');
    grad.addColorStop(0.4, '#1a2e4a');
    grad.addColorStop(0.7, '#0d3355');
    grad.addColorStop(1, '#0a1628');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, size, size);

    // Círculo decorativo sutil
    const circleGrad = ctx.createRadialGradient(size * 0.75, size * 0.25, 0, size * 0.75, size * 0.25, size * 0.5);
    circleGrad.addColorStop(0, 'rgba(99,179,237,0.15)');
    circleGrad.addColorStop(1, 'rgba(99,179,237,0)');
    ctx.fillStyle = circleGrad;
    ctx.fillRect(0, 0, size, size);
  }

  private formatearFechaLocal(fecha?: Date | string): string {
    if (!fecha) return 'Sin fecha';
    const date = fecha instanceof Date ? fecha : new Date(fecha);
    return date.toLocaleDateString('es-ES', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  }

  private redondearMinutosLocal(segundos: number): number {
    return Math.round((segundos || 0) / 60);
  }

  private dibujarResumenSesion(ctx: CanvasRenderingContext2D, sesion: SesionRutina, size: number): void {
    const tiempo = this.redondearMinutosLocal(sesion.duracion || 0);
    const fecha = this.formatearFechaLocal(sesion.fechaInicio);
    const exercises = sesion.rutinaResumen?.ejercicios || [];
    const pad = 56;

    // ── FILA SUPERIOR ──────────────────────────────────────────
    const topY = 74;

    // Fecha
    ctx.font = `${size * 0.032}px Arial`;
    ctx.fillStyle = 'rgba(255,255,255,0.92)';
    ctx.textAlign = 'left';
    ctx.fillText(`📅 ${fecha}`, pad, topY);

    // "¡Completado! 🔥"
    ctx.font = `bold ${size * 0.032}px Arial`;
    ctx.fillStyle = '#fbbf24';
    ctx.textAlign = 'right';
    ctx.fillText('¡Completado! 🔥', size - pad, topY);
    ctx.textAlign = 'left';

    // ── SECCIÓN INFERIOR ─────────────────
    let y = size * 0.72;

    // Duración
    ctx.font = `bold ${size * 0.052}px Arial`;
    ctx.fillStyle = 'rgba(255,255,255,0.95)';
    ctx.fillText(`⏱ ${tiempo} min`, pad, y);
    y += size * 0.072;

    // Lista de ejercicios
    if (exercises.length) {
      const maxEjs = Math.min(exercises.length, 6);
      for (let i = 0; i < maxEjs; i++) {
        const ej = exercises[i];
        ctx.font = `${size * 0.034}px Arial`;
        ctx.fillStyle = 'rgba(255,255,255,0.85)';
        const ejNombre = `${i + 1}. ${ej.nombre || 'Ejercicio'}`;
        const ejTruncado = ejNombre.length > 32 ? ejNombre.substring(0, 32) + '...' : ejNombre;
        ctx.fillText(ejTruncado, pad, y);
        y += size * 0.054;
        if (y > size * 0.93) break;
      }

      if (exercises.length > 6) {
        ctx.font = `italic ${size * 0.027}px Arial`;
        ctx.fillStyle = 'rgba(255,255,255,0.4)';
        ctx.fillText(`+${exercises.length - 6} más...`, pad, y);
      }
    }
  }

  private dibujarWatermarkSimple(ctx: CanvasRenderingContext2D, size: number): void {
    ctx.font = `${size * 0.025}px Arial`;
    ctx.fillStyle = 'rgba(255,255,255,0.3)';
    ctx.textAlign = 'right';
    ctx.fillText('Gym App', size - 40, size - 40);
    ctx.textAlign = 'left';
  }

  /**
   * Genera la imagen para compartir una sesión de rutina
   */
  async generarImagenSesionRutina(sesion: SesionRutina): Promise<Blob> {
    const SIZE = 1080;
    const canvas = document.createElement('canvas');
    canvas.width = SIZE;
    canvas.height = SIZE;
    const ctx = canvas.getContext('2d');
    if (!ctx) {
      throw new Error('No se pudo obtener el contexto 2D del canvas');
    }

    if (sesion.fotoProgreso) {
      try {
        const img = await this.cargarImagenUrl(sesion.fotoProgreso);
        this.dibujarFotoFondo(ctx, img, SIZE);
      } catch (e) {
        console.warn('[SocialShareService] Error al cargar la foto de progreso para el canvas, usando degradado:', e);
        this.dibujarFondoGradiente(ctx, SIZE);
      }
    } else {
      this.dibujarFondoGradiente(ctx, SIZE);
    }

    // Overlay oscuro inferior
    const overlayGrad = ctx.createLinearGradient(0, SIZE * 0.35, 0, SIZE);
    overlayGrad.addColorStop(0, 'rgba(0,0,0,0)');
    overlayGrad.addColorStop(0.4, 'rgba(0,0,0,0.75)');
    overlayGrad.addColorStop(1, 'rgba(0,0,0,0.92)');
    ctx.fillStyle = overlayGrad;
    ctx.fillRect(0, 0, SIZE, SIZE);

    // Overlay oscuro superior
    const topGrad = ctx.createLinearGradient(0, 0, 0, SIZE * 0.22);
    topGrad.addColorStop(0, 'rgba(0,0,0,0.7)');
    topGrad.addColorStop(1, 'rgba(0,0,0,0)');
    ctx.fillStyle = topGrad;
    ctx.fillRect(0, 0, SIZE, SIZE);

    this.dibujarResumenSesion(ctx, sesion, SIZE);
    this.dibujarWatermarkSimple(ctx, SIZE);

    return new Promise<Blob>((resolve, reject) => {
      canvas.toBlob(blob => {
        blob ? resolve(blob) : reject(new Error('Canvas vacío'));
      }, 'image/png');
    });
  }

  /**
   * Comparte una sesión de rutina (por WhatsApp o menú nativo según soporte)
   */
  async compartirSesionRutina(sesion: SesionRutina, textoCompartir: string, onReadyToShare?: () => void): Promise<void> {
    try {
      const imageBlob = await Promise.race([
        this.generarImagenSesionRutina(sesion),
        new Promise<never>((_, reject) => setTimeout(() => reject(new Error('Timeout maestro generación imagen')), 5000))
      ]);
      const imageFile = new File([imageBlob], 'gym-app-entrenamiento.png', { type: 'image/png' });

      if (onReadyToShare) {
        onReadyToShare();
      }

      if (navigator.share && navigator.canShare?.({ files: [imageFile] })) {
        try {
          await navigator.share({ files: [imageFile], text: textoCompartir });
          return;
        } catch (err: unknown) {
          if (err instanceof Error && (err.name === 'AbortError' || err.name === 'NotAllowedError')) {
            return;
          }
        }
      }

      if (navigator.share) {
        try {
          await navigator.share({ title: 'Gym App', text: textoCompartir });
          return;
        } catch { /* continuar */ }
      }

      this.downloadImage(imageBlob, 'gym-app-entrenamiento.png');
      const waUrl = `https://wa.me/?text=${encodeURIComponent(textoCompartir)}`;
      window.open(waUrl, '_blank');

      const toast = await this.toastCtrl.create({
        message: 'Imagen guardada. Abriendo WhatsApp...',
        duration: 2000,
        color: 'success',
        position: 'bottom'
      });
      toast.present();

    } catch (error) {
      console.error('[SocialShareService] Error al compartir sesión:', error);
      if (onReadyToShare) {
        onReadyToShare();
      }
      const waUrl = `https://wa.me/?text=${encodeURIComponent(textoCompartir)}`;
      window.open(waUrl, '_blank');
    }
  }
}

