import { Injectable, signal, WritableSignal, Signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
	Firestore,
	collection,
	addDoc,
	doc,
	deleteDoc,
	setDoc,
	onSnapshot,
	query,
	where,
	QuerySnapshot,
	DocumentSnapshot,
	Timestamp
} from 'firebase/firestore';
import { Ejercicio, Rol } from 'gym-library';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

/**
 * Errores de validación personalizados
 */
export class EjercicioValidationError extends Error {
	constructor(message: string) {
		super(message);
		this.name = 'EjercicioValidationError';
	}
}

@Injectable({ providedIn: 'root' })
export class EjercicioService {
	private readonly firestore = inject(FIRESTORE);

	private readonly injector = inject(Injector);
	private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
	private readonly COLLECTION = 'ejercicios';

	private readonly _ejercicios: WritableSignal<Ejercicio[]> = signal<Ejercicio[]>([]);
	private readonly ejercicioSignals = new Map<string, WritableSignal<Ejercicio | null>>();
	private readonly isSubscribed = new Map<string, boolean>();
	private readonly computedFilters = new Map<string, Signal<Ejercicio[]>>();
	private isListenerInitialized = false;

	/**
	 * Devuelve los ejercicios "creados por el usuario", combinando:
	 * - Los que tienen `creadorId` (nuevo modelo)
	 * - Los que están en la lista legacy `ejerciciosCreadosIds` del perfil de entrenado
	 */
	getCreatedByUser(userId: string, legacyCreatedIds: string[] = []): Signal<Ejercicio[]> {
		return computed(() => {
			const all = this.ejercicios();
			const byCreator = all.filter(e => e.creadorId === userId);
			const legacySet = new Set(legacyCreatedIds);
			const byLegacy = all.filter(e => legacySet.has(e.id));

			const map = new Map<string, Ejercicio>();
			[...byCreator, ...byLegacy].forEach(e => map.set(e.id, e));
			return Array.from(map.values());
		});
	}

	private filterByRange<T>(items: T[], getValue: (item: T) => number, min: number, max?: number): T[] {
		return items.filter(item => {
			const value = getValue(item);
			if (max !== undefined) {
				return value >= min && value <= max;
			}
			return value >= min;
		});
	}

	constructor() { }

	/**
	 * Ejecuta el callback en el contexto correcto (zona o inyección)
	 */
	private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
		if (this.zoneRunner) {
			return this.zoneRunner.run(callback);
		}
		return runInInjectionContext(this.injector, callback as any);
	}

	/**
	 * Inicializa el listener de Firestore de forma segura.
	 * Si se pasa gymId, filtra por gimnasio (recomendado para entrenados/creaciones).
	 */
	private initializeListener(gymId?: string): void {
		if (this.isListenerInitialized) return;

		try {
			const col = collection(this.firestore, this.COLLECTION);
			let q: any = col;

			if (gymId) {
				q = query(col, where('gimnasioId', '==', gymId));
			}

			onSnapshot(q, (snap: QuerySnapshot) => {
				this.runInZone(() => {
					const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
					this._ejercicios.set(list);
				});
			});
			this.isListenerInitialized = true;
		} catch (e) {
			console.warn('Error inicializando listener de ejercicios:', e);
		}
	}

	/**
	 * Signal readonly con todos los ejercicios
	 */
	get ejercicios(): Signal<Ejercicio[]> {
		if (!this.isListenerInitialized) {
			this.initializeListener();
		}
		return this._ejercicios.asReadonly();
	}

	/**
	 * Versión gym-scoped para la sección de entrenados.
	 */
	getEjerciciosForGym(gymId: string): Signal<Ejercicio[]> {
		if (!this.isListenerInitialized) {
			this.initializeListener(gymId);
		}
		return this._ejercicios.asReadonly();
	}

	/**
	 * Obtiene un ejercicio específico por ID
	 */
	getEjercicio(id: string): Signal<Ejercicio | null> {
		if (!this.ejercicioSignals.has(id)) {
			const ejercicioSignal = signal<Ejercicio | null>(null);
			this.ejercicioSignals.set(id, ejercicioSignal);
			this.isSubscribed.set(id, false);

			const ejercicioRef = doc(this.firestore, this.COLLECTION, id);
			onSnapshot(ejercicioRef, (docSnap: DocumentSnapshot) => {
				this.runInZone(() => {
					if (docSnap.exists()) {
						ejercicioSignal.set(this.mapFromFirestore({ ...docSnap.data(), id: docSnap.id }));
					} else {
						ejercicioSignal.set(null);
					}
					this.isSubscribed.set(id, true);
				});
			});
		}
		return this.ejercicioSignals.get(id)!.asReadonly();
	}

	/**
	 * Valida las reglas de negocio del ejercicio
	 * @throws {EjercicioValidationError} Si la validación falla
	 */
	validateEjercicio(ejercicio: Ejercicio): void {
		if (ejercicio.series < 0) {
			throw new EjercicioValidationError('Las series deben ser un valor positivo');
		}

		if (ejercicio.repeticiones < 0) {
			throw new EjercicioValidationError('Las repeticiones deben ser un valor positivo');
		}

		if (ejercicio.peso !== undefined && ejercicio.peso < 0) {
			throw new EjercicioValidationError('El peso debe ser un valor positivo');
		}
	}

	/**
	 * Normaliza y limpia el ejercicio antes de guardar
	 */
	private normalizeEjercicio(ejercicio: Ejercicio): Ejercicio {
		const normalized: any = { ...ejercicio };

		if (!normalized.nombre || normalized.nombre.trim() === '') {
			throw new EjercicioValidationError('El nombre del ejercicio es obligatorio');
		}
		normalized.nombre = normalized.nombre.trim();
		if (normalized.descripcion) {
			normalized.descripcion = normalized.descripcion.trim();
			if (normalized.descripcion === '') {
				delete normalized.descripcion;
			}
		}

		// Eliminar cualquier campo undefined para evitar errores en Firestore
		Object.keys(normalized).forEach(key => {
			if (normalized[key] === undefined) {
				delete normalized[key];
			}
		});

		const now = new Date();
		if (!normalized.id || normalized.id === '') {
			normalized.fechaCreacion = now;
		}
		normalized.fechaModificacion = now;

		return normalized;
	}

	/**
	 * Guarda o actualiza un ejercicio (upsert si tiene id). Aplica validaciones y normalización automáticamente.
	 * @throws {EjercicioValidationError} Si la validación falla
	 */
	async save(ejercicio: Ejercicio): Promise<void> {
		const normalizedEjercicio = this.normalizeEjercicio(ejercicio);
		this.validateEjercicio(normalizedEjercicio);

		return this.runInZone(async () => {
			const dataToSave = this.mapToFirestore(normalizedEjercicio);
			if (normalizedEjercicio.id) {
				const ejercicioRef = doc(this.firestore, this.COLLECTION, normalizedEjercicio.id);
				await setDoc(ejercicioRef, dataToSave, { merge: true });
			} else {
				const col = collection(this.firestore, this.COLLECTION);
				await addDoc(col, dataToSave);
			}
		});
	}

	/**
	 * Elimina un ejercicio por ID
	 */
	async delete(id: string): Promise<void> {
		return this.runInZone(async () => {
			const ejercicioRef = doc(this.firestore, this.COLLECTION, id);
			await deleteDoc(ejercicioRef);
		});
	}

	/**
	 * Busca ejercicios por nombre
	 */
	getEjerciciosByNombre(nombre: string): Signal<Ejercicio[]> {
		const key = `nombre-${nombre}`;
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this._ejercicios().filter(ejercicio =>
					ejercicio.nombre.toLowerCase().includes(nombre.toLowerCase())
				)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Busca ejercicios por descripción
	 */
	getEjerciciosByDescripcion(descripcion: string): Signal<Ejercicio[]> {
		const key = `descripcion-${descripcion}`;
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this._ejercicios().filter(ejercicio =>
					ejercicio.descripcion?.toLowerCase().includes(descripcion.toLowerCase())
				)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Busca ejercicios por rango de series
	 */
	getEjerciciosBySeries(minSeries: number, maxSeries?: number): Signal<Ejercicio[]> {
		const key = `series-${minSeries}-${maxSeries || 'max'}`;
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this.filterByRange(this._ejercicios(), e => e.series, minSeries, maxSeries)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Obtiene el conteo total de ejercicios
	 */
	get ejercicioCount(): Signal<number> {
		return computed(() => this._ejercicios().length);
	}

	/**
	 * Busca ejercicios por rango de repeticiones
	 */
	getEjerciciosByRepeticiones(minReps: number, maxReps?: number): Signal<Ejercicio[]> {
		const key = `repeticiones-${minReps}-${maxReps || 'max'}`;
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this.filterByRange(this._ejercicios(), e => e.repeticiones, minReps, maxReps)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Obtiene ejercicios con peso específico
	 */
	getEjerciciosConPeso(): Signal<Ejercicio[]> {
		const key = 'con-peso';
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this._ejercicios().filter(ejercicio => ejercicio.peso && ejercicio.peso > 0)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Obtiene ejercicios sin peso (peso corporal)
	 */
	getEjerciciosSinPeso(): Signal<Ejercicio[]> {
		const key = 'sin-peso';
		if (!this.computedFilters.has(key)) {
			this.computedFilters.set(key, computed(() =>
				this._ejercicios().filter(ejercicio => !ejercicio.peso || ejercicio.peso === 0)
			));
		}
		return this.computedFilters.get(key)!;
	}

	/**
	 * Verifica si un rol puede crear ejercicios
	 */
	static canCreateEjercicio(rol: Rol): boolean {
		return rol === Rol.ENTRENADO || rol === Rol.ENTRENADOR;
	}

	/**
	 * Obtiene los roles que pueden crear ejercicios
	 */
	static getRolesCreadores(): Rol[] {
		return [Rol.ENTRENADO, Rol.ENTRENADOR];
	}

	private mapFromFirestore(data: any): Ejercicio {
		return {
			id: data.id,
			nombre: data.nombre || '',
			descripcion: data.descripcion,
			series: data.series || 0,
			repeticiones: data.repeticiones || 0,
			peso: data.peso,
			descansoSegundos: data.descansoSegundos,
			serieSegundos: data.serieSegundos,
			fechaCreacion: data.fechaCreacion instanceof Timestamp ? data.fechaCreacion.toDate() : data.fechaCreacion,
			fechaModificacion: data.fechaModificacion instanceof Timestamp ? data.fechaModificacion.toDate() : data.fechaModificacion,
			creadorId: data.creadorId
		};
	}

	private mapToFirestore(ejercicio: Ejercicio): any {
		const data: any = {
			nombre: ejercicio.nombre,
			descripcion: ejercicio.descripcion || null,
			series: ejercicio.series,
			repeticiones: ejercicio.repeticiones
		};

		if (ejercicio.peso !== undefined) data.peso = ejercicio.peso;
		if (ejercicio.descansoSegundos !== undefined) data.descansoSegundos = ejercicio.descansoSegundos;
		if (ejercicio.serieSegundos !== undefined) data.serieSegundos = ejercicio.serieSegundos;
		if (ejercicio.fechaCreacion) data.fechaCreacion = ejercicio.fechaCreacion instanceof Date ? Timestamp.fromDate(ejercicio.fechaCreacion) : ejercicio.fechaCreacion;
		if (ejercicio.fechaModificacion) data.fechaModificacion = ejercicio.fechaModificacion instanceof Date ? Timestamp.fromDate(ejercicio.fechaModificacion) : ejercicio.fechaModificacion;
		if (ejercicio.creadorId) data.creadorId = ejercicio.creadorId;

		return data;
	}
}

import { Injectable, signal, computed, inject, Injector, runInInjectionContext } from '@angular/core';
import {
  Firestore,
  collection,
  addDoc,
  doc,
  deleteDoc,
  setDoc,
  onSnapshot,
  QuerySnapshot,
  DocumentSnapshot,
  Timestamp,
  query,
  where,
  updateDoc
} from 'firebase/firestore';
import { Entrenador, Ejercicio, Plan, Rol, PlanLimits, ROL_PLAN_LIMITS } from 'gym-library';
import { RutinaService } from './rutina.service';
import { EjercicioService } from './ejercicio.service';
import { EntrenadoService } from './entrenado.service';
import { UserService } from './user.service';
import { NotificacionService } from './notificacion.service';
import { MensajeService } from './mensaje.service';
import { InvitacionService } from './invitacion.service';
import { ZoneRunnerService } from './zone-runner.service';
import { FIRESTORE } from '../firebase.tokens';

// Clase de error personalizada para límites
export class PlanLimitError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'PlanLimitError';
  }
}

/**
 * 🏋️‍♂️ Servicio de gestión de Entrenadores
 */
@Injectable({
  providedIn: 'root'
})
export class EntrenadorService {
  private readonly firestore = inject(FIRESTORE);
  private readonly injector = inject(Injector);
  private readonly zoneRunner = inject(ZoneRunnerService, { optional: true });
  private readonly COLLECTION = 'entrenadores';

  private rutinaService = inject(RutinaService);
  private ejercicioService = inject(EjercicioService);
  private entrenadoService = inject(EntrenadoService);
  private userService = inject(UserService);
  private notificacionService = inject(NotificacionService);
  private mensajeService = inject(MensajeService);
  private invitacionService = inject(InvitacionService);

  // 📊 Signals para el estado de los entrenadores
  private readonly _entrenadores = signal<Entrenador[]>([]);
  private readonly _loading = signal<boolean>(false);
  private readonly _error = signal<string | null>(null);

  // 🔍 Signals públicos de solo lectura
  readonly entrenadores = this._entrenadores.asReadonly();
  readonly loading = this._loading.asReadonly();
  readonly error = this._error.asReadonly();

  private isListenerInitialized = false;

  // Cache para límites por entrenador (evita búsquedas repetidas)
  private limitsCache = new Map<string, PlanLimits>();

  constructor() { }

  /**
   * Ejecuta el callback en el contexto correcto (zona o inyección)
   */
  private runInZone<T>(callback: () => T | Promise<T>): T | Promise<T> {
    if (this.zoneRunner) {
      return this.zoneRunner.run(callback);
    }
    return runInInjectionContext(this.injector, callback as any);
  }

  // Métodos para límites de plan
  getLimits(entrenadorId: string): PlanLimits {
    if (this.limitsCache.has(entrenadorId)) {
      return this.limitsCache.get(entrenadorId)!;
    }
    const user = this.userService.users().find(u => u.uid === entrenadorId);
    const plan = user?.plan || Plan.FREE;
    const limits = ROL_PLAN_LIMITS[Rol.ENTRENADOR][plan];
    this.limitsCache.set(entrenadorId, limits);
    return limits;
  }

  private validateLimit(entrenadorId: string, currentCount: number, max: number, item: string): void {
    if (currentCount >= max) {
      throw new PlanLimitError(`Límite alcanzado: ${currentCount}/${max} ${item} en plan free.`);
    }
  }

  private async addItemWithLimit(
    entrenadorId: string,
    itemId: string,
    arrayKey: keyof Entrenador,
    maxKey: keyof ReturnType<typeof this.getLimits>,
    itemName: string
  ): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (!entrenador) return;

    const limits = this.getLimits(entrenadorId);
    const currentArray = (entrenador[arrayKey] as string[]) || [];
    this.validateLimit(entrenadorId, currentArray.length, limits[maxKey] as number, itemName);

    if (!currentArray.includes(itemId)) {
      const updatedArray = [...currentArray, itemId];
      await this.update(entrenadorId, { [arrayKey]: updatedArray });
    }
  }

  invalidateLimitsCache(entrenadorId: string): void {
    this.limitsCache.delete(entrenadorId);
  }

  /**
   * Inicializa el listener de entrenadores
   */
  initializeListener(): void {
    if (this.isListenerInitialized) return;

    this._loading.set(true);
    this._error.set(null);
    try {
      const col = collection(this.firestore, this.COLLECTION);
      onSnapshot(col, (snap: QuerySnapshot) => {
        this.runInZone(() => {
          const list = snap.docs.map((d) => this.mapFromFirestore({ ...d.data(), id: d.id }));
          this._entrenadores.set(list);
          this._loading.set(false);
          this._error.set(null);
        });
      }, (error) => {
        this.runInZone(() => {
          console.error('❌ Error en listener de entrenadores:', error);
          this._error.set('Error al cargar entrenadores');
          this._loading.set(false);
        });
      });
      this.isListenerInitialized = true;
    } catch (error) {
      console.error('❌ Error al inicializar listener de entrenadores:', error);
      this._error.set('Error al inicializar entrenadores');
      this._loading.set(false);
    }
  }

  /**
   * Crea un nuevo entrenador
   */
  async create(entrenadorData: Omit<Entrenador, 'id'>): Promise<string> {
    this._loading.set(true);
    this._error.set(null);
    try {
      return await this.runInZone(async () => {
        const docRef = await addDoc(collection(this.firestore, this.COLLECTION), this.mapToFirestore(entrenadorData));
        return docRef.id;
      });
    } catch (error) {
      console.error('❌ Error al crear entrenador:', error);
      this._error.set('Error al crear entrenador');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Crea un nuevo entrenador con ID específico
   */
  async createWithId(id: string, entrenadorData: Omit<Entrenador, 'id'>): Promise<void> {
    this._loading.set(true);
    this._error.set(null);
    try {
      await this.runInZone(async () => {
        await setDoc(doc(this.firestore, this.COLLECTION, id), this.mapToFirestore(entrenadorData));
      });
    } catch (error) {
      this._error.set('Error al crear entrenador');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Actualiza un entrenador existente
   */
  async update(id: string, entrenadorData: Partial<Entrenador>): Promise<void> {
    this._loading.set(true);
    this._error.set(null);
    try {
      await this.runInZone(async () => {
        const dataToUpdate = this.mapPartialToFirestore(entrenadorData);
        await updateDoc(doc(this.firestore, this.COLLECTION, id), dataToUpdate);
      });
    } catch (error) {
      console.error('❌ Error al actualizar entrenador:', error);
      this._error.set('Error al actualizar entrenador');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Elimina un entrenador
   */
  async delete(id: string): Promise<void> {
    this._loading.set(true);
    this._error.set(null);
    try {
      await this.runInZone(async () => {
        await deleteDoc(doc(this.firestore, this.COLLECTION, id));
      });
    } catch (error) {
      console.error('❌ Error al eliminar entrenador:', error);
      this._error.set('Error al eliminar entrenador');
      throw error;
    } finally {
      this._loading.set(false);
    }
  }

  /**
   * Busca un entrenador por ID
   */
  getEntrenadorById(id: string) {
    return computed(() =>
      this._entrenadores().find(entrenador => entrenador.id === id)
    );
  }

  /**
   * Obtiene las rutinas de un entrenador específico
   */
  getRutinasByEntrenador(entrenadorId: string) {
    return computed(() => {
      const entrenador = this._entrenadores().find(e => e.id === entrenadorId);
      if (!entrenador || !entrenador.rutinasCreadasIds) return [];
      return this.rutinaService.rutinas().filter(rutina =>
        entrenador.rutinasCreadasIds.includes(rutina.id)
      );
    });
  }

  /**
   * Obtiene los ejercicios de un entrenador específico
   */
  getEjerciciosByEntrenador(entrenadorId: string) {
    return computed(() => {
      return this.ejercicioService.ejercicios().filter(ejercicio =>
        ejercicio.creadorId === entrenadorId
      );
    });
  }

  /**
   * Obtiene las invitaciones de un entrenador específico
   */
  getInvitacionesByEntrenador(entrenadorId: string) {
    return this.invitacionService.getInvitacionesPorEntrenador(entrenadorId);
  }

  /**
   * Obtiene los mensajes de un entrenador específico
   */
  getMensajesByEntrenador(entrenadorId: string) {
    return this.mensajeService.getMensajesByEntrenador(entrenadorId);
  }

  /**
   * Obtiene el conteo de entrenados asignados a un entrenador
   */
  getEntrenadosCount(entrenadorId: string) {
    return computed(() => {
      const entrenador = this.getEntrenadorById(entrenadorId)();
      return entrenador?.entrenadosAsignadosIds?.length || 0;
    });
  }

  /**
   * Desvincula un entrenado de un entrenador
   */
  async desvincularEntrenado(entrenadorId: string, entrenadoId: string): Promise<void> {
    const entrenado = this.entrenadoService.getEntrenadoById(entrenadoId)();
    if (entrenado) {
      const entrenadoresId = (entrenado.entrenadoresId || []).filter((id: string) => id !== entrenadorId);
      await this.entrenadoService.save({ ...entrenado, entrenadoresId });
    }

    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (entrenador) {
      const entrenadosAsignadosIds = (entrenador.entrenadosAsignadosIds || []).filter((id: string) => id !== entrenadoId);
      await this.update(entrenadorId, { entrenadosAsignadosIds });
    }
  }

  /**
   * Obtiene los entrenadores con información de usuario combinada
   */
  getEntrenadoresWithUserInfo() {
    return computed(() => {
      return this._entrenadores().map(entrenador => {
        const usuario = this.userService.users().find(u => u.uid === entrenador.id);
        return {
          ...entrenador,
          displayName: usuario?.nombre || usuario?.email || `Usuario ${entrenador.id}`,
          email: usuario?.email || '',
          plan: usuario?.plan || 'free'
        };
      });
    });
  }

  /**
   * ➕ Agrega un ejercicio a la lista de ejercicios creados de un entrenador
   */
  async addEjercicioCreado(entrenadorId: string, ejercicioId: string): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (!entrenador) return;

    const limits = this.getLimits(entrenadorId);
    if (!limits.allowCustomTimers) { // Plan free
      const ejercicio = this.ejercicioService.getEjercicio(ejercicioId)();
      if (ejercicio && (ejercicio.descansoSegundos !== undefined || ejercicio.serieSegundos !== undefined)) {
        throw new PlanLimitError('En el plan free no se pueden configurar tiempos de descanso o serie. Actualiza a premium.');
      }
    }

    const currentCount = entrenador.ejerciciosCreadasIds?.length || 0;
    this.validateLimit(entrenadorId, currentCount, limits.maxExercises, 'ejercicios');

    const ejerciciosCreadasIds = [...(entrenador.ejerciciosCreadasIds || [])];
    if (!ejerciciosCreadasIds.includes(ejercicioId)) {
      ejerciciosCreadasIds.push(ejercicioId);
      await this.update(entrenadorId, { ejerciciosCreadasIds });
    }
  }

  /**
   * ➖ Quita un ejercicio de la lista de ejercicios creados de un entrenador
   */
  async removeEjercicioCreado(entrenadorId: string, ejercicioId: string): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (entrenador) {
      const ejerciciosCreadasIds = (entrenador.ejerciciosCreadasIds || []).filter((id: string) => id !== ejercicioId);
      await this.update(entrenadorId, { ejerciciosCreadasIds });
    }
  }

  async deleteEjercicioCreado(entrenadorId: string, ejercicioId: string): Promise<void> {
    await this.ejercicioService.delete(ejercicioId);
    await this.removeEjercicioCreado(entrenadorId, ejercicioId);
  }

  async addRutinaCreada(entrenadorId: string, rutinaId: string): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (!entrenador) return;

    const limits = this.getLimits(entrenadorId);
    if (!limits.allowCustomDuration) { // Plan free
      const rutina = this.rutinaService.getRutina(rutinaId)();
      if (rutina && rutina.duracion !== undefined) {
        throw new PlanLimitError('En el plan free no se pueden configurar duración. Actualiza a premium.');
      }
    }

    await this.addItemWithLimit(entrenadorId, rutinaId, 'rutinasCreadasIds', 'maxRoutines', 'rutinas');
  }

  async removeRutinaCreada(entrenadorId: string, rutinaId: string): Promise<void> {
    const entrenador = this.getEntrenadorById(entrenadorId)();
    if (entrenador) {
      const rutinasCreadasIds = (entrenador.rutinasCreadasIds || []).filter((id: string) => id !== rutinaId);
      await this.update(entrenadorId, { rutinasCreadasIds });
    }
  }

  async asignarEntrenado(entrenadorId: string, entrenadoId: string): Promise<void> {
    await this.addItemWithLimit(entrenadorId, entrenadoId, 'entrenadosAsignadosIds', 'maxClients', 'clientes activos');
    const entrenado = this.entrenadoService.getEntrenadoById(entrenadoId)();
    if (entrenado) {
      const entrenadoresId = [...(entrenado.entrenadoresId || []), entrenadorId];
      await this.entrenadoService.save({ ...entrenado, entrenadoresId });
    }
  }

  private mapToFirestore(entrenador: Omit<Entrenador, 'id'> | Entrenador): any {
    const data = { ...entrenador } as any;
    if (entrenador.fechaRegistro) {
      data.fechaRegistro = Timestamp.fromDate(entrenador.fechaRegistro);
    }
    return data;
  }

  private mapFromFirestore(data: any): Entrenador {
    const entrenador = { ...data };
    if (data.fechaRegistro && data.fechaRegistro instanceof Timestamp) {
      entrenador.fechaRegistro = data.fechaRegistro.toDate();
    }
    return entrenador as Entrenador;
  }

  private mapPartialToFirestore(entrenador: Partial<Entrenador>): any {
    const data: any = {};
    if (entrenador.fechaRegistro !== undefined) {
      data.fechaRegistro = entrenador.fechaRegistro ? Timestamp.fromDate(entrenador.fechaRegistro) : null;
    }
    if (entrenador.ejerciciosCreadasIds !== undefined) data.ejerciciosCreadasIds = entrenador.ejerciciosCreadasIds;
    if (entrenador.entrenadosAsignadosIds !== undefined) data.entrenadosAsignadosIds = entrenador.entrenadosAsignadosIds;
    if (entrenador.rutinasCreadasIds !== undefined) data.rutinasCreadasIds = entrenador.rutinasCreadasIds;
    return data;
  }
}

