    if (event) event.stopPropagation();
    this.edit.emit(item);
  }
}

import { Component, input, output, effect, signal, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import {
  IonHeader,
  IonToolbar,
  IonTitle,
  IonContent,
  IonButton,
  IonIcon,
  IonItem,
  IonModal,
  IonButtons,
  IonInput,
  IonTextarea,
  IonText
} from '@ionic/angular/standalone';
import { addIcons } from 'ionicons';
import { close, star } from 'ionicons/icons';

@Component({
  selector: 'app-ejercicio-modal',
  templateUrl: './ejercicio-modal.component.html',
  standalone: true,
  imports: [
    CommonModule,
    ReactiveFormsModule,
    IonHeader,
    IonToolbar,
    IonTitle,
    IonContent,
    IonButton,
    IonIcon,
    IonItem,
    IonModal,
    IonButtons,
    IonInput,
    IonTextarea,
    IonText
  ],
  styles: [`
    .ejercicio-modal {
      --width: 95%;
      --max-width: 600px;
      --border-radius: 16px;
      --backdrop-opacity: 0.3;
    }
    .gym-modal-item {
      --background: rgba(255, 255, 255, 0.05);
      --border-radius: 12px;
      --border-width: 1px;
      --border-style: solid;
      --border-color: rgba(255, 255, 255, 0.08);
      --padding-start: 16px;
      --padding-end: 16px;
    }
  `]
})
export class EjercicioModalComponent {
  private fb = inject(FormBuilder);

  isOpen = input.required<boolean>();
  ejercicio = input<any>(null);
  isCreating = input<boolean>(false);
  isFreePlan = input<boolean>(true);

  close = output<void>();
  save = output<any>();

  readonly form = signal<FormGroup | null>(null);
  private readonly formStatus = signal<string>('INVALID');

  readonly isSaveDisabled = computed(() => {
    return this.formStatus() === 'INVALID';
  });

  constructor() {
    addIcons({ close, star });

    // Cuando cambia el ejercicio o el estado de apertura, recreamos el formulario
    effect(() => {
      const item = this.ejercicio();
      const open = this.isOpen();
      if (open && item) {
        this.createForm(item);
      } else {
        this.form.set(null);
      }
    });
  }

  private createForm(item: any) {
    const formConfig: any = {
      nombre: [item.nombre || '', [Validators.required]],
      descripcion: [item.descripcion || ''],
      series: [item.series || 1, [Validators.required, Validators.min(1)]],
      repeticiones: [item.repeticiones || 1, [Validators.required, Validators.min(1)]],
      peso: [item.peso || 0],
      creadorId: [item.creadorId || ''],
      creadorTipo: [item.creadorTipo || 'entrenador']
    };

    if (!this.isFreePlan()) {
      formConfig.serieSegundos = [item.serieSegundos || 0];
      formConfig.descansoSegundos = [item.descansoSegundos || 60];
    }

    const formGroup = this.fb.group(formConfig);
    this.form.set(formGroup);

    formGroup.statusChanges.subscribe(status => {
      this.formStatus.set(status);
    });
    this.formStatus.set(formGroup.status);
  }

  onSubmit() {
    const formGroup = this.form();
    if (formGroup && formGroup.valid) {
      this.save.emit(formGroup.value);
    }
  }
}

import { Component, Input, Output, EventEmitter, inject, signal, OnChanges, SimpleChanges } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import {
  IonHeader,
  IonToolbar,
  IonTitle,
  IonContent,
  IonButton,
  IonIcon,
  IonModal,
  IonButtons,
  IonInput,
  IonTextarea,
  IonPopover,
  ToastController
} from '@ionic/angular/standalone';
import { addIcons } from 'ionicons';
import { close, saveOutline, barbellOutline, helpCircleOutline } from 'ionicons/icons';
import { EjercicioService } from '../../../../../core/services/ejercicio.service';
import { EntrenadoService } from '../../../../../core/services/entrenado.service';
import { AuthService } from '../../../../../core/services/auth.service';
import { Plan } from 'gym-library';

@Component({
  selector: 'app-ejercicio-modal',
  standalone: true,
  imports: [
    CommonModule,
    ReactiveFormsModule,
    IonHeader,
    IonToolbar,
    IonTitle,
    IonContent,
    IonButton,
    IonIcon,
    IonModal,
    IonButtons,
    IonInput,
    IonTextarea,
    IonPopover,
    IonContent
  ],
  templateUrl: './ejercicio-modal.component.html'
})
export class EjercicioModalComponent implements OnChanges {
  private fb = inject(FormBuilder);
  private authService = inject(AuthService);
  private ejercicioService = inject(EjercicioService);
  private entrenadoService = inject(EntrenadoService);
  private toastCtrl = inject(ToastController);

  @Input() isOpen = false;
  @Input() item: import('gym-library').Ejercicio | null = null;
  @Output() close = new EventEmitter<void>();
  @Output() saved = new EventEmitter<void>();

  saving = signal(false);
  isEditing = false;

  form: FormGroup;

  constructor() {
    addIcons({ close, saveOutline, barbellOutline, helpCircleOutline });

    this.form = this.fb.group({
      nombre: ['', [Validators.required, Validators.minLength(2)]],
      descripcion: [''],
      series: [3, [Validators.required, Validators.min(1)]],
      repeticiones: [12, [Validators.required, Validators.min(1)]],
      peso: [0]
    });
  }

  ngOnChanges(changes: SimpleChanges) {
    if (changes['item'] && this.item) {
      this.loadItemForEdit();
    }
  }

  private loadItemForEdit() {
    if (!this.item) return;
    this.isEditing = true;

    this.form.patchValue({
      nombre: this.item.nombre || '',
      descripcion: this.item.descripcion || '',
      series: this.item.series || 3,
      repeticiones: this.item.repeticiones || 12,
      peso: this.item.peso || 0
    });
  }

  closeModal() {
    this.close.emit();
    this.isEditing = false;
    this.form.reset({
      series: 3,
      repeticiones: 12,
      peso: 0
    });
  }

  async guardar() {
    if (this.form.invalid || this.saving()) return;

    const user = this.authService.currentUser();
    if (!user) {
      this.showToast('Debes iniciar sesión', 'danger');
      return;
    }

    const uid = user.uid;

    if (!this.isEditing) {
      const plan = this.authService.currentUser()?.plan;
      if (plan !== Plan.PREMIUM) {
        this.showToast('La creación de ejercicios personalizados es exclusiva para usuarios Premium 🔒', 'warning');
        this.closeModal();
        return;
      }
    }

    this.saving.set(true);
    try {
      const formValue = this.form.value;

      let ejercicioData: Partial<import('gym-library').Ejercicio>;

      if (this.isEditing && this.item) {
        ejercicioData = {
          ...this.item,
          nombre: (formValue.nombre || '').trim(),
          descripcion: (formValue.descripcion || '').trim(),
          series: Number(formValue.series) || 3,
          repeticiones: Number(formValue.repeticiones) || 12,
          peso: Number(formValue.peso) || 0,
        };
      } else {
        ejercicioData = {
          id: 'ej-' + Date.now(),
          nombre: (formValue.nombre || '').trim(),
          descripcion: (formValue.descripcion || '').trim(),
          series: Number(formValue.series) || 3,
          repeticiones: Number(formValue.repeticiones) || 12,
          peso: Number(formValue.peso) || 0,
          descansoSegundos: 60,
          serieSegundos: 0,
          creadorId: uid,
        };
      }

      await this.ejercicioService.save(ejercicioData as any);

      if (!this.isEditing) {
        await this.entrenadoService.addEjercicioCreado(uid, ejercicioData.id!);
      }

      this.showToast(this.isEditing ? 'Ejercicio actualizado' : 'Ejercicio creado con éxito', 'success');
      this.saved.emit();
      this.closeModal();
    } catch (e) {
      console.error(e);
      this.showToast(this.isEditing ? 'Error al actualizar el ejercicio' : 'Error al crear el ejercicio', 'danger');
    } finally {
      this.saving.set(false);
    }
  }

  private async showToast(message: string, color: 'success' | 'danger' | 'warning') {
    const toast = await this.toastCtrl.create({
      message,
      duration: 2500,
      color,
      position: 'top'
    });
    await toast.present();
  }
}

