import { EntrenadoService } from '../../core/services/entrenado.service';


@Component({
  selector: 'app-gimnasio-dashboard',
  templateUrl: 'gimnasio-dashboard.page.html',
  standalone: true,
  imports: [
    IonContent
  ],
})
