import { Component, OnInit, signal, computed, inject, effect, OnDestroy } from '@angular/core';
import { Router } from '@angular/router';
import { CommonModule, NgOptimizedImage } from '@angular/common';
import { Platform, LoadingController, ToastController, MenuController } from '@ionic/angular/standalone';

import {
  IonButton, IonIcon, IonMenu, IonSpinner,
  IonHeader, IonToolbar, IonContent, IonButtons, IonFooter
} from '@ionic/angular/standalone';
import { Unsubscribe } from 'firebase/firestore';
import { addIcons } from 'ionicons';
import {
  logOutOutline, personOutline, mailOutline, shieldOutline, timeOutline, checkmarkCircleOutline,
  trophyOutline, fitnessOutline, statsChartOutline, pencilOutline, cameraOutline, saveOutline,
  closeOutline, notificationsOutline, lockClosedOutline, arrowBackOutline, starOutline, alertCircleOutline,
  checkmarkCircle, person, trophy, mail, star, helpCircleOutline,
  flagOutline, barChartOutline
} from 'ionicons/icons';

import { User as LibraryUser, Rutina, Plan, SolicitudPlan, Objetivo } from 'gym-library';
export interface User extends LibraryUser {
  photoURL?: string;
}

import { UserService } from '../../../../../core/services/user.service';
import { AuthService } from '../../../../../core/services/auth.service';
import { RutinaService } from '../../../../../core/services/rutina.service';
import { EntrenadoService } from '../../../../../core/services/entrenado.service';
import { PlanService } from '../../../../../core/services/plan.service';
import { NotificacionService } from '../../../../../core/services/notificacion.service';

import { EditProfileModalComponent } from './components/edit-profile-modal/edit-profile-modal.component';
import { PremiumRequestModalComponent } from './components/premium-request-modal/premium-request-modal.component';

@Component({
  selector: 'app-profile',
  templateUrl: './profile.component.html',
  standalone: true,
  imports: [
    CommonModule,
    IonIcon, IonMenu, IonSpinner, IonButton,
    IonHeader, IonToolbar, IonContent, IonButtons, IonFooter,
    NgOptimizedImage, EditProfileModalComponent, PremiumRequestModalComponent
  ],
})
export class ProfileComponent implements OnInit, OnDestroy {
  private authService = inject(AuthService);
  private userService = inject(UserService);
  private rutinaService = inject(RutinaService);
  public entrenadoService = inject(EntrenadoService);
  private planService = inject(PlanService);
  private notificacionService = inject(NotificacionService);
  private router = inject(Router);
  public loadingCtrl = inject(LoadingController);
  private toastCtrl = inject(ToastController);
  private platform = inject(Platform);
  private menuCtrl = inject(MenuController);

  currentUser = computed(() => this.authService.currentUser() as User);
  currentEntrenado = computed(() => {
    const user = this.currentUser();
    return user?.role === 'entrenado' ? this.entrenadoService.getEntrenado(user.uid)() : null;
  });

  rutinas = signal<Rutina[]>([]);
  ultimasolicitud = signal<SolicitudPlan | null>(null);

  isEditModalOpen = signal<boolean>(false);
  isPremiumModalOpen = signal<boolean>(false);

  private solicitudesUnsubscribe?: Unsubscribe;

  constructor() {
    addIcons({
      logOutOutline, personOutline, mailOutline, shieldOutline, timeOutline, checkmarkCircleOutline,
      trophyOutline, fitnessOutline, statsChartOutline, pencilOutline, cameraOutline, saveOutline,
      closeOutline, notificationsOutline, lockClosedOutline, arrowBackOutline, starOutline, alertCircleOutline,
      checkmarkCircle, person, trophy, mail, star, helpCircleOutline,
      flagOutline, barChartOutline
    });

    effect(() => {
      const user = this.currentUser();
      if (user && user.role !== 'gimnasio') {
        this.iniciarListenerSolicitudes(user.uid);
      }
    });
  }

  ngOnInit() {
    this.rutinas.set(this.rutinaService.rutinas());
    // Aseguramos que el gesto de swipe desde el borde izquierdo funcione
    this.menuCtrl.enable(true, 'profile-menu');
  }

  ngOnDestroy() {
    if (this.solicitudesUnsubscribe) {
      this.solicitudesUnsubscribe();
    }
  }

  openEditModal() {
    this.isEditModalOpen.set(true);
  }

  closeEditModal() {
    this.isEditModalOpen.set(false);
  }

  openPremiumModal() {
    this.isPremiumModalOpen.set(true);
  }

  closePremiumModal() {
    this.isPremiumModalOpen.set(false);
  }

  private iniciarListenerSolicitudes(userId: string) {
    if (this.solicitudesUnsubscribe) this.solicitudesUnsubscribe();
    this.solicitudesUnsubscribe = this.planService.getSolicitudesUsuarioListener(userId, (solicitudes: SolicitudPlan[]) => {
      this.ultimasolicitud.set(solicitudes && solicitudes.length > 0 ? solicitudes[0] : null);
    });
  }

  private async showToast(message: string, color: 'success' | 'danger' | 'warning') {
    const toast = await this.toastCtrl.create({ message, duration: 2000, color, position: 'bottom' });
    toast.present();
  }

  isLoggingOut = signal(false);

  async logout() {
    const loading = await this.loadingCtrl.create({
      message: 'Cerrando sesión...',
      spinner: 'crescent'
    });
    await loading.present();

    try {
      this.isLoggingOut.set(true);

      // PASO CRÍTICO: Esperar a que el menú se cierre TOTALMENTE antes de que el @if 
      // de app.component destruya este componente. Si se destruye antes, el backdrop se queda "huérfano" y bloquea la UI.
      if (this.menuCtrl) {
        await this.menuCtrl.close('profile-menu');
        await this.menuCtrl.close(); // Doble cierre por seguridad
      }

      // Pequeño delay adicional para que Ionic limpie el DOM del menú
      await new Promise(resolve => setTimeout(resolve, 100));

      // Cerramos sesión en Firebase (esto disparará el @if y destruirá este componente)
      await this.authService.logout();

      // Limpiar caché local
      localStorage.removeItem('gym_auth_user');

      // Redirigir al login
      await this.router.navigate(['/login'], { replaceUrl: true });

      this.showToast('Sesión cerrada correctamente', 'success');
    } catch (error) {
      console.error('🛡️ Profile: Error en logout:', error);
      // Fallback: Si el router se queda bloqueado, forzamos recarga
      window.location.href = '/login';
    } finally {
      this.isLoggingOut.set(false);
      await loading.dismiss();
    }
  }

  getRoleDisplayName(role?: string): string {
    switch (role) {
      case 'gimnasio': return 'Gimnasio';
      case 'entrenado': return 'Entrenado';
      case 'entrenador': return 'Entrenador';
      case 'user': return 'Usuario';
      default: return 'Usuario';
    }
  }

  getIniciales(nombre?: string): string {
    if (!nombre) return 'U';
    return nombre.split(' ').map((n: string) => n.charAt(0).toUpperCase()).join('').substring(0, 2);
  }
}

import { Component, Input, computed, signal } from '@angular/core';
import {
    IonCard,
    IonCardContent
} from '@ionic/angular/standalone';

@Component({
    selector: 'app-progreso-estadisticas',
    standalone: true,
    imports: [
        IonCard,
        IonCardContent
    ],
    templateUrl: './progreso-estadisticas.component.html'
})
export class ProgresoEstadisticasComponent {
    @Input() stats: any = null;                 // TODO: tipar con interfaz de estadísticas generales
    @Input() sesiones: import('gym-library').SesionRutina[] = [];
    @Input() dbStats: import('gym-library').EstadisticasEntrenado | null = null;

    // Computed chart data
    readonly weeklyActivity = computed(() => this.computeWeeklyActivity());
    readonly topRutinas = computed(() => this.computeTopRutinas());
    readonly completionRate = computed(() => this.computeCompletionRate());
    readonly maxWeeklyValue = computed(() => Math.max(1, ...this.weeklyActivity().map(d => d.value)));

    formatearTiempo(minutos: number): string {
        const horas = Math.floor(minutos / 60);
        const mins = minutos % 60;

        if (horas > 0) {
            return `${horas}h ${mins}m`;
        }
        return `${mins}m`;
    }

    private computeWeeklyActivity() {
        if (!this.sesiones || this.sesiones.length === 0) {
            return Array.from({ length: 7 }, (_, i) => ({ label: this.dayLabel(i), value: 0, minutes: 0 }));
        }

        const now = new Date();
        const dayNames = ['D', 'L', 'M', 'X', 'J', 'V', 'S'];
        const activity = Array.from({ length: 7 }, (_, i) => {
            const d = new Date(now);
            d.setDate(d.getDate() - (6 - i));
            return {
                label: dayNames[d.getDay()],
                dateKey: d.toISOString().slice(0, 10),
                value: 0,
                minutes: 0
            };
        });

        const map = new Map(activity.map(a => [a.dateKey, a]));

        this.sesiones.forEach((s) => {
            if (!s.fechaInicio || !s.completada) return;
            const d = new Date(s.fechaInicio);
            const key = d.toISOString().slice(0, 10);
            const entry = map.get(key);
            if (entry) {
                entry.value += 1;
                entry.minutes += Math.round((s.duracion || 0) / 60);
            }
        });

        return activity;
    }

    private dayLabel(offsetFromToday: number): string {
        const d = new Date();
        d.setDate(d.getDate() - (6 - offsetFromToday));
        return ['D','L','M','X','J','V','S'][d.getDay()];
    }

    private computeTopRutinas() {
        const counts = new Map<string, number>();
        (this.sesiones || []).filter((s) => s.completada).forEach((s) => {
            const name = s.rutinaResumen?.nombre || 'Rutina';
            counts.set(name, (counts.get(name) || 0) + 1);
        });
        const arr = Array.from(counts.entries())
            .map(([name, count]) => ({ name, count }))
            .sort((a, b) => b.count - a.count)
            .slice(0, 4);
        const max = Math.max(1, ...arr.map(a => a.count));
        return arr.map(a => ({ ...a, percent: Math.round((a.count / max) * 100) }));
    }

    private computeCompletionRate(): number {
        if (!this.sesiones || this.sesiones.length === 0) return 0;
        const completadas = this.sesiones.filter((s) => s.completada).length;
        return Math.round((completadas / this.sesiones.length) * 100);
    }

    getNivel(): number {
        return this.dbStats?.nivel || 1;
    }

    getExperiencia(): number {
        return this.dbStats?.experiencia || 0;
    }

    getExperienciaProximo(): number {
        return this.dbStats?.experienciaProximoNivel || 100;
    }

    getRacha(): number {
        return this.dbStats?.rachaActual || 0;
    }

    getMejorRacha(): number {
        return this.dbStats?.mejorRacha || 0;
    }

    getXpPercent(): number {
        const exp = this.getExperiencia();
        const next = this.getExperienciaProximo();
        return Math.min(100, Math.round((exp / Math.max(1, next)) * 100));
    }
}

